_ART_RAW_CACHE = {}  # name -> PIL.Image (RGBA, decoded once from the embedded bytes)


def _load_art_image(name):
    """Load (and cache) the source PIL image for one art asset, decoded
    from the base64 bytes embedded in this file (_ART_DATA_B64) -- no
    filesystem access, so there is no separate art/ folder to go missing."""
    if name in _ART_RAW_CACHE:
        return _ART_RAW_CACHE[name]
    if name not in _ART_DATA_B64:
        raise RuntimeError(
            f"Unknown art asset '{name}' -- no embedded data for it. "
            f"Known assets: {sorted(_ART_DATA_B64)}.")
    raw = base64.b64decode(_ART_DATA_B64[name])
    im = Image.open(io.BytesIO(raw)).convert("RGBA")
    _ART_RAW_CACHE[name] = im
    return im


_ART_OUTLINED_CACHE = {}  # name -> PIL.Image, with a white silhouette stroke added


def _add_white_outline(im, thickness=2.0, outline_mask=None):
    """Trace a soft, anti-aliased white stroke `thickness` px wide around
    the *outer* silhouette of `im` (an RGBA PIL image) -- the whole
    character's alpha boundary, not each individual ink line inside it.
    The artwork's own pixels (black ink strokes, green/red fill) are left
    completely untouched; the ring only ever occupies pixels that were
    fully transparent in the source, so there's no risk of it bleeding
    into or covering any linework. This replaces the old approach of
    inverting the black ink to white -- Filip wanted the ink to stay
    black and instead have an outline carry the contrast against the
    dark background.

    Built from a Euclidean distance transform rather than a binary
    dilation -- per Filip's "try and make the white outlines of neurons
    higher res and thinner": a hard pixel-dilation ring has a visible
    blocky/jagged stairstep edge and can only ever be an integer number
    of pixels wide, while a distance-based ring fades smoothly over the
    last ~1px (true anti-aliasing) and supports sub-pixel thickness, so
    it reads as noticeably crisper and thinner at the same on-screen size
    without needing to re-rasterize any source art at a higher resolution.

    `outline_mask`, if given, is a boolean array (same shape as `im`)
    restricting which occupied pixels the ring is allowed to hug -- used
    by kurtosis_splash to outline just the neuron characters and not the
    plain trace-line strokes sharing the same image (Filip: "outlines of
    the grey lines in kurtosis splash don't need to be there"). Defaults
    to the full alpha mask (outline everything), the original behavior.

    The canvas is padded by `thickness` (+2px slack) on every side so the
    outline never gets clipped; callers that rely on fractional anchor
    offsets (eye/snout position) are unaffected in practice since the
    padding is small and symmetric."""
    arr = np.array(im)
    mask = arr[..., 3] > 16
    src_mask = mask if outline_mask is None else (outline_mask & mask)
    pad = int(math.ceil(thickness)) + 2
    h, w = mask.shape

    padded_src = np.zeros((h + 2 * pad, w + 2 * pad), dtype=bool)
    padded_src[pad:pad + h, pad:pad + w] = src_mask
    padded_full = np.zeros((h + 2 * pad, w + 2 * pad), dtype=bool)
    padded_full[pad:pad + h, pad:pad + w] = mask

    dist = distance_transform_edt(~padded_src)
    # Full-strength at the boundary, fading linearly to nothing over the
    # last 1px for a soft (anti-aliased) rather than a hard pixel edge.
    ring_alpha = np.clip(thickness + 0.5 - dist, 0.0, 1.0)
    ring_alpha[padded_full] = 0.0  # never draw over any real content

    # Build directly with numpy rather than PIL's paste()/alpha_composite()
    # -- paste(im, box, im) blends partially-transparent (anti-aliased edge)
    # source pixels against whatever's already there, which very slightly
    # changes their RGB/alpha values. A raw masked array copy instead
    # guarantees the artwork's own pixels come out byte-identical.
    out = np.zeros((h + 2 * pad, w + 2 * pad, 4), dtype=np.uint8)
    out[..., 0] = 255
    out[..., 1] = 255
    out[..., 2] = 255
    out[..., 3] = np.round(ring_alpha * 255).astype(np.uint8)
    dest = out[pad:pad + h, pad:pad + w]
    dest[mask] = arr[mask]
    return Image.fromarray(out, mode="RGBA")


def _load_art_image_outlined(name, thickness=2.0):
    """Same artwork as _load_art_image, but with a white silhouette
    outline added around it (see _add_white_outline) -- reads clearly
    against a dark background while the ink/fill colors themselves stay
    exactly as drawn."""
    cache_key = (name, thickness)
    if cache_key in _ART_OUTLINED_CACHE:
        return _ART_OUTLINED_CACHE[cache_key]
    im = _load_art_image(name)
    out = _add_white_outline(im, thickness=thickness)
    _ART_OUTLINED_CACHE[cache_key] = out
    return out


def _load_kurtosis_splash_outlined(thickness=2.0):
    """kurtosis_splash-specific loader: only the neuron characters carry
    a white silhouette ring, never the grey trace-line strokes -- per
    Filip's repeated "the grey lines still have white contours."

    Earlier attempts tried to separate "neuron pixel" from "trace pixel"
    after the fact, on a single flattened raster, by guessing from color
    (exact-value match, then a greyness/brightness heuristic). Both broke
    under real-world pixel blending (resizing, anti-aliasing) because a
    color guess on a flattened image can never be 100% reliable.

    kurtosis_splash is now built from the original "Kurt 01 Artboard
    1.svg" with the neuron-character layers (Vector_layer_4_/5_) and the
    trace-line layer (Vector_layer_3_) rendered to two SEPARATE
    transparent rasters at high supersampling, so there is no ambiguity:
    the outline ring is computed from (and can only ever touch) the
    neuron-only raster, then the un-outlined trace raster is composited
    underneath. The result already has this baked in at build time, so
    loading it is just loading the asset -- no runtime pixel heuristics,
    no way for the bug to recur."""
    cache_key = ("kurtosis_splash", thickness)
    if cache_key in _ART_OUTLINED_CACHE:
        return _ART_OUTLINED_CACHE[cache_key]
    out = _load_art_image("kurtosis_splash")
    _ART_OUTLINED_CACHE[cache_key] = out
    return out


def _apply_row_distort(im, distort, phase):
    """Row-wise horizontal pixel shift (a 'scanline glitch'), vectorized
    over numpy so it's cheap enough to redo every animation frame. Mirrors
    the shape of the original hand-drawn jitter formula (two summed sines
    at different row-frequencies/phase-rates) but applied to pixels instead
    of vector point coordinates -- used by the motion-correction overlay to
    visually 'scramble' the neuron and let it resolve back to clean as
    NormCorre progress comes in."""
    if distort <= 0.002:
        return im
    arr = np.array(im)
    h, w = arr.shape[0], arr.shape[1]
    if w == 0 or h == 0:
        return im
    max_shift = distort * w * 0.10
    rows = np.arange(h)
    shifts = (max_shift * np.sin(rows * 0.15 + phase)
              + max_shift * 0.4 * np.sin(rows * 0.4 - phase * 1.7))
    shifts = shifts.astype(np.int64)
    col_idx = (np.arange(w)[None, :] - shifts[:, None]) % w
    out = arr[rows[:, None], col_idx]
    return Image.fromarray(out, mode="RGBA")


# Two caching layers on top of the raw/outlined decode caches above --
# added after Filip reported "the hand movement is very not smooth" even
# after the rise/drag motion was switched to an eased curve. The actual
# bottleneck turned out to be here: every single 33ms tick was redoing a
# full LANCZOS resize (the highest-quality *and* slowest PIL resampling
# filter) plus a brand-new ImageTk.PhotoImage construction, for *every*
# character drawn that frame (neuron, chameleon, photon, hand) -- even
# though most of those calls use the exact same (name, outlined, target_h)
# every time, since only their *position* changes frame to frame, not
# their size. On a slower machine that per-frame cost can exceed the 33ms
# budget, silently dropping the effective frame rate and producing exactly
# the visible judder Filip described -- smoother easing math doesn't help
# if frames are being skipped entirely.
#   _ART_RESIZED_CACHE: (name, outlined, target_h) -> resized PIL.Image,
#     skips the LANCZOS resize (but not distort/rotate, which are cheap
#     and can legitimately differ every frame -- e.g. the photon's flight
#     angle, or the motion-correction overlay's scanline glitch phase).
#   _ART_PHOTO_CACHE: same key -> a ready ImageTk.PhotoImage, reused
#     as-is (skipping PhotoImage construction too) whenever a call has no
#     rotation/distortion at all, which covers the neuron/chameleon/hand
#     in the busy bar entirely.
_ART_RESIZED_CACHE = {}
_ART_PHOTO_CACHE = {}


def _render_art_image(canvas, name, cx, cy, target_h, tag,
                       rotate_deg=0.0, distort=0.0, phase=0.0, outlined=False):
    """Load, resize (to target_h px tall, aspect-preserved), optionally
    rotate and/or scanline-distort, then draw the given art asset centered
    at (cx, cy) on `canvas` via create_image. Keeps a strong reference to
    the resulting PhotoImage on the canvas itself (Tk requires this --
    otherwise it gets garbage-collected and the image silently vanishes).
    `outlined=True` uses the white-silhouette-outlined version (ink/fill
    colors unchanged, just a white stroke traced around the outer edge),
    for display on a dark background. Returns (disp_w, disp_h), the actual
    on-screen pixel size, so callers can compute anchor points (eye,
    snout, ...) relative to it. See the cache comments above -- repeat
    calls with the same (name, outlined, target_h) are cheap.
    """
    canvas.delete(tag)
    target_h = max(4, int(target_h))
    key = (name, outlined, target_h)
    no_rotate_or_distort = not rotate_deg and distort <= 0.002

    if no_rotate_or_distort and key in _ART_PHOTO_CACHE:
        photo, w, h = _ART_PHOTO_CACHE[key]
    else:
        resized = _ART_RESIZED_CACHE.get(key)
        if resized is None:
            src = _load_art_image_outlined(name) if outlined else _load_art_image(name)
            scale = target_h / src.height
            target_w = max(4, int(src.width * scale))
            resized = src.resize((target_w, target_h), Image.LANCZOS)
            _ART_RESIZED_CACHE[key] = resized
        out = _apply_row_distort(resized, distort, phase)
        if rotate_deg:
            out = out.rotate(-rotate_deg, expand=True, resample=Image.BICUBIC)
        photo = ImageTk.PhotoImage(out)
        w, h = out.width, out.height
        if no_rotate_or_distort:
            _ART_PHOTO_CACHE[key] = (photo, w, h)

    if not hasattr(canvas, "_art_photo_refs"):
        canvas._art_photo_refs = {}
    canvas._art_photo_refs[tag] = photo  # prevent GC
    canvas.create_image(cx, cy, image=photo, anchor="center", tags=tag)
    return w, h


# Fractional anchor offsets (relative to each character's own displayed
# width/height, measured from its center) used to aim the photon at
# roughly the right spot -- the neuron's eye, the chameleon's snout tip --
# rather than just its bounding-box center. Approximate (eyeballed from
# the source images' own proportions), not pixel-exact.
NRN_EYE_OFFSET_FRAC = (0.0, -0.22)      # eye sits a bit above center (legs take up the lower half)
CHAM_SNOUT_OFFSET_FRAC = (-0.48, -0.22)  # snout is at the far-left edge, upper third (measured
                                          # directly off chameleon.png's alpha bbox: leftmost
                                          # content column sits at y-fraction -0.217 of height)
HAND_GRIP_OFFSET_FRAC = (0.0, -0.28)     # H2's curled fingers/knuckle cluster sits in the upper
                                          # ~1/3 of the image (wrist/arm fills the lower 2/3), so
                                          # the caught photon is drawn there, not at the hand's
                                          # bbox center


def _smoothstep(x):
    """Ease-in-out a 0..1 progress fraction (3x^2 - 2x^3) -- used for the
    slab-hand's rise/drag motion so a large vertical travel over just a
    handful of 33ms frames accelerates in and decelerates out instead of
    moving at a flat, choppy-looking constant speed."""
    x = 0.0 if x < 0.0 else (1.0 if x > 1.0 else x)
    return x * x * (3.0 - 2.0 * x)


# The 6 new poses Filip supplied from "Untitled - 15 July 2026 13 01
# Artboard 1.svg", replacing the original 3-pose (surprised/annoyed/sleepy)
# pool. "alt5" reads as the one actually getting smashed -- its whole body
# is tilted into a dynamic diagonal lean, eye squinted shut, antenna bent
# back with a motion-line stroke -- so PhotonNeuronBar always shows that
# specific pose the instant a photon lands, rather than a random one of
# the six. NEURON_IDLE_REACTION_EXPRS is what it regresses to afterward: a
# random pick from the remaining 5, instead of snapping back to the plain
# neutral face every time.
NEURON_SMASHED_EXPR = "alt5"
NEURON_IDLE_REACTION_EXPRS = ["alt1", "alt2", "alt3", "alt4", "alt6"]


def draw_neuron(canvas, cx, cy, scale, expr="neutral", distort=0.0, phase=0.0,
                 tag="neuron", outline="#111111"):
    """Draw Filip's actual neuron sketch (one of 4 expressions) centered at
    (cx, cy). `scale` sets the display size (kept as the same "px per local
    60-unit" convention the old vector version used, so callers didn't need
    to change their numbers -- multiplied by a fixed constant to get a
    pixel height). `distort` in [0, 1] applies a scanline glitch that the
    motion-correction overlay decays to zero as NormCorre progresses.
    Returns (disp_w, disp_h) for anchor-point math."""
    # "surprised"/"annoyed"/"sleepy" are the original 3-pose set (kept for
    # backward compat / anywhere that names them directly); "alt1".."alt6"
    # are the 6 new poses Filip supplied, which is what PhotonNeuronBar's
    # hit-reaction pool actually randomizes across now (see NEURON_REACTION_EXPRS).
    name = {"neutral": "neuron_neutral", "surprised": "neuron_surprised",
            "annoyed": "neuron_annoyed", "sleepy": "neuron_sleepy",
            "alt1": "neuron_alt1", "alt2": "neuron_alt2", "alt3": "neuron_alt3",
            "alt4": "neuron_alt4", "alt5": "neuron_alt5", "alt6": "neuron_alt6",
            }.get(expr, "neuron_neutral")
    target_h = scale * 4.2
    return _render_art_image(canvas, name, cx, cy, target_h, tag,
                              distort=distort, phase=phase, outlined=True)


def draw_chameleon(canvas, cx, cy, scale, tag="chameleon", outline="#111111"):
    """Draw Filip's actual chameleon sketch (the animation's 'light
    source') centered at (cx, cy). Returns (disp_w, disp_h)."""
    target_h = scale * 3.4
    return _render_art_image(canvas, "chameleon", cx, cy, target_h, tag, outlined=True)


def draw_slab_hand(canvas, cx, cy, scale, tag="slab_hand", pose="open"):
    """Draw the slab-hand (Filip's H1/H2 sketches -- "I would like to have
    this hand come from below open and than close with the photon in it
    and drag it off screen down. It can come and leave in a hole"),
    centered at (cx, cy). pose="open" is H1 (fingers spread, rising to
    catch); pose="closed" is H2 (fingers curled shut around the caught
    photon, dragging it away). Both keep the "SLAB" wordmark baked into
    the artwork itself. See PhotonNeuronBar's _hand_phase state machine
    ("hidden"/"rise"/"close"/"hold"/"drag") for the full sequence. Returns
    (disp_w, disp_h)."""
    name = "slab_hand_closed" if pose == "closed" else "slab_hand_open"
    # Was scale*5.0 -- at PhotonNeuronBar.NRN_SCALE=56 that's a 280px-tall
    # hand sitting at the midpoint between the chameleon and neuron's own
    # eye-lines (roughly mid-canvas height), which left it clipping the
    # top/bottom of the (340px-tall) canvas as it rose/dragged. Shrunk
    # per Filip's "the hand goes out of bounds so maybe make it smaller"
    # (paired with a taller canvas -- see PhotonNeuronBar.HEIGHT).
    target_h = scale * 3.2
    return _render_art_image(canvas, name, cx, cy, target_h, tag, outlined=True)


def draw_donut_neuron(canvas, cx, cy, scale, pose="standing", tag="donut_neuron"):
    """Draw one frame of the Neuropil Sweep tab's donut-eating-neuron idle
    animation (DonutNeuronBar), centered at (cx, cy). `pose` selects one of
    the five poses in the eat cycle -- "standing" (neutral, no donut yet,
    also used while DonutNeuronBar is busy/sweeping), "approach" (donut
    arriving near the mouth), "bite", "chew", "crumbs" (still chewing,
    crumbs starting to fall from the source art itself -- separate from
    the accumulated crumb dots DonutNeuronBar draws on the ground, which
    persist across cycles instead of resetting each loop). Returns
    (disp_w, disp_h)."""
    name = {"standing": "neuron_idle_standing", "approach": "neuron_donut_approach",
            "bite": "neuron_donut_bite", "chew": "neuron_donut_chew",
            "crumbs": "neuron_donut_crumbs"}.get(pose, "neuron_idle_standing")
    target_h = scale * 4.6
    return _render_art_image(canvas, name, cx, cy, target_h, tag, outlined=True)


def draw_broom(canvas, cx, cy, scale, tag="broom"):
    """Draw the broom DonutNeuronBar sweeps across the accumulated crumbs
    with once a real Neuropil Sweep run starts -- per Filip: "when the
    loading is happening sweep the crumbs away." Returns (disp_w, disp_h)."""
    target_h = scale * 6.0
    return _render_art_image(canvas, "broom", cx, cy, target_h, tag, outlined=True)


def _load_photon_variant(tint="red"):
    """The photon squiggle art for a given leg of the volley: 'red' is the
    chameleon's outbound shot, 'green' is the neuron's return shot. Each is
    real, independently hand-drawn artwork (photon_red.png / photon_green.png)
    with its own black ink wave, with a white silhouette outline added like
    the other assets (ink/fill colors untouched, just outlined). Previously
    the green variant was synthesized by swapping the red art's R/G
    channels; Filip has since supplied a real green-inked squiggle, so that
    synthesis is no longer needed."""
    name = "photon_green" if tint == "green" else "photon_red"
    return _load_art_image_outlined(name)


def draw_photon(canvas, cx, cy, length, amplitude, angle_deg, phase, tag="photon",
                 tint="red"):
    """Draw Filip's actual photon squiggle sketch centered at (cx, cy),
    sized from `length`, rotated to point along its direction of travel
    (`angle_deg`). `amplitude`/`phase` no longer reshape the squiggle itself
    (it's a fixed drawing now) but `phase` still adds a small extra wobble
    rotation so the in-flight animation keeps some life to it. `tint`
    selects "red" (the chameleon's outbound shot) or "green" (the neuron's
    return volley)."""
    canvas.delete(tag)
    im = _load_photon_variant(tint)
    target_w = max(4, int(length * 2.0))
    scale = target_w / im.width
    target_h = max(4, int(im.height * scale))
    im = im.resize((target_w, target_h), Image.LANCZOS)
    wobble = 6.0 * math.sin(phase)
    im = im.rotate(-(angle_deg + wobble), expand=True, resample=Image.BICUBIC)
    photo = ImageTk.PhotoImage(im)
    if not hasattr(canvas, "_art_photo_refs"):
        canvas._art_photo_refs = {}
    canvas._art_photo_refs[tag] = photo
    canvas.create_image(cx, cy, image=photo, anchor="center", tags=tag)


def draw_tally(canvas, x, y, count, tag="tally", stroke=2, line_h=16, line_w=6,
                group_gap=9, color="#111111", max_groups=6):
    """Draw `count` as classic 'gate' tally marks (four verticals per group
    of five, with a diagonal fifth stroke crossing them), left to right
    starting at (x, y) as the top-left anchor. Caps at `max_groups` full
    groups to avoid overflowing the strip; anything beyond that collapses
    to a '+N' text suffix instead of drawing hundreds of tiny lines.
    Returns the x-coordinate just past the last mark drawn (for layout)."""
    canvas.delete(tag)
    full_groups, remainder = divmod(max(0, int(count)), 5)
    cx = x
    drawn_groups = min(full_groups, max_groups)
    for _ in range(drawn_groups):
        for i in range(4):
            lx = cx + i * line_w
            canvas.create_line(lx, y, lx, y + line_h, fill=color, width=stroke, tags=tag)
        canvas.create_line(cx - 2, y + line_h + 2, cx + 3 * line_w + 2, y - 2,
                            fill=color, width=stroke, tags=tag)
        cx += 4 * line_w + group_gap

    if full_groups > max_groups:
        leftover = count - drawn_groups * 5
        canvas.create_text(cx, y + line_h / 2, text=f"+{leftover}", fill=color,
                            font=(FONT_FAMILY, 10, "bold"), anchor="w", tags=tag)
        return cx + 28

    for i in range(remainder):
        lx = cx + i * line_w
        canvas.create_line(lx, y, lx, y + line_h, fill=color, width=stroke, tags=tag)
    return cx + remainder * line_w


def _rounded_rect_points(x1, y1, x2, y2, radius):
    """Point list for a rounded rectangle, meant to be drawn via
    canvas.create_polygon(points, smooth=True, ...) -- the standard
    tkinter recipe for smooth corners (Tk's Canvas has no native
    rounded-rectangle primitive). `radius` is clamped so it never exceeds
    half the shorter side, which would otherwise self-intersect on very
    small/thin cards."""
    radius = max(0, min(radius, (x2 - x1) / 2, (y2 - y1) / 2))
    return [
        x1 + radius, y1,
        x2 - radius, y1,
        x2, y1,
        x2, y1 + radius,
        x2, y2 - radius,
        x2, y2,
        x2 - radius, y2,
        x1 + radius, y2,
        x1, y2,
        x1, y2 - radius,
        x1, y1 + radius,
        x1, y1,
    ]


def _lighten_hex(hex_color, amt):
    """Blend a "#rrggbb" color toward white by `amt` (0-1) -- used for the
    hover state of rounded buttons, a flat color-shift instead of the old
    relief=RAISED/SUNKEN 3D bevel (which doesn't read right on a rounded
    shape)."""
    hex_color = hex_color.lstrip("#")
    r, g, b = int(hex_color[0:2], 16), int(hex_color[2:4], 16), int(hex_color[4:6], 16)
    r = min(255, int(r + (255 - r) * amt))
    g = min(255, int(g + (255 - g) * amt))
    b = min(255, int(b + (255 - b) * amt))
    return f"#{r:02x}{g:02x}{b:02x}"


BTN_RADIUS = 10     # corner radius for pill-shaped buttons, in px
ENTRY_RADIUS = 8    # corner radius for pill-shaped entry fields, in px


def _rounded_entry(parent, textvariable, width=7, justify="right", font_size=10):
    """A rounded-pill entry field -- a small Canvas draws the rounded-rect
    background (BG_PANEL, matching the old square entry's own fill), with
    a borderless tk.Entry (same bg, so its own square corners blend
    invisibly into the canvas fill beneath/around it) inset within it via
    create_window. Redraws on <Configure> of either the entry itself
    (natural-width case, most sidebar rows) or the canvas itself (the
    fill=X/expand=True case, e.g. the fit-range lo/hi pair sharing a row).
    Returns (canvas, entry) -- pack/grid the canvas; bind tooltips, focus,
    etc. to `entry` exactly as with a plain tk.Entry."""
    parent_bg = parent["bg"]
    canvas = tk.Canvas(parent, bg=parent_bg, highlightthickness=0, bd=0)
    entry = tk.Entry(canvas, textvariable=textvariable, width=width,
                      bg=BG_PANEL, fg="white", insertbackground="white",
                      relief=tk.FLAT, font=(FONT_FAMILY, font_size),
                      justify=justify, bd=0, highlightthickness=0)
    win_id = canvas.create_window(0, 0, window=entry, anchor="nw")
    state = {"bg_item": None}

    def _redraw(event=None):
        req_w = entry.winfo_reqwidth()
        req_h = entry.winfo_reqheight()
        w, h = req_w + 14, req_h + 8
        cw = canvas.winfo_width()
        if cw > 1:
            w = max(w, cw)
        canvas.config(height=h)
        if cw <= 1:
            canvas.config(width=w)
        canvas.coords(win_id, max((w - req_w) // 2, 6), (h - req_h) // 2)
        pts = _rounded_rect_points(1, 1, w - 1, h - 1, ENTRY_RADIUS)
        if state["bg_item"] is None:
            state["bg_item"] = canvas.create_polygon(pts, smooth=True, fill=BG_PANEL, outline="")
            canvas.tag_lower(state["bg_item"])
        else:
            canvas.coords(state["bg_item"], *pts)

    entry.bind("<Configure>", _redraw)
    canvas.bind("<Configure>", _redraw)
    canvas.after_idle(_redraw)
    return canvas, entry


def _rounded_button(parent, text, command, bg=None, fg="white", font_size=10,
                     bold=False, side=tk.LEFT, padx=6, pady=5, fill=None):
    """Rounded-pill button -- shared by the top-bar/sidebar `_lbtn` helper
    (KurtosisChecker._build_controls) and standalone Toplevel dialogs
    (OK/Cancel/Continue/Close), so every clickable button in the app gets
    the same treatment instead of just the ones inside the main window.

    A small Canvas draws the rounded-rect background (redrawn on every
    <Configure> to match its content/parent size, same recipe as
    _sidebar_card / _rounded_entry), with a borderless Label holding the
    text embedded on top via create_window. Hover gives a flat
    color-shift instead of a 3D relief bevel, which doesn't read right on
    a rounded shape.

    Returns the outer Frame, with .config()/.configure() overridden so
    `btn.config(bg=..., fg=..., text=...)` keeps working exactly like it
    did against the old plain widgets (e.g. the active-tab toggle)."""
    if bg is None:
        bg = GREY_BTN
    weight = "bold" if bold else "normal"
    parent_bg = parent["bg"]
    outer = tk.Frame(parent, bg=parent_bg)
    if fill:
        outer.pack(side=side, padx=padx, pady=pady, fill=fill)
    else:
        outer.pack(side=side, padx=padx, pady=pady)

    canvas = tk.Canvas(outer, bg=parent_bg, highlightthickness=0, bd=0, cursor="hand2")
    canvas.pack(fill=tk.BOTH if fill else None, expand=bool(fill))

    label = tk.Label(canvas, text=text, bg=bg, fg=fg,
                      font=(FONT_FAMILY, font_size, weight), cursor="hand2")
    win_id = canvas.create_window(0, 0, window=label, anchor="nw")

    state = {"bg_item": None, "base_bg": bg}

    def _apply_bg(color):
        label.config(bg=color)
        if state["bg_item"] is not None:
            canvas.itemconfig(state["bg_item"], fill=color)

    def _redraw(event=None):
        req_w = label.winfo_reqwidth()
        req_h = label.winfo_reqheight()
        w, h = req_w + 30, req_h + 12
        cw = canvas.winfo_width()
        if fill and cw > 1:
            w = max(w, cw)
        canvas.config(height=h)
        if not fill or cw <= 1:
            canvas.config(width=w)
        canvas.coords(win_id, (w - req_w) // 2, (h - req_h) // 2)
        pts = _rounded_rect_points(1, 1, w - 1, h - 1, BTN_RADIUS)
        if state["bg_item"] is None:
            state["bg_item"] = canvas.create_polygon(
                pts, smooth=True, fill=state["base_bg"], outline="")
            canvas.tag_lower(state["bg_item"])
        else:
            canvas.coords(state["bg_item"], *pts)

    label.bind("<Configure>", _redraw)
    if fill:
        canvas.bind("<Configure>", _redraw)

    def _click(e=None):
        command()

    def _enter(e=None):
        _apply_bg(_lighten_hex(state["base_bg"], 0.18))

    def _leave(e=None):
        _apply_bg(state["base_bg"])

    for w_ in (canvas, label):
        w_.bind("<Button-1>", _click)
        w_.bind("<Enter>", _enter)
        w_.bind("<Leave>", _leave)

    orig_config = outer.config

    def _custom_config(**kwargs):
        if "text" in kwargs:
            label.config(text=kwargs.pop("text"))
            outer.after_idle(_redraw)
        if "fg" in kwargs:
            label.config(fg=kwargs.pop("fg"))
        if "bg" in kwargs:
            state["base_bg"] = kwargs.pop("bg")
            _apply_bg(state["base_bg"])
        if kwargs:
            orig_config(**kwargs)

    outer.config = _custom_config
    outer.configure = _custom_config

    outer.after_idle(_redraw)
    return outer


class PhotonNeuronBar(tk.Canvas):
    """Busy-state animation replacing the plain progress strip: a chameleon
    (light source) launches red photon squiggles at the neuron; each impact
    increments a running counter and swaps the neuron's expression for a
    moment. Purely decorative -- ticks continuously while Run Analysis is
    doing anything (reg_tif read / PTC compute / CNMF), not tied to a real
    progress metric, since most of those steps don't expose one either.

    Dark background matching the rest of the app, neuron on the left,
    chameleon on the right -- both drawn with their original black ink
    strokes/colored fill untouched, plus a white silhouette outline traced
    around the outside so they read against the dark canvas instead of
    needing a white one."""

    # Sized for display in the main output area (replacing the plot canvas
    # while Run Analysis works) rather than the old slim strip under the
    # status line -- bumped up proportionally from the original 190/42/46
    # so the characters read at a reasonable size in that much larger space.
    #
    # HEIGHT/NRN_SCALE/nrn_cy (in _render, below) were previously 300/66/0.68
    # -- with the neuron centered that low and that tall (scale*4.2 =
    # ~277px), its bottom edge landed at y=~343, well past the 300px-tall
    # canvas, so its legs (and the "photons:" tally line sitting right
    # underneath) were silently clipped by the canvas boundary. Fixed by
    # raising the neuron's vertical anchor (closer to the chameleon's own,
    # for a more natural "facing each other" eye-line too), trimming its
    # scale slightly, and giving the canvas a bit more headroom overall.
    #
    # Bumped again, 340 -> 380, alongside shrinking the hand itself (see
    # draw_slab_hand) -- per Filip's "the hand goes out of bounds so
    # maybe make it smaller and the canvas bigger": the hand rises to sit
    # at the midpoint between the chameleon's and neuron's eye-lines,
    # roughly mid-canvas, and at its old size that put its top/bottom
    # edges close enough to the canvas boundary to visibly clip while
    # rising/dragging.
    HEIGHT = 380
    NRN_SCALE = 56
    CHAM_SCALE = 72

    # Each volley: the chameleon fires two red photons in quick succession
    # (STAGGER seconds apart, both genuinely in flight together for most of
    # the trip -- a "burst" rather than one-at-a-time), then once both have
    # landed, the neuron fires exactly one green photon back. Flight A
    # ("_flight_frac"/"_flight_dir") carries the first outbound leg and
    # later the single return leg; flight B ("_flight2_frac", always
    # outbound) only ever carries the second, closely-following shot.
    VOLLEY_STAGGER = 0.15

    # The slab-hand catches the return shot at the midpoint between the
    # chameleon and the neuron, but per Filip's redesign it's no longer a
    # scale pop-in there: "I would like to have this hand come from below
    # open and than close with the photon in it and drag it off screen
    # down. It can come and leave in a hole." So the sequence is now a
    # vertical rise/drag with a pose swap, not a scale animation:
    #   "rise" -- open hand (H1) rises up from a hole at the bottom of the
    #             canvas to the midpoint, starting as soon as the return
    #             flight leaves the neuron (so it's in position, open,
    #             before the photon actually arrives) -- HAND_RISE_DUR.
    #   "close" -- right when the return photon lands at the midpoint
    #              (frac >= 1.0 for the "back" flight), the hand snaps
    #              from open (H1) to closed (H2) around it -- HAND_CLOSE_DUR
    #              (a small static photon_green glyph is then drawn tucked
    #              into the closed fist -- see HAND_GRIP_OFFSET_FRAC --
    #              rather than just vanishing on contact).
    #   "hold" -- briefly holds closed at the midpoint -- HAND_HOLD_DUR.
    #   "drag" -- drags the closed hand straight down, back into the hole,
    #             off the bottom of the canvas -- HAND_DRAG_DUR.
    # "rise" and "drag" ease in/out (see _smoothstep) rather than moving at
    # a flat linear speed, and their durations are long enough relative to
    # the 33ms tick that the motion reads as continuous rather than a
    # visible per-frame jump.
    #
    # Re-tuned per Filip's "you can make it come up and down faster making
    # it stay for a bit in the way of the photon and then snapping when the
    # photon is on top of it. (0.5s open, 0.5s closed) and then quick
    # removal." The hand starts rising the instant the return shot
    # launches and only ever snaps shut the instant that shot actually
    # lands (a fixed ~0.55s window -- see `dur` in _tick), so shrinking
    # HAND_RISE_DUR doesn't shorten how long the hand is up waiting, it
    # just makes the rise itself quicker and leaves more of that ~0.5s
    # window as a still, fully-open hand sitting right in the photon's
    # path -- exactly "stay for a bit in the way of the photon." Closed
    # hold time is now explicitly ~0.5s, and the drag back into the hole
    # is much shorter for a "quick removal."
    # See _hand_phase ("hidden" / "rise" / "close" / "hold" / "drag").
    HAND_RISE_DUR = 0.15
    HAND_CLOSE_DUR = 0.1
    HAND_HOLD_DUR = 0.5
    HAND_DRAG_DUR = 0.2
    HAND_HOLE_Y_OFFSET = 34  # how far below the canvas bottom the hole's
                              # "fully hidden" hand position sits

    # Per Filip's "the chameleon can wait 0.5s after the hand is gone
    # before triggering a photon again": the next volley's launch time is
    # set once the hand actually finishes dragging away (see the "drag"
    # branch below transitioning to "hidden"), not back when the photon
    # first landed -- otherwise a new volley could fire while the hand is
    # still visibly on its way out, undercutting the "the hand is gone"
    # part of the pause.
    NEXT_VOLLEY_PAUSE_S = 0.5

    def __init__(self, parent, **kw):
        super().__init__(parent, height=self.HEIGHT, bg=BG_DARK, highlightthickness=0, **kw)
        self._width = 400
        self._running = False
        self._job = None
        self._hits = 0
        self._expr = "neutral"
        self._expr_until = 0.0
        self._flight_frac = None
        self._flight_t0 = 0.0
        self._flight_dir = "out"  # "out" = chameleon->neuron, "back" = neuron->chameleon
        self._flight2_frac = None   # the 2nd, closely-following outbound shot
        self._flight2_t0 = 0.0
        self._next_second_launch = None
        self._out_landed = None     # outbound shots landed so far this volley (0/1/2), None = idle
        self._return_pending = False
        self._next_launch = 0.0
        self._t0 = None
        self._hand_phase = "hidden"   # "hidden"/"rise"/"close"/"hold"/"drag"
        self._hand_frac = None        # progress 0..1 through the current sub-phase
        self._hand_t0 = 0.0
        self.bind("<Configure>", self._on_resize)

    def _on_resize(self, event):
        self._width = event.width
        if not self._running:
            self._render(0.0)

    def start(self):
        if self._running:
            return
        self._running = True
        self._hits = 0
        self._expr = "neutral"
        self._t0 = time.monotonic()
        self._next_launch = 0.4
        self._flight_frac = None
        self._flight_dir = "out"
        self._flight2_frac = None
        self._next_second_launch = None
        self._out_landed = None
        self._return_pending = False
        self._hand_phase = "hidden"
        self._hand_frac = None
        self._tick()

    def stop(self):
        self._running = False
        if self._job is not None:
            try:
                self.after_cancel(self._job)
            except Exception:
                pass
            self._job = None
        self.delete("all")

    def _tick(self):
        if not self._running:
            return
        t = time.monotonic() - self._t0
        dur = 0.55

        # -- launch shot A: the first outbound photon of a new volley --
        # `_out_landed is None` guards against the window that now exists
        # between "both outbound shots landed" and "the return shot
        # actually fires" (the neuron holds its hit pose for a beat
        # first -- see the combined revert+return block below): during
        # that hold, flight_frac/flight2_frac/return_pending all look
        # exactly like full idle, but _out_landed is still 2, not None.
        # Without this check a new volley could spuriously launch on top
        # of a volley that's still mid-hold, orphaning the pending return.
        if (self._flight_frac is None and self._flight2_frac is None
                and not self._return_pending and self._out_landed is None
                and t >= self._next_launch):
            self._flight_frac = 0.0
            self._flight_t0 = t
            self._flight_dir = "out"
            self._out_landed = 0
            self._next_second_launch = t + self.VOLLEY_STAGGER

        # -- launch shot B shortly after shot A ("right after each other"),
        #    while shot A is typically still mid-flight --
        if (self._flight2_frac is None and self._flight_dir == "out"
                and self._next_second_launch is not None
                and t >= self._next_second_launch):
            self._flight2_frac = 0.0
            self._flight2_t0 = t
            self._next_second_launch = None

        # -- advance shot A (outbound leg, or later the single return leg) --
        if self._flight_frac is not None:
            frac = (t - self._flight_t0) / dur
            if frac >= 1.0:
                if self._flight_dir == "out":
                    self._hits += 1
                    self._out_landed += 1
                    self._expr = NEURON_SMASHED_EXPR
                    self._expr_until = t + 0.5
                    self._flight_frac = None
                else:
                    # the single return shot landed at the midpoint -- the
                    # slab-hand (already risen, open, waiting there since
                    # the return flight started) closes around it right
                    # now, regardless of exactly how far its rise had
                    # gotten. Volley's done.
                    self._flight_frac = None
                    self._flight_dir = "out"
                    self._return_pending = False
                    self._out_landed = None
                    # NOT scheduling _next_launch here anymore -- see
                    # NEXT_VOLLEY_PAUSE_S: it's now set once the hand
                    # actually finishes dragging away (the "drag" ->
                    # "hidden" transition below), not at landing time.
                    self._hand_phase = "close"
                    self._hand_t0 = t
                    self._hand_frac = 0.0
            else:
                self._flight_frac = frac

        # -- advance the hand's rise / close / hold / drag timeline (see
        # the HAND_* constants' docstring above for the full sequence).
        # "rise" and "drag" interpolate the hand's y-position (see
        # _render); "close" swaps its pose from open to closed partway
        # through, then "hold"/"drag" stay closed. --
        if self._hand_phase == "rise":
            dt = t - self._hand_t0
            # No self-driven transition out of "rise" -- it just holds at
            # frac=1.0 (fully risen, open, waiting) if it finishes before
            # the photon lands; the landing branch above force-jumps it to
            # "close" whenever that actually happens.
            self._hand_frac = min(1.0, dt / self.HAND_RISE_DUR)
        elif self._hand_phase == "close":
            dt = t - self._hand_t0
            if dt >= self.HAND_CLOSE_DUR:
                self._hand_phase = "hold"
                self._hand_t0 = t
                self._hand_frac = 1.0
            else:
                self._hand_frac = dt / self.HAND_CLOSE_DUR
        elif self._hand_phase == "hold":
            dt = t - self._hand_t0
            if dt >= self.HAND_HOLD_DUR:
                self._hand_phase = "drag"
                self._hand_t0 = t
            else:
                self._hand_frac = 1.0
        elif self._hand_phase == "drag":
            dt = t - self._hand_t0
            if dt >= self.HAND_DRAG_DUR:
                self._hand_phase = "hidden"
                self._hand_frac = None
                # The hand is now genuinely gone -- per Filip, the
                # chameleon waits NEXT_VOLLEY_PAUSE_S from this exact
                # moment (not from when the photon was caught) before the
                # next volley is allowed to launch.
                self._next_launch = t + self.NEXT_VOLLEY_PAUSE_S
            else:
                self._hand_frac = dt / self.HAND_DRAG_DUR

        # -- advance shot B (always outbound) --
        if self._flight2_frac is not None:
            frac2 = (t - self._flight2_t0) / dur
            if frac2 >= 1.0:
                self._hits += 1
                self._out_landed += 1
                self._expr = NEURON_SMASHED_EXPR
                self._expr_until = t + 0.5
                self._flight2_frac = None
            else:
                self._flight2_frac = frac2

        # -- once both outbound shots have landed AND the smashed-pose
        #    hold has run its course, the neuron fires its one return shot
        #    back (reusing flight A's slot), timed to leave as it's
        #    visibly reverting out of the 'hit' stance into a random idle
        #    pose -- rather than the instant it gets hit, while still
        #    mid-flinch, which is what this did before. Checking against
        #    NEURON_SMASHED_EXPR specifically (not "not neutral") means
        #    this whole block only fires once per hit: after it picks a
        #    random idle pose, _expr no longer equals NEURON_SMASHED_EXPR,
        #    so it won't re-trigger on every subsequent tick.
        if (self._expr == NEURON_SMASHED_EXPR and t >= self._expr_until
                and self._out_landed is not None and self._out_landed >= 2
                and self._flight_frac is None and self._flight2_frac is None
                and not self._return_pending):
            self._expr = random.choice(NEURON_IDLE_REACTION_EXPRS)
            self._return_pending = True
            self._flight_dir = "back"
            self._flight_frac = 0.0
            self._flight_t0 = t
            # the hand starts rising the instant the return flight leaves
            # the neuron -- open (H1), climbing out of the hole -- so it's
            # already in position and waiting by the time the photon
            # actually reaches the midpoint (HAND_RISE_DUR < dur, the
            # flight time). It's forced to "close" the moment the photon
            # actually lands (see the "advance shot A" landing branch
            # below), regardless of exactly how far the rise had gotten.
            self._hand_phase = "rise"
            self._hand_t0 = t
            self._hand_frac = 0.0
        try:
            self._render(t)
        except Exception:
            # Never let a rendering hiccup (e.g. a missing art/ asset) kill
            # the recurring .after() schedule -- that would silently stop
            # the whole loader with no visible error. Log once via the
            # canvas's own error flag instead of spamming every 33ms.
            if not getattr(self, "_render_error_shown", False):
                self._render_error_shown = True
                traceback.print_exc()
        self._job = self.after(33, self._tick)

    def _render(self, t):
        w = max(self._width, 60)
        h = self.HEIGHT
        nrn_cx, nrn_cy = w * 0.16, h * 0.55
        cham_cx, cham_cy = w * 0.86, h * 0.46

        nrn_w, nrn_h = draw_neuron(self, nrn_cx, nrn_cy, scale=self.NRN_SCALE,
                                    expr=self._expr, tag="nrn")
        cham_w, cham_h = draw_chameleon(self, cham_cx, cham_cy, scale=self.CHAM_SCALE,
                                         tag="cham")

        cham_pt = (cham_cx + CHAM_SNOUT_OFFSET_FRAC[0] * cham_w,
                   cham_cy + CHAM_SNOUT_OFFSET_FRAC[1] * cham_h)
        nrn_pt = (nrn_cx + NRN_EYE_OFFSET_FRAC[0] * nrn_w,
                  nrn_cy + NRN_EYE_OFFSET_FRAC[1] * nrn_h)
        # the slab-hand's fixed pop-in spot -- the midpoint between the
        # chameleon and the neuron -- and also the return flight's actual
        # destination, so the hand is genuinely catching it right there
        # rather than just decorating a flight that ends elsewhere.
        mid_pt = ((nrn_pt[0] + cham_pt[0]) / 2, (nrn_pt[1] + cham_pt[1]) / 2)

        if self._flight_frac is not None:
            if self._flight_dir == "out":
                (x0, y0), (x1, y1) = cham_pt, nrn_pt
                tint = "red"
            else:
                (x0, y0), (x1, y1) = nrn_pt, mid_pt
                tint = "green"
            fx = x0 + (x1 - x0) * self._flight_frac
            fy = y0 + (y1 - y0) * self._flight_frac
            angle = math.degrees(math.atan2(y1 - y0, x1 - x0))
            draw_photon(self, fx, fy, length=30, amplitude=8,
                        angle_deg=angle, phase=t * 14, tag="photon", tint=tint)
        else:
            self.delete("photon")

        # shot B -- the 2nd, closely-following outbound photon of the
        # burst -- is always red/outbound, drawn under its own tag so it
        # doesn't get clobbered by draw_photon's internal delete(tag) call
        # for shot A above.
        if self._flight2_frac is not None:
            (x0, y0), (x1, y1) = cham_pt, nrn_pt
            fx = x0 + (x1 - x0) * self._flight2_frac
            fy = y0 + (y1 - y0) * self._flight2_frac
            angle = math.degrees(math.atan2(y1 - y0, x1 - x0))
            draw_photon(self, fx, fy, length=30, amplitude=8,
                        angle_deg=angle, phase=t * 14 + 2.5, tag="photon2", tint="red")
        else:
            self.delete("photon2")

        # The slab-hand: rises open (H1) from a hole below the canvas up
        # to the midpoint, closes (H2) around the landed return photon,
        # holds, then drags back down into the hole. See the HAND_* consts
        # and _tick's phase-advancement block for the full timeline.
        # Rise/drag use an ease-in-out (smoothstep) curve rather than raw
        # linear interpolation -- a big vertical travel at a flat, constant
        # speed over a handful of 33ms frames is what read as "very not
        # smooth" (visibly jumping a fixed pixel step every frame with no
        # easing at either end).
        if self._hand_phase != "hidden" and self._hand_frac is not None:
            hole_y = h + self.HAND_HOLE_Y_OFFSET  # off-canvas, "inside the hole"
            hand_x = mid_pt[0]
            grip_pt = None  # where the caught photon sits once the hand has closed
            if self._hand_phase == "rise":
                eased = _smoothstep(self._hand_frac)
                hy = hole_y + (mid_pt[1] - hole_y) * eased
                pose = "open"
            elif self._hand_phase == "close":
                hy = mid_pt[1]
                closed = self._hand_frac >= 0.5
                pose = "closed" if closed else "open"
                if closed:
                    grip_pt = (hand_x, hy)
            elif self._hand_phase == "hold":
                hy = mid_pt[1]
                pose = "closed"
                grip_pt = (hand_x, hy)
            else:  # "drag"
                eased = _smoothstep(self._hand_frac)
                hy = mid_pt[1] + (hole_y - mid_pt[1]) * eased
                pose = "closed"
                grip_pt = (hand_x, hy)
            # A small dark ellipse at the hole's mouth, right at the
            # canvas's bottom edge, so the hand visibly emerges from and
            # recedes into it rather than just appearing/disappearing.
            self.create_oval(hand_x - 24, h - 7, hand_x + 24, h + 7,
                              fill="#050505", outline="", tags="hand_hole")
            hand_w, hand_h = draw_slab_hand(self, hand_x, hy, scale=self.NRN_SCALE,
                                             pose=pose, tag="hand")
            if grip_pt is not None:
                # The caught photon, small and static (no wave animation --
                # it's held still, not in flight), tucked into the closed
                # fist rather than just vanishing on contact.
                gx = grip_pt[0] + HAND_GRIP_OFFSET_FRAC[0] * hand_w
                gy = grip_pt[1] + HAND_GRIP_OFFSET_FRAC[1] * hand_h
                _render_art_image(self, "photon_green", gx, gy, target_h=16,
                                   tag="hand_photon", outlined=True)
            else:
                self.delete("hand_photon")
        else:
            self.delete("hand")
            self.delete("hand_hole")
            self.delete("hand_photon")

        self.delete("counter_label")
        label = self.create_text(14, h - 12, text="photons:", anchor="w",
                                  fill=TEXT_MAIN, font=(FONT_FAMILY, 9), tags="counter_label")
        bbox = self.bbox(label)
        tally_x = (bbox[2] + 8) if bbox else 70
        draw_tally(self, tally_x, h - 12, self._hits, tag="counter_tally", color=TEXT_MAIN)


class PlainProgressBar(tk.Canvas):
    """The "de-whimsified" stand-in for PhotonNeuronBar (and, later, any
    other creative busy-animation) -- same drop-in start()/stop()/pack()
    interface and footprint (HEIGHT matches PhotonNeuronBar.HEIGHT so
    swapping between the two never jumps the layout), but purely a plain
    indeterminate bar with a status word underneath. No characters, no
    art. See KurtosisChecker.whimsy_var / _toggle_whimsy / _active_bar."""

    HEIGHT = 340
    BAR_W_FRAC = 0.6
    BAR_H = 10
    SWEEP_PERIOD = 1.4   # seconds for the highlight to cross the track once

    def __init__(self, parent, **kw):
        super().__init__(parent, height=self.HEIGHT, bg=BG_DARK, highlightthickness=0, **kw)
        self._width = 400
        self._running = False
        self._job = None
        self._t0 = None
        self.bind("<Configure>", self._on_resize)

    def _on_resize(self, event):
        self._width = event.width
        if not self._running:
            self._render(0.0)

    def start(self):
        if self._running:
            return
        self._running = True
        self._t0 = time.monotonic()
        self._tick()

    def stop(self):
        self._running = False
        if self._job is not None:
            try:
                self.after_cancel(self._job)
            except Exception:
                pass
            self._job = None
        self.delete("all")

    def _tick(self):
        if not self._running:
            return
        t = time.monotonic() - self._t0
        self._render(t)
        self._job = self.after(30, self._tick)

    def _render(self, t):
        self.delete("all")
        w, h = self._width, self.HEIGHT
        self.create_text(w / 2, h / 2 - 30, text="Working...", fill=TEXT_MAIN,
                          font=(FONT_FAMILY, 14))
        bar_w = w * self.BAR_W_FRAC
        bx0 = (w - bar_w) / 2
        by0 = h / 2 - self.BAR_H / 2
        self.create_rectangle(bx0, by0, bx0 + bar_w, by0 + self.BAR_H,
                               fill="#2a2a2a", outline="", tags="track")
        frac = (t % self.SWEEP_PERIOD) / self.SWEEP_PERIOD
        seg_w = bar_w * 0.28
        seg_x = bx0 + (bar_w - seg_w) * (0.5 - 0.5 * math.cos(frac * 2 * math.pi))
        self.create_rectangle(seg_x, by0, seg_x + seg_w, by0 + self.BAR_H,
                               fill=TEXT_DIM, outline="", tags="highlight")


class DonutNeuronBar(tk.Canvas):
    """Neuropil Sweep tab's idle/busy view, replacing the old static
    donut-bite splash image with a live animation, per Filip: "lets have a
    donut eating neuron animation running at the default. Let the crumbs
    accumulate. then when the loading is happening sweep the crumbs
    away." Two modes, both driven by the same 33ms tick loop:

    "idle" -- the neuron continuously loops through a 5-pose eat cycle
    (standing -> approach -> bite -> chew -> crumbs -> standing -> ...).
    Every time the cycle passes through "crumbs", a handful of small dots
    are added to an on-the-ground crumb pile that is *never* cleared just
    by looping -- it keeps growing across repeated cycles (capped at
    MAX_CRUMBS so it can't grow without bound over a long idle period).

    "busy" -- shown for the real duration of a Neuropil Sweep run (see
    KurtosisChecker._progress_start/_progress_stop). The neuron holds a
    plain "standing" pose (no eating while real work is happening) while a
    broom first sweeps once across the accumulated crumb pile, clearing
    it, then keeps sweeping back and forth continuously for as long as
    the real computation is still running -- per Filip's "the broom
    should keep sweeping until the computation there is done" (an earlier
    version parked the broom the moment the crumb pile was clear, which
    read as "finished" even while the sweep was still in progress).
    Going back to idle resumes the eat cycle from "standing" with an
    empty crumb pile.

    Same drop-in HEIGHT as PhotonNeuronBar/PlainProgressBar so swapping it
    in for the plot canvas never jumps the layout -- though since this
    widget is packed with fill=BOTH/expand=True and is the ONLY one of
    the three that also serves as the idle splash (not just the busy
    view), it tracks its own live on-screen size via <Configure> (both
    width AND height, unlike the other two bars which only ever track
    width) and centers + scales the neuron off of that real size, per
    Filip's "neuropil splash animation should be centered in the canvas
    and bigger" -- a fixed HEIGHT constant used for the vertical layout
    math was leaving the character anchored high up in a much taller
    real canvas instead of centered in it. Every character is drawn
    through the shared _render_art_image cache and resized by target
    height only (never stretched to a fixed box), so it keeps its
    original aspect ratio regardless of the widget's on-screen size --
    per Filip's "keep the aspect ratio of the drawings.\""""

    HEIGHT = 340
    NRN_SCALE = 62          # fallback only, before the first real <Configure>
    NRN_HEIGHT_FRAC = 0.56  # neuron's target height as a fraction of the
                             # widget's real on-screen height -- scales up
                             # automatically on a bigger canvas instead of
                             # staying a fixed pixel size

    # (pose name, seconds to hold it) -- cycles indefinitely while idle.
    # An extra "chew" beat repeats right before "crumbs" (same sprite,
    # just a second turn in the sequence) so chewing reads as its own
    # clear moment before the neuron moves on to cleaning its hands off
    # and spilling crumbs -- per Filip's "for the neuron that is cleaning
    # its hands and spilling crumbles lets add a version before that of
    # it chewing."
    IDLE_SEQUENCE = [
        ("standing", 0.6),
        ("approach", 0.4),
        ("bite", 0.4),
        ("chew", 0.4),
        ("chew", 0.4),
        ("crumbs", 0.5),
    ]
    CRUMBS_PER_CYCLE = (2, 4)   # random.randint range, added on entering "crumbs"
    MAX_CRUMBS = 40             # caps unbounded growth over a long idle period
    CRUMB_COLOR = "#c9a874"

    # Crumbs accumulate within this x-offset band relative to the neuron's
    # center (roughly under/around its feet); the broom sweeps a bit wider
    # than that band on both sides so every crumb is guaranteed to be
    # caught in a single left-to-right pass.
    # Given in the same pixel units as the NRN_SCALE=62 fallback above --
    # _render scales these by the real neuron's size ratio (eff_scale /
    # NRN_SCALE) so a bigger canvas gets a proportionally wider crumb
    # spread and sweep path instead of a fixed absolute pixel span.
    CRUMB_X_RANGE = (-55, 95)
    SWEEP_X_RANGE = (-90, 130)
    SWEEP_DUR = 1.1     # the initial crumb-clearing pass
    LOOP_PERIOD = 1.5   # one full back-and-forth cycle of the "still
                         # working" sweep once the crumb pile is clear

    # The broom art's bristle tip (the part that actually needs to line up
    # with the crumbs on the ground) sits well off-center in its own
    # bounding box -- (x, y) fraction of (width, height), measured from
    # the image's own center, of where the bristle tip actually is.
    # Without this, draw_broom's default center-anchor would float the
    # bristles well above the crumb line instead of sweeping through it.
    BROOM_TIP_OFFSET_FRAC = (-0.28, 0.44)

    def __init__(self, parent, **kw):
        super().__init__(parent, height=self.HEIGHT, bg=BG_DARK, highlightthickness=0, **kw)
        self._width = 400
        self._height = self.HEIGHT
        self._running = False
        self._job = None
        self._mode = "idle"          # "idle" / "busy"
        self._idle_seq_idx = 0
        self._pose_t0 = 0.0
        self._crumbs = []            # list of (x_offset, y_offset, radius)
        self._sweep_phase = None     # None / "sweeping" / "looping"
        self._sweep_t0 = 0.0
        self.bind("<Configure>", self._on_resize)

    def _on_resize(self, event):
        self._width = event.width
        self._height = event.height
        if self._running:
            self._render(time.monotonic())
        else:
            self._render(0.0)

    def start_idle(self):
        """Begin (or resume) the idle eat-cycle loop. Safe to call
        whenever this widget is shown -- if it's already running this
        just leaves the current mode/crumb pile alone rather than
        resetting anything."""
        if not self._running:
            self._running = True
            self._pose_t0 = time.monotonic()
            self._tick()
        elif self._mode == "busy":
            self._mode = "idle"
            self._idle_seq_idx = 0
            self._pose_t0 = time.monotonic()

    def set_busy(self, busy):
        """Switch between the idle eat-cycle and the busy/sweeping view.
        No-op if this widget isn't currently running at all (start_idle()
        must be called first -- mirrors how _progress_start only ever
        fires while the Neuropil Sweep tab's idle view is already up)."""
        if not self._running:
            return
        if busy and self._mode != "busy":
            self._mode = "busy"
            # if there's nothing to clear, skip straight to the continuous
            # "still working" loop instead of the pile-clearing pass --
            # either way the broom keeps moving for the rest of the run
            self._sweep_phase = "sweeping" if self._crumbs else "looping"
            self._sweep_t0 = time.monotonic()
        elif not busy and self._mode != "idle":
            self._mode = "idle"
            self._idle_seq_idx = 0
            self._pose_t0 = time.monotonic()
            self._sweep_phase = None

    def stop(self):
        self._running = False
        if self._job is not None:
            try:
                self.after_cancel(self._job)
            except Exception:
                pass
            self._job = None
        self.delete("all")

    def _spawn_crumbs(self):
        n = random.randint(*self.CRUMBS_PER_CYCLE)
        for _ in range(n):
            if len(self._crumbs) >= self.MAX_CRUMBS:
                break
            ox = random.uniform(*self.CRUMB_X_RANGE)
            oy = random.uniform(-6, 10)
            r = random.uniform(2.5, 5)
            self._crumbs.append((ox, oy, r))

    def _tick(self):
        if not self._running:
            return
        t = time.monotonic()
        if self._mode == "idle":
            self._advance_idle(t)
        else:
            self._advance_busy(t)
        try:
            self._render(t)
        except Exception:
            if not getattr(self, "_render_error_shown", False):
                self._render_error_shown = True
                traceback.print_exc()
        self._job = self.after(33, self._tick)

    def _advance_idle(self, t):
        _, dur = self.IDLE_SEQUENCE[self._idle_seq_idx]
        if t - self._pose_t0 >= dur:
            self._idle_seq_idx = (self._idle_seq_idx + 1) % len(self.IDLE_SEQUENCE)
            self._pose_t0 = t
            if self.IDLE_SEQUENCE[self._idle_seq_idx][0] == "crumbs":
                self._spawn_crumbs()

    def _advance_busy(self, t):
        if self._sweep_phase == "sweeping":
            dt = t - self._sweep_t0
            frac = min(1.0, dt / self.SWEEP_DUR)
            x0, x1 = self.SWEEP_X_RANGE
            reach = x0 + (x1 - x0) * frac
            self._crumbs = [c for c in self._crumbs if c[0] > reach]
            if frac >= 1.0:
                self._crumbs = []
                # crumb pile is clear -- keep the broom moving in a
                # continuous back-and-forth "still working" loop rather
                # than parking, for as long as the real computation is
                # still running (set_busy(False) is what actually stops
                # it). Restart the clock here so the loop's own phase
                # calc starts fresh from frac=1 (right where the clearing
                # pass just ended -- no visible jump).
                self._sweep_phase = "looping"
                self._sweep_t0 = t
        # "looping" needs no per-tick state mutation -- _render computes
        # its ping-pong position directly from elapsed time each frame.

    def _render(self, t):
        w = max(self._width, 60)
        h = max(self._height, 200)
        nrn_cx, nrn_cy = w * 0.5, h * 0.46

        eff_scale = h * self.NRN_HEIGHT_FRAC / 4.6  # draw_donut_neuron's
                                                      # target_h = scale*4.6
        size_ratio = eff_scale / self.NRN_SCALE

        pose = self.IDLE_SEQUENCE[self._idle_seq_idx][0] if self._mode == "idle" else "standing"
        nw, nh = draw_donut_neuron(self, nrn_cx, nrn_cy, scale=eff_scale,
                                    pose=pose, tag="dnrn")
        feet_y = nrn_cy + nh / 2 - 6

        self.delete("crumb")
        for ox, oy, r in self._crumbs:
            px, py = nrn_cx + ox * size_ratio, feet_y + oy * size_ratio
            self.create_oval(px - r, py - r, px + r, py + r,
                              fill=self.CRUMB_COLOR, outline="", tags="crumb")

        if self._mode == "busy":
            if self._sweep_phase == "sweeping":
                frac = min(1.0, (t - self._sweep_t0) / self.SWEEP_DUR)
            elif self._sweep_phase == "looping":
                # continuous 1 -> 0 -> 1 -> ... ping-pong across
                # SWEEP_X_RANGE, starting at frac=1 (the clearing pass's
                # end point) so the hand-off from "sweeping" is seamless
                half = self.LOOP_PERIOD / 2.0
                phase = ((t - self._sweep_t0) / half) % 2.0
                frac = abs(phase - 1.0)
            else:
                frac = 1.0
            x0, x1 = self.SWEEP_X_RANGE
            tip_x = nrn_cx + (x0 + (x1 - x0) * frac) * size_ratio
            tip_y = feet_y
            # draw_broom anchors on the *image's* own center, but the part
            # that actually needs to line up with the ground/crumbs is the
            # bristle tip, well off-center -- shift the draw center by
            # BROOM_TIP_OFFSET_FRAC (in the opposite direction) so the tip
            # itself, not the image center, lands at (tip_x, tip_y).
            broom_im = _load_art_image_outlined("broom")
            broom_h = eff_scale * 6.0
            broom_w = broom_h * (broom_im.width / broom_im.height)
            dxf, dyf = self.BROOM_TIP_OFFSET_FRAC
            broom_cx = tip_x - dxf * broom_w
            broom_cy = tip_y - dyf * broom_h
            draw_broom(self, broom_cx, broom_cy, scale=eff_scale, tag="broom")
        else:
            self.delete("broom")


class MotionCorrectionOverlay:
    """Big, centered popup shown specifically while NormCorre motion
    correction is running. Shows a progress bar driven by CaImAn's own
    log-line events (via the existing progress_cb channel) and a neuron
    drawing whose scanline/phase distortion decays to zero as those events
    accumulate, visually 'resolving' into the clean drawing -- a metaphor
    for what motion correction does to the movie.

    NOTE: CaImAn's motion_correct() is one blocking call with no true
    frame-level percentage exposed, so the bar is a step-count heuristic
    (each distinct log line nudges it forward, capped short of 100% until
    the call actually returns) rather than an exact percentage. The UI
    says so plainly rather than implying more precision than it has."""

    W = 600
    H_WHIMSY = 620
    H_PLAIN = 230   # no art_canvas -- just title/bar/pct/message
    NRN_SCALE = 95

    def __init__(self, root, plain=False):
        # plain=True is the de-whimsified variant (see whimsy_var /
        # _toggle_whimsy): same bar + message, no neuron-distortion art,
        # shorter popup since there's nothing below the message to show.
        self.plain = plain
        self.H = self.H_PLAIN if plain else self.H_WHIMSY
        self.top = tk.Toplevel(root)
        self.top.title("Motion correction running...")
        self.top.configure(bg=BG_DARK)
        try:
            self.top.resizable(False, False)
        except Exception:
            pass
        self.top.geometry(f"{self.W}x{self.H}")
        try:
            root.update_idletasks()
            rx, ry = root.winfo_rootx(), root.winfo_rooty()
            rw, rh = root.winfo_width(), root.winfo_height()
            x = rx + (rw - self.W) // 2
            y = ry + (rh - self.H) // 2
            self.top.geometry(f"{self.W}x{self.H}+{max(0, x)}+{max(0, y)}")
        except Exception:
            pass

        tk.Label(self.top, text="Registering movie with NoRMCorre...",
                 bg=BG_DARK, fg=TEXT_BRIGHT, font=(FONT_FAMILY, 13, "bold")
                 ).pack(pady=(18, 4))

        self._bar_w = self.W - 60
        self.bar_canvas = tk.Canvas(self.top, width=self._bar_w, height=18,
                                     bg=BG_DARK, highlightthickness=0)
        self.bar_canvas.pack(pady=(6, 2))

        self.pct_label = tk.Label(self.top, text="0%", bg=BG_DARK, fg=TEXT_DIM,
                                   font=(FONT_FAMILY, 10))
        self.pct_label.pack()

        self.msg_var = tk.StringVar(value="Starting NoRMCorre...")
        tk.Label(self.top, textvariable=self.msg_var, bg=BG_DARK, fg=TEXT_DIM,
                 font=(FONT_FAMILY, 9), wraplength=self.W - 40
                 ).pack(pady=(2, 8))

        self.art_canvas = None
        if not self.plain:
            self._art_w = self.W - 40
            self._art_h = self.H - 190
            self.art_canvas = tk.Canvas(self.top, width=self._art_w, height=self._art_h,
                                         bg=BG_DARK, highlightthickness=0)
            self.art_canvas.pack()

        self._progress = 0.0
        self._phase = 0.0
        self._closing = False
        self._render_bar()
        self._render_art()

    def _render_bar(self):
        c = self.bar_canvas
        c.delete("all")
        w, h = self._bar_w, 18
        c.create_rectangle(0, 2, w, h - 2, fill=BG_PANEL, outline="")
        fill_w = int(w * min(1.0, max(0.0, self._progress)))
        if fill_w > 0:
            c.create_rectangle(0, 2, fill_w, h - 2, fill=ACCENT, outline="")
        try:
            self.pct_label.config(text=f"{int(self._progress * 100)}%")
        except Exception:
            pass

    def _render_art(self):
        if self.plain or self.art_canvas is None:
            return
        cx = self._art_w / 2
        cy = self._art_h / 2
        distort = max(0.0, 1.0 - self._progress)
        try:
            draw_neuron(self.art_canvas, cx, cy, scale=self.NRN_SCALE, expr="neutral",
                        distort=distort, phase=self._phase, tag="neuron")
        except Exception:
            # A missing/broken art asset shouldn't take down the progress
            # bar itself -- that's the one part of this popup that's not
            # just decorative.
            if not getattr(self, "_render_error_shown", False):
                self._render_error_shown = True
                traceback.print_exc()

    def tick(self, msg=None):
        """Called (via the app's progress_cb channel) each time a new
        CaImAn log line / status message arrives during motion correction."""
        if self._closing:
            return
        if msg:
            try:
                self.msg_var.set(msg)
            except Exception:
                pass
        self._progress += (0.95 - self._progress) * 0.18
        self._progress = min(self._progress, 0.95)
        self._phase += 0.35
        self._render_bar()
        self._render_art()

    def close(self, success=True):
        if self._closing:
            return
        self._closing = True
        self._progress = 1.0
        self._phase = 0.0
        try:
            self.msg_var.set("Done." if success else "Stopped.")
        except Exception:
            pass
        self._render_bar()
        self._render_art()
        try:
            self.top.after(450, self.top.destroy)
        except Exception:
            pass


class MeanProjectionViewer:
    """Zoomable/pannable viewer for a registered movie's mean projection,
    shown right before the CNMF prompt so the user can eyeball how many
    pixels a cell spans before picking the 'CNMF cell radius' setting.
    Uses a real embedded matplotlib canvas with its navigation toolbar
    (zoom/pan + a live cursor-position readout at the bottom-left) --
    unlike the main app's plot canvas, the toolbar is kept here on
    purpose since that readout is the whole point of this window.

    Rather than just showing the image and trusting the user to go set
    "CNMF cell radius (px)" themselves afterward, this window asks
    directly for the cell diameter (in px) they measured and hands that
    back via on_continue -- the caller converts it to a radius and
    updates the setting in the same flow."""

    W, H = 640, 720

    def __init__(self, root, mean_img, default_diameter, on_continue):
        self.on_continue = on_continue
        self.top = tk.Toplevel(root)
        self.top.title("Mean projection — measure cell diameter")
        self.top.configure(bg=BG_DARK)
        self.top.geometry(f"{self.W}x{self.H}")
        try:
            root.update_idletasks()
            rx, ry = root.winfo_rootx(), root.winfo_rooty()
            rw, rh = root.winfo_width(), root.winfo_height()
            x = rx + (rw - self.W) // 2
            y = ry + (rh - self.H) // 2
            self.top.geometry(f"{self.W}x{self.H}+{max(0, x)}+{max(0, y)}")
        except Exception:
            pass
        self.top.protocol("WM_DELETE_WINDOW", self._continue)

        tk.Label(self.top, text="Mean projection of the registered movie",
                 bg=BG_DARK, fg=TEXT_BRIGHT, font=(FONT_FAMILY, 12, "bold")
                 ).pack(pady=(12, 2))
        tk.Label(self.top,
                 text="Zoom/pan below (magnifying-glass tool, then scroll or "
                      "drag a box) to count how many pixels a cell spans "
                      "across. Cursor position in pixels shows at the "
                      "bottom-left of the toolbar as you hover.",
                 bg=BG_DARK, fg=TEXT_DIM, font=(FONT_FAMILY, 9),
                 wraplength=self.W - 40, justify="left").pack(pady=(0, 8))

        self.fig = Figure(facecolor=BG_DARK)
        ax = self.fig.add_axes([0.09, 0.07, 0.87, 0.87])
        ax.set_facecolor(BG_DARK)
        vmin, vmax = np.percentile(mean_img, [1, 99.5])
        if vmax <= vmin:
            vmax = vmin + 1.0
        ax.imshow(mean_img, cmap="gray", vmin=vmin, vmax=vmax,
                  interpolation="nearest")
        ax.set_xlabel("x (px)", color=TEXT_MAIN, fontsize=8)
        ax.set_ylabel("y (px)", color=TEXT_MAIN, fontsize=8)
        ax.tick_params(colors=TEXT_MAIN, labelsize=7)
        for spine in ax.spines.values():
            spine.set_color(TEXT_DIM)
        self.ax = ax

        canvas_frame = tk.Frame(self.top, bg=BG_DARK)
        canvas_frame.pack(fill=tk.BOTH, expand=True, padx=10)
        self.canvas = FigureCanvasTkAgg(self.fig, master=canvas_frame)
        self.canvas.get_tk_widget().pack(fill=tk.BOTH, expand=True)
        toolbar_frame = tk.Frame(self.top, bg=BG_MID)
        toolbar_frame.pack(fill=tk.X)
        self.toolbar = NavigationToolbar2Tk(self.canvas, toolbar_frame)
        self.toolbar.update()
        self.canvas.draw()

        entry_row = tk.Frame(self.top, bg=BG_DARK)
        entry_row.pack(pady=(10, 2))
        tk.Label(entry_row, text="Cell diameter you measured (px):",
                 bg=BG_DARK, fg=TEXT_MAIN, font=(FONT_FAMILY, 10)
                 ).pack(side=tk.LEFT, padx=(0, 8))
        self.diam_var = tk.StringVar(value=str(default_diameter))
        entry_canvas, entry = _rounded_entry(entry_row, self.diam_var, width=8, justify="left")
        entry_canvas.pack(side=tk.LEFT)
        tk.Label(entry_row, text="→ sets CNMF cell radius to half of this",
                 bg=BG_DARK, fg=TEXT_DIM, font=(FONT_FAMILY, 9)
                 ).pack(side=tk.LEFT, padx=(8, 0))

        btn_row = tk.Frame(self.top, bg=BG_DARK)
        btn_row.pack(pady=10)
        _rounded_button(btn_row, "Continue →", self._continue,
                        bg=ACCENT, fg="white", font_size=10, bold=True, side=tk.TOP)

    def _continue(self):
        diameter = None
        try:
            raw = self.diam_var.get().strip()
            if raw:
                v = float(raw)
                if v > 0:
                    diameter = v
        except Exception:
            diameter = None
        try:
            self.top.destroy()
        except Exception:
            pass
        if self.on_continue:
            self.on_continue(diameter)


class CNMFMaskViewer:
    """Non-blocking sanity-check popup shown right after CNMF finishes: the
    mean projection with footprint contours overlaid so you can actually
    see the masks CNMF found, not just trust the flux histogram. Green =
    kept (survived component-quality filtering), red = filtered out. Same
    zoomable/pannable matplotlib canvas as MeanProjectionViewer -- doesn't
    block the pipeline, it's purely for visual inspection."""

    W, H = 640, 700
    THRESHOLD = 0.2  # must match footprints_to_raw_traces' own default

    def __init__(self, root, mean_img, mask_info):
        Ly, Lx = mask_info["dims"]
        self.top = tk.Toplevel(root)
        self.top.title("CNMF footprints — sanity check")
        self.top.configure(bg=BG_DARK)
        self.top.geometry(f"{self.W}x{self.H}")
        try:
            root.update_idletasks()
            rx, ry = root.winfo_rootx(), root.winfo_rooty()
            rw, rh = root.winfo_width(), root.winfo_height()
            x = rx + (rw - self.W) // 2
            y = ry + (rh - self.H) // 2
            self.top.geometry(f"{self.W}x{self.H}+{max(0, x)}+{max(0, y)}")
        except Exception:
            pass

        tk.Label(self.top, text="CNMF footprints over mean projection",
                 bg=BG_DARK, fg=TEXT_BRIGHT, font=(FONT_FAMILY, 12, "bold")
                 ).pack(pady=(12, 2))
        n_total = mask_info.get("n_total", 0)
        n_kept = mask_info.get("n_kept", 0)
        metric = mask_info.get("quality_metric") or "no quality filtering available"
        tk.Label(self.top,
                 text=f"Green = kept ({n_kept}/{n_total}) via {metric}   ·   "
                      f"Red = filtered out. Zoom/pan to check whether the "
                      f"green outlines actually look like cells before "
                      f"trusting the flux numbers.",
                 bg=BG_DARK, fg=TEXT_DIM, font=(FONT_FAMILY, 9),
                 wraplength=self.W - 40, justify="left").pack(pady=(0, 8))

        self.fig = Figure(facecolor=BG_DARK)
        ax = self.fig.add_axes([0.09, 0.07, 0.87, 0.87])
        ax.set_facecolor(BG_DARK)
        vmin, vmax = np.percentile(mean_img, [1, 99.5])
        if vmax <= vmin:
            vmax = vmin + 1.0
        ax.imshow(mean_img, cmap="gray", vmin=vmin, vmax=vmax, interpolation="nearest")

        def _overlay(A_dense, color):
            if A_dense is None:
                return
            for i in range(A_dense.shape[1]):
                comp = A_dense[:, i]
                peak = comp.max()
                if peak <= 0:
                    continue
                # A columns are flattened with x-major/y-minor order (matches
                # footprints_to_raw_traces' flat_movie convention) -- undo
                # that back into a (Ly, Lx) image for plotting.
                comp2d = comp.reshape((Lx, Ly)).T
                try:
                    ax.contour(comp2d, levels=[self.THRESHOLD * peak],
                               colors=[color], linewidths=1.0)
                except Exception:
                    pass

        _overlay(mask_info.get("A_rejected"), "#e74c3c")
        _overlay(mask_info.get("A_kept"), "#2ecc71")

        ax.set_xlabel("x (px)", color=TEXT_MAIN, fontsize=8)
        ax.set_ylabel("y (px)", color=TEXT_MAIN, fontsize=8)
        ax.tick_params(colors=TEXT_MAIN, labelsize=7)
        for spine in ax.spines.values():
            spine.set_color(TEXT_DIM)

        canvas_frame = tk.Frame(self.top, bg=BG_DARK)
        canvas_frame.pack(fill=tk.BOTH, expand=True, padx=10)
        self.canvas = FigureCanvasTkAgg(self.fig, master=canvas_frame)
        self.canvas.get_tk_widget().pack(fill=tk.BOTH, expand=True)
        toolbar_frame = tk.Frame(self.top, bg=BG_MID)
        toolbar_frame.pack(fill=tk.X)
        self.toolbar = NavigationToolbar2Tk(self.canvas, toolbar_frame)
        self.toolbar.update()
        self.canvas.draw()

        _rounded_button(self.top, "Close", self.top.destroy,
                        bg=BG_PANEL, fg=TEXT_BRIGHT, font_size=10, pady=10, side=tk.TOP)


# ═════════════════════════════════════════════════════════════════════════
# Neuropil sweep (mode 3, Suite2p only) -- sweeps alpha in
# Fcorr = rawF - alpha*Fneu and plots the mean pairwise cell-cell
# correlation (off-diagonal, excluding closely-adjacent ROI pairs) at
# each alpha. The idea: two cells with no genuine shared activity should
# have ~zero correlation once neuropil contamination is properly removed;
# systematically positive correlation across many pairs at a given alpha
# suggests under-subtraction (shared neuropil signal still bleeding into
# both traces), while systematically negative correlation suggests
# over-subtraction. See _render_neuropil_results for how the sweep curve
# is plotted.
# ═════════════════════════════════════════════════════════════════════════

def roi_pair_min_distance(ypix1, xpix1, ypix2, xpix2):
    """Exact nearest-pixel (edge-to-edge) distance between two Suite2p ROI
    masks, given as parallel pixel-coordinate arrays (stat.npy's own
    'ypix'/'xpix' per ROI). Builds a KD-tree over the larger point set and
    queries the smaller one against it, so this stays cheap even for
    sizeable ROIs."""
    pts1 = np.column_stack([ypix1, xpix1]).astype(float)
    pts2 = np.column_stack([ypix2, xpix2]).astype(float)
    if len(pts1) > len(pts2):
        pts1, pts2 = pts2, pts1
    tree = cKDTree(pts2)
    d, _ = tree.query(pts1, k=1)
    return float(np.min(d))


def build_exclusion_mask(stat, exclude_px):
    """Boolean (n, n) matrix: True where a pair of ROIs' nearest pixels
    are within `exclude_px` of each other, meaning that pair should be
    dropped from the pairwise-correlation pool the neuropil sweep
    averages over -- closely adjacent or overlapping ROIs can share
    optical bleed-through independent of the neuropil coefficient being
    tested, which would bias the sweep at every alpha the same way.

    `stat` is a sequence of Suite2p stat.npy-style dicts (only 'ypix'/
    'xpix' are used), already filtered/ordered to match the F/Fneu rows
    the caller is using.

    A cheap centroid + equivalent-radius prefilter skips the expensive
    exact nearest-pixel check for pairs that are obviously far apart: if
    the distance between two ROIs' centroids already exceeds the sum of
    their equivalent radii (sqrt(npix/pi), i.e. the radius of a circle
    with the same pixel count) plus exclude_px, no pixel pair between
    them could possibly be within exclude_px, so the exact O(npix_i *
    npix_j) check is skipped entirely for that pair. This keeps the
    function tractable for typical Suite2p cell counts (100s-1000s)."""
    n = len(stat)
    centroids = np.zeros((n, 2))
    radii = np.zeros(n)
    pix = []
    for i, s in enumerate(stat):
        yp = np.asarray(s["ypix"], dtype=float)
        xp = np.asarray(s["xpix"], dtype=float)
        centroids[i] = [yp.mean(), xp.mean()]
        radii[i] = math.sqrt(max(1, len(yp)) / math.pi)
        pix.append((yp, xp))

    excl = np.zeros((n, n), dtype=bool)
    diff = centroids[:, None, :] - centroids[None, :, :]
    cdist = np.sqrt((diff ** 2).sum(axis=2))
    radius_sum = radii[:, None] + radii[None, :]
    candidate = np.triu(cdist <= (radius_sum + exclude_px), k=1)

    for i, j in zip(*np.where(candidate)):
        yp1, xp1 = pix[i]
        yp2, xp2 = pix[j]
        if roi_pair_min_distance(yp1, xp1, yp2, xp2) <= exclude_px:
            excl[i, j] = True
            excl[j, i] = True
    return excl


def neuropil_alpha_sweep(F, Fneu, stat, alphas, exclude_px,
                          kurtosis_thresh=None, progress_cb=None):
    """Core computation for the Neuropil Sweep tab.

    For each alpha in `alphas`, computes Fcorr = F - alpha*Fneu, then the
    mean +/- SEM of the off-diagonal pairwise Pearson correlation between
    cells, excluding pairs whose ROIs are within exclude_px of each other
    (see build_exclusion_mask) -- that exclusion set is computed once, up
    front, since it doesn't depend on alpha.

    F, Fneu: (n_cells, T) arrays, already restricted to iscell==1.
    stat: sequence of per-cell Suite2p stat.npy dicts, same filtering and
          row order as F/Fneu -- only 'ypix'/'xpix' are used.
    kurtosis_thresh: if given, cells are further restricted up front to
        Pearson kurtosis(F, fisher=False) > kurtosis_thresh (computed on
        the raw, un-subtracted F -- same convention as the Kurtosis tab's
        own metric) before anything else runs.

    Returns a dict: alphas, mean_corr, sem_corr (all length len(alphas)),
    n_cells and n_pairs actually used (constant across alpha, since the
    exclusion mask and any kurtosis filtering don't depend on alpha).
    """
    F = np.asarray(F, dtype=float)
    Fneu = np.asarray(Fneu, dtype=float)
    stat = list(stat)

    if kurtosis_thresh is not None:
        kurt = stats.kurtosis(F, axis=1, fisher=False)
        keep = kurt > kurtosis_thresh
        F = F[keep]
        Fneu = Fneu[keep]
        stat = [s for s, k in zip(stat, keep) if k]

    n_cells = F.shape[0]
    if n_cells < 2:
        raise RuntimeError(
            f"Only {n_cells} cell(s) left after filtering -- need at "
            "least 2 to compute pairwise correlations. Lower the "
            "kurtosis threshold, or check the loaded data.")

    if progress_cb:
        progress_cb(f"Computing ROI exclusion mask ({n_cells} cells, "
                     f"{exclude_px:.0f}px)...")
    excl = build_exclusion_mask(stat, exclude_px)
    iu = np.triu_indices(n_cells, k=1)
    pair_keep = ~excl[iu]
    n_pairs = int(pair_keep.sum())
    if n_pairs == 0:
        raise RuntimeError(
            "Every cell pair was excluded by the exclusion distance -- "
            "try a smaller exclusion radius.")

    alphas = np.asarray(alphas, dtype=float)
    means = np.full(len(alphas), np.nan)
    sems = np.full(len(alphas), np.nan)
    for ai, alpha in enumerate(alphas):
        if progress_cb and (ai % 5 == 0 or ai == len(alphas) - 1):
            progress_cb(f"Sweeping alpha: {ai + 1}/{len(alphas)} "
                        f"(alpha={alpha:.2f})...")
        Fcorr = F - alpha * Fneu
        with np.errstate(invalid="ignore"):
            R = np.corrcoef(Fcorr)
        vals = R[iu][pair_keep]
        vals = vals[np.isfinite(vals)]
        if len(vals) == 0:
            continue
        means[ai] = float(np.mean(vals))
        sems[ai] = float(np.std(vals, ddof=1) / math.sqrt(len(vals))) if len(vals) > 1 else 0.0

    return {
        "alphas": alphas,
        "mean_corr": means,
        "sem_corr": sems,
        "n_cells": n_cells,
        "n_pairs": n_pairs,
        "exclude_px": float(exclude_px),
        "kurtosis_thresh": kurtosis_thresh,
    }


# ═════════════════════════════════════════════════════════════════════════
# Main app
# ═════════════════════════════════════════════════════════════════════════

class KurtosisChecker:
    def __init__(self, root):
        self.root = root
        self.root.title(f"Kurtosis / Gain Estimation Checker  —  build {APP_VERSION}")
        self.root.configure(bg=BG_DARK)
        self.root.geometry("1760x990")
        self._set_icon()

        # kurtosis-mode state
        self.F    = None
        self.Fneu = None
        self.data_type = None
        self.mode = tk.StringVar(value="kurtosis")   # sort-by metric within kurtosis tab

        # gain-mode state
        self.g_plane_dir = None
        self.g_ops  = None
        self.g_F    = None
        self.g_Fneu = None
        self.g_stat = None
        self.g_results = None   # lightweight dict — never holds the raw movie array

        # gain-mode state: manual-TIFF fallback (no Suite2p output found)
        self.g_raw_tiffs = None       # list of paths, or None if using Suite2p
        self.g_raw_shape = None       # (Ly, Lx, total_frames) probed at load time

        # gain-mode state: pre-motion-corrected movie loaded directly from a
        # .mat file (bypasses NormCorre entirely -- e.g. when motion
        # correction was already done in MATLAB, or when NormCorre's memmap
        # write keeps failing with "No space left on device")
        self.g_mat_movie = None       # (T, Ly, Lx) array, or None
        self.g_mat_movie_note = ""

        # big centered popup shown only while NormCorre is genuinely running
        self._motion_overlay = None

        # neuropil-sweep-mode state (mode 3 -- Suite2p only, no registered
        # movie ever needed: F.npy/Fneu.npy/stat.npy/iscell.npy are enough)
        self.np_plane_dir = None
        self.np_F    = None
        self.np_Fneu = None
        self.np_stat = None
        self.np_results = None

        self.tab_var = tk.StringVar(value="kurtosis")  # "kurtosis" | "gain" | "neuropil"

        self._build_controls()
        self._build_canvas()

    @staticmethod
    def _build_icon_image(size=512, rounded=True):
        """Generate the Kurtosis app icon — 3-trace bold style (logo2)."""
        K_X_STEM, K_X_ARM = 200, 352
        K_Y_TOP, K_Y_BOTTOM = 96, 420
        K_Y_VERTEX = 288
        K_Y_ARM_TOP, K_Y_ARM_BOTTOM = 214, 420
        ROW_COUNT = 3
        BAND_X0, BAND_X1 = 84, 428
        BAND_Y0, BAND_Y1 = 168, 352
        SAMPLES = 220
        MAX_AMP = 92
        RISE_PX, DECAY_PX = 10, 34
        MINT = (245, 247, 250)

        def k_crossings(y):
            xs = []
            if K_Y_TOP <= y <= K_Y_BOTTOM:
                xs.append(K_X_STEM)
            if K_Y_ARM_TOP <= y <= K_Y_VERTEX:
                t = (K_Y_VERTEX - y) / (K_Y_VERTEX - K_Y_ARM_TOP)
                xs.append(K_X_STEM + t * (K_X_ARM - K_X_STEM))
            if K_Y_VERTEX <= y <= K_Y_ARM_BOTTOM:
                t = (y - K_Y_VERTEX) / (K_Y_ARM_BOTTOM - K_Y_VERTEX)
                xs.append(K_X_STEM + t * (K_X_ARM - K_X_STEM))
            return xs

        step = (BAND_Y1 - BAND_Y0) / (ROW_COUNT - 1)

        SCALE = 2
        W = H = size * SCALE
        RX = min(104 * SCALE, W // 2 - 1)

        img = Image.new("RGBA", (W, H), (0, 0, 0, 0))
        if rounded:
            ImageDraw.Draw(img).rounded_rectangle([0, 0, W - 1, H - 1], radius=RX,
                                                   fill=(13, 18, 24, 255))

        for r in range(ROW_COUNT):
            row_y = BAND_Y0 + r * step
            is_last = (r == ROW_COUNT - 1)
            if is_last:
                events = [BAND_X0 + (BAND_X1 - BAND_X0) * 0.42]
            else:
                events = k_crossings(row_y)
            pts = []
            for s in range(SAMPLES):
                t = s / (SAMPLES - 1)
                x = BAND_X0 + t * (BAND_X1 - BAND_X0)
                deflect = 0.0
                for ex in events:
                    d = x - ex
                    k = max(0.0, 1 + d / RISE_PX) if d < 0 else math.exp(-d / DECAY_PX)
                    deflect += k
                deflect = min(deflect, 1.2) * MAX_AMP
                wobble = math.sin(x * 0.04 + r * 1.9) * 1.4 + math.sin(x * 0.1 + r * 0.5) * 0.7
                pts.append((x * SCALE, (row_y - deflect - wobble) * SCALE))

            alpha = 255

            # Glow pass
            glow = Image.new("RGBA", (W, H), (0, 0, 0, 0))
            ImageDraw.Draw(glow).line(pts, fill=(*MINT, int(alpha * 0.7)), width=6)
            glow = glow.filter(ImageFilter.GaussianBlur(radius=6 * SCALE / 2))
            img = Image.alpha_composite(img, glow)

            # Crisp line
            line = Image.new("RGBA", (W, H), (0, 0, 0, 0))
            ImageDraw.Draw(line).line(pts, fill=(*MINT, alpha), width=int(4.5 * SCALE))
            img = Image.alpha_composite(img, line)

        if rounded:
            # Border
            border = Image.new("RGBA", (W, H), (0, 0, 0, 0))
            ImageDraw.Draw(border).rounded_rectangle([1, 1, W - 2, H - 2], radius=RX,
                                                      outline=(255, 255, 255, 15), width=2)
            img = Image.alpha_composite(img, border)
            # Rounded-rect mask
            mask = Image.new("L", (W, H), 0)
            ImageDraw.Draw(mask).rounded_rectangle([0, 0, W - 1, H - 1], radius=RX, fill=255)
            img.putalpha(mask)

        return img.resize((size, size), Image.LANCZOS)

    def _set_icon(self):
        """Load icon.png (15-row sparse version) and set as window icon."""
        try:
            icon_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "icon.png")
            if os.path.exists(icon_path):
                toolbar_img = Image.open(icon_path).convert("RGBA")
            else:
                toolbar_img = self._build_icon_image(512)
            self._icon_img = ImageTk.PhotoImage(toolbar_img)
            self.root.wm_iconphoto(True, self._icon_img)
        except Exception:
            pass  # icon is cosmetic — never crash over it


    # ── controls ──────────────────────────────────────────────────────────

    def _load_slab_logo_photo(self, height=26):
        """Load the slab wordmark, resized to `height` px tall, as a cached
        ImageTk.PhotoImage. The source art is a plain mid-grey mark (no
        color to invert), so it's used as-is against the dark chrome."""
        cache_attr = f"_slab_logo_photo_{height}"
        cached = getattr(self, cache_attr, None)
        if cached is not None:
            return cached
        im = _load_art_image("slab_logo")
        scale = height / im.height
        w = max(1, round(im.width * scale))
        photo = ImageTk.PhotoImage(im.resize((w, height), Image.LANCZOS))
        setattr(self, cache_attr, photo)  # keep a strong ref -- Tk drops GC'd images
        return photo

    def _build_slab_logo(self, parent):
        """The slab wordmark, top-left of the window -- click opens the lab
        site in the default browser. SLAB_LAB_URL is a placeholder until
        Filip gives the real link."""
        photo = self._load_slab_logo_photo(26)
        lbl = tk.Label(parent, image=photo, bg=BG_MID, cursor="hand2", bd=0)
        lbl.pack(side=tk.LEFT, padx=(10, 14), pady=5)
        lbl.bind("<Button-1>", lambda e: webbrowser.open(SLAB_LAB_URL))
        return lbl

    def _build_controls(self):
        # ── top bar — 3-column grid so the tab toggle sits centered ────────
        self._bar = tk.Frame(self.root, bg=BG_MID, pady=6)
        self._bar.pack(fill=tk.X)
        self._bar.columnconfigure(0, weight=1)
        self._bar.columnconfigure(1, weight=0)
        self._bar.columnconfigure(2, weight=1)

        left = tk.Frame(self._bar, bg=BG_MID)
        left.grid(row=0, column=0, sticky="w")
        center = tk.Frame(self._bar, bg=BG_MID)
        center.grid(row=0, column=1)
        right = tk.Frame(self._bar, bg=BG_MID)
        right.grid(row=0, column=2, sticky="e")

        def _lbtn(parent, text, command, bg=GREY_BTN, fg=TEXT_BRIGHT, font_size=12,
                   bold=True, side=tk.LEFT, padx=6, fill=None):
            """Rounded-pill button (see module-level _rounded_button for the
            implementation, shared with standalone dialogs) — colour
            always renders on macOS. Greyscale by default now (bg=GREY_BTN);
            pass bg=GREY_BTN_ACTIVE + fg=GREY_BTN_TEXT_ACTIVE for the one
            "primary action" button in a given view. Pass fill=tk.X for
            sidebar buttons that should stretch full-width (avoids the
            winfo_children() re-pack dance, which also chokes under the
            _fake_tkinter test shim)."""
            return _rounded_button(parent, text, command, bg=bg, fg=fg,
                                    font_size=font_size, bold=bold, side=side,
                                    padx=padx, pady=5, fill=fill)
        self._lbtn = _lbtn  # reused by the gain sidebar

        self._build_slab_logo(left)

        # Kurtosis-tab chrome (Load Data / Settings toggle / Plot button /
        # Sort-by) -- the Gain Estimation tab replaced all of this with the
        # always-visible left sidebar (see _build_gain_sidebar), so these
        # are hidden whenever tab_var == "gain" (see _switch_tab).
        self._load_data_btn = _lbtn(left, "📂  Load Data", self._load_dispatch, padx=(4, 6))

        self._settings_open = False
        self._settings_btn = _lbtn(left, "⚙  Settings", self._toggle_settings, bold=False)

        # Plot lives right next to Load Data / Settings (Filip: "move the
        # plot button next to load and options") rather than pinned to the
        # far right of the bar -- kurtosis-tab only, same as the other two.
        self._action_btn = _lbtn(left, "▶  Plot", self._on_action_click,
                                  bg=GREY_BTN_ACTIVE, fg=GREY_BTN_TEXT_ACTIVE,
                                  font_size=13, side=tk.LEFT, padx=(6, 10))

        # ── center tab toggle ────────────────────────────────────────────
        self._tab_kurtosis_btn = _lbtn(center, "Kurtosis", lambda: self._switch_tab("kurtosis"),
                                        bg=GREY_BTN_ACTIVE, fg=GREY_BTN_TEXT_ACTIVE,
                                        font_size=11, padx=(0, 2))
        self._tab_gain_btn = _lbtn(center, "Gain Estimation", lambda: self._switch_tab("gain"),
                                    bg=GREY_BTN, font_size=11, padx=(2, 2))
        self._tab_neuropil_btn = _lbtn(center, "Neuropil Sweep", lambda: self._switch_tab("neuropil"),
                                        bg=GREY_BTN, font_size=11, padx=(2, 0))

        # ── whimsy toggle — present on every tab, unlike Load/Settings/
        # Plot/Sort-by which are kurtosis-only (see _switch_tab). Clicking
        # it swaps every creative busy-animation (PhotonNeuronBar, and any
        # future ones) for a plain default progress bar; clicking again
        # (now labelled "Whimsify the GUI") reverts. See whimsy_var,
        # _toggle_whimsy, _active_bar.
        self.whimsy_var = tk.BooleanVar(value=True)
        self._whimsy_btn = _lbtn(right, "De-whimsify the GUI", self._toggle_whimsy,
                                  bold=False, font_size=10, side=tk.RIGHT, padx=10)

        # "Sort by:" toggle — kurtosis-tab only
        self._sort_frame = tk.Frame(left, bg=BG_MID)
        self._sort_frame.pack(side=tk.LEFT, padx=(16, 0))
        tk.Label(self._sort_frame, text="Sort by:", bg=BG_MID, fg=TEXT_MAIN,
                 font=(FONT_FAMILY, 11)).pack(side=tk.LEFT, padx=(0, 6))
        for val, txt in (("kurtosis", "Kurtosis"), ("snr", "SNR")):
            tk.Radiobutton(self._sort_frame, text=txt, variable=self.mode, value=val,
                           bg=BG_MID, fg=TEXT_BRIGHT, selectcolor=BG_MID,
                           activebackground=BG_MID, font=(FONT_FAMILY, 11),
                           command=self._replot_if_loaded).pack(side=tk.LEFT, padx=4)

        # ── status row (its own line so it never unbalances tab centering) ─
        status_row = tk.Frame(self.root, bg=BG_MID)
        status_row.pack(fill=tk.X)
        self.status_var = tk.StringVar(value="No data loaded")
        tk.Label(status_row, textvariable=self.status_var, bg=BG_MID, fg=TEXT_DIM,
                 font=(FONT_FAMILY, 10)).pack(side=tk.LEFT, padx=14, pady=(0, 4))

        # ── settings panels (kurtosis-tab only now, hidden by default) ───
        # The old always-toggled gain-settings panel is gone -- gain-mode
        # settings live in the always-visible left sidebar instead (see
        # _build_gain_sidebar), matching Filip's "options stuff should be
        # visible before we run gain estimation... on the left column".
        self._settings_shared = tk.Frame(self.root, bg="#141414", pady=6)
        self._settings_kurtosis = tk.Frame(self.root, bg="#141414", pady=6)
        self._build_settings_shared(self._settings_shared)
        self._build_settings_kurtosis(self._settings_kurtosis)

    def _build_settings_shared(self, sf):
        def lbl(t, dim=False, parent=sf):
            tk.Label(parent, text=t, bg="#141414",
                     fg=TEXT_DIM if dim else TEXT_MAIN,
                     font=(FONT_FAMILY, 10)).pack(side=tk.LEFT, padx=(0, 2))

        def ent(var, w=6, parent=sf):
            c, e = _rounded_entry(parent, var, width=w, justify="left")
            c.pack(side=tk.LEFT)
            return e

        lbl("Frame rate fs:")
        self.fs_var = tk.DoubleVar(value=30.0)
        ent(self.fs_var, 6); lbl("Hz", dim=True)

    def _build_settings_kurtosis(self, sf):
        def lbl(t, dim=False, parent=sf):
            tk.Label(parent, text=t, bg="#141414",
                     fg=TEXT_DIM if dim else TEXT_MAIN,
                     font=(FONT_FAMILY, 10)).pack(side=tk.LEFT, padx=(0, 2))

        def ent(var, w=5, parent=sf):
            c, e = _rounded_entry(parent, var, width=w, justify="left")
            c.pack(side=tk.LEFT)
            return e

        self.do_neuropil = tk.BooleanVar(value=True)
        tk.Checkbutton(sf, text="Subtract neuropil  coeff:",
                       variable=self.do_neuropil, bg="#141414", fg=TEXT_MAIN,
                       selectcolor="#141414", activebackground="#141414",
                       activeforeground="white",
                       font=(FONT_FAMILY, 10)).pack(side=tk.LEFT, padx=(0, 0))
        self.neuropil_coeff = tk.DoubleVar(value=0.7)
        ent(self.neuropil_coeff, 5); lbl("   |", dim=True)

        lbl("Boxcar:")
        self.boxcar_sec = tk.DoubleVar(value=0.5)
        ent(self.boxcar_sec, 5); lbl("s", dim=True); lbl("   |", dim=True)

        self.do_dff = tk.BooleanVar(value=False)
        tk.Checkbutton(sf, text="   ΔF/F₀  pct:",
                       variable=self.do_dff, bg="#141414", fg=TEXT_MAIN,
                       selectcolor="#141414", activebackground="#141414",
                       activeforeground="white",
                       font=(FONT_FAMILY, 10)).pack(side=tk.LEFT)
        self.dff_pct = tk.IntVar(value=8)
        ent(self.dff_pct, 3)

    # ── Gain Estimation sidebar (always-visible left column) ────────────
    #
    # Replaces the old toggle-hidden "Settings" panel for this tab: Filip
    # wanted the options visible before running the analysis, grouped into
    # areas rather than one long wrapping row, with the Load actions as
    # explicit buttons (Suite2p folder / .mat movie) instead of one
    # auto-detecting "Load Data" button. Built in _build_canvas (needs
    # self._gain_sidebar, created there) once self.fs_var etc. already
    # exist from _build_settings_shared.

    CARD_RADIUS = 18  # corner radius for the rounded sidebar cards, in px

    def _sidebar_card(self, title=None, parent=None):
        """A rounded-corner, padded group -- the "areas" the settings/
        buttons are grouped into, echoing the boxed-panel look Filip
        pointed to (rounded per his "smoother angles" follow-up). Plain
        tk.Frame has no rounded-corner support, so the card background is
        a rounded-rectangle drawn on a backing Canvas, with the actual
        content (title + returned body frame) embedded on top via
        create_window; the canvas auto-resizes to fit the content and
        redraws the rounded rect to match on every size change.

        `parent` defaults to the Gain-tab sidebar's inner scroll frame
        (the original, only caller for a long time); pass the Neuropil
        Sweep sidebar's inner frame explicitly to build cards there
        instead."""
        if parent is None:
            parent = self._gain_sidebar_inner
        canvas = tk.Canvas(parent, bg=BG_MID, highlightthickness=0, bd=0)
        canvas.pack(fill=tk.X, padx=12, pady=(0, 10))

        content = tk.Frame(canvas, bg=CARD_BG)
        win_id = canvas.create_window(0, 0, window=content, anchor="nw")
        state = {"bg_item": None}

        def _redraw(event=None):
            w = max(content.winfo_reqwidth(), 20)
            h = max(content.winfo_reqheight(), 20)
            canvas.config(width=w, height=h)
            canvas.itemconfig(win_id, width=w)
            pts = _rounded_rect_points(1, 1, w - 1, h - 1, self.CARD_RADIUS)
            if state["bg_item"] is None:
                state["bg_item"] = canvas.create_polygon(
                    pts, smooth=True, fill=CARD_BG, outline=CARD_BORDER, width=1)
                canvas.tag_lower(state["bg_item"])  # keep it behind the content window
            else:
                canvas.coords(state["bg_item"], *pts)

        content.bind("<Configure>", _redraw)

        if title:
            tk.Label(content, text=title, bg=CARD_BG, fg=TEXT_DIM,
                     font=(FONT_FAMILY, 9, "bold")).pack(anchor="w", padx=10, pady=(8, 2))
        body = tk.Frame(content, bg=CARD_BG)
        body.pack(fill=tk.X, padx=10, pady=(2, 10))
        return body

    def _make_tooltip(self, icon, text):
        """Attach a click-to-toggle info popup to a single "?" icon -- a
        small floating borderless window with `text`, shown just below
        the icon on click and dismissed by clicking the icon (or the
        popup itself) again. Previously this opened on hover over an
        entire parameter row (label/entry/suffix/icon all wired in),
        which Filip found intrusive ("the information brackets are a bit
        intrusive... only appear after the ? is clicked on") -- now it's
        click-only and scoped to just the icon, so typing in a nearby
        entry or reading a label never triggers it."""
        state = {"win": None}

        def _close():
            if state["win"] is not None:
                state["win"].destroy()
                state["win"] = None

        def _toggle(event=None):
            if state["win"] is not None:
                _close()
                return
            win = tk.Toplevel(icon)
            win.wm_overrideredirect(True)
            try:
                win.wm_attributes("-topmost", True)
            except Exception:
                pass
            x = icon.winfo_rootx() - 6
            y = icon.winfo_rooty() + icon.winfo_height() + 4
            win.wm_geometry(f"+{x}+{y}")
            lbl = tk.Label(win, text=text, bg="#1c1c1c", fg=TEXT_BRIGHT,
                            font=(FONT_FAMILY, 9), justify="left", wraplength=260,
                            padx=8, pady=6, bd=1, relief=tk.SOLID, cursor="hand2")
            lbl.pack()
            lbl.bind("<Button-1>", lambda e: _close())
            state["win"] = win

        icon.bind("<Button-1>", _toggle)
        return state

    def _help_icon(self, parent, help_text=None):
        """A small "?" glyph -- click it to toggle a floating info popup
        open/closed (see _make_tooltip). Previously the whole parameter
        row opened this on hover; per Filip's "only appear after the ? is
        clicked on" it's now click-only and scoped to just this icon."""
        icon = tk.Label(parent, text="?", bg=CARD_BG, fg=TEXT_DIM,
                         font=(FONT_FAMILY, 6, "bold"), width=1,
                         relief=tk.RIDGE, bd=1, cursor="hand2")
        icon.pack(side=tk.LEFT, padx=(3, 0))
        if help_text:
            self._make_tooltip(icon, help_text)
        return icon

    def _sidebar_row(self, parent, label_text, var, width=7, suffix=None, help_text=None):
        row = tk.Frame(parent, bg=CARD_BG)
        row.pack(fill=tk.X, pady=2)
        lbl = tk.Label(row, text=label_text, bg=CARD_BG, fg=TEXT_MAIN,
                        font=(FONT_FAMILY, 10))
        lbl.pack(side=tk.LEFT)
        if help_text:
            self._help_icon(row, help_text)
        if suffix:
            suf = tk.Label(row, text=suffix, bg=CARD_BG, fg=TEXT_DIM,
                            font=(FONT_FAMILY, 9))
            suf.pack(side=tk.RIGHT)
        entry_canvas, entry = _rounded_entry(row, var, width=width, justify="right")
        entry_canvas.pack(side=tk.RIGHT, padx=(0, 6))
        return row

    def _sidebar_check(self, parent, text, var, help_text=None):
        row = tk.Frame(parent, bg=CARD_BG)
        row.pack(fill=tk.X, pady=3, anchor="w")
        chk = tk.Checkbutton(row, text=text, variable=var, bg=CARD_BG, fg=TEXT_MAIN,
                       selectcolor=CARD_BG, activebackground=CARD_BG,
                       activeforeground=TEXT_BRIGHT, font=(FONT_FAMILY, 10),
                       anchor="w", justify="left", wraplength=190)
        chk.pack(side=tk.LEFT, fill=tk.X)
        if help_text:
            self._help_icon(row, help_text)

    def _build_gain_sidebar(self):
        # Tk variables the old row-based _build_settings_gain used to create
        # inline as it built each widget -- now created up front since the
        # sidebar's cards are built in a different order (Load first).
        self.enf_var = tk.DoubleVar(value=1.2)
        self.fit_lo_var = tk.DoubleVar(value=0.0)
        self.fit_hi_var = tk.DoubleVar(value=50.0)
        self.spatial_bin_var = tk.IntVar(value=1)
        # 4px matches the Lees et al. 2025 reference script's own default
        # (see PTC method notes in README) -- a contaminated edge left
        # uncropped can visibly bias the fitted slope, so cropping a small
        # margin by default is the safer out-of-the-box choice than 0.
        self.margin_var = tk.IntVar(value=4)
        self.max_frames_var = tk.IntVar(value=2000)
        self.frame_start_var = tk.StringVar(value="")
        self.cnmf_gsig_var = tk.IntVar(value=6)
        self.exclude_roi_var = tk.BooleanVar(value=False)
        # Default ON + 30th pctile: convert each cell's own baseline F0
        # (its resting/least-active trace value) to photons/s, rather than
        # the plain trace mean, which activity transients pull upward --
        # see photon_flux_per_cell's docstring. On by default per Filip's
        # "these numbers are huge" feedback.
        self.subtract_baseline_var = tk.BooleanVar(value=True)
        self.flux_baseline_pct_var = tk.DoubleVar(value=30.0)
        self.pw_rigid_var = tk.BooleanVar(value=False)
        self.skip_mc_var = tk.BooleanVar(value=False)
        self.save_mc_var = tk.BooleanVar(value=True)
        # Blank = CaImAn's own default scratch location; see
        # run_normcorre's docstring and _scratch_dir_or_none.
        self.scratch_dir_var = tk.StringVar(value="")

        # ── Load ──────────────────────────────────────────────────────
        load_body = self._sidebar_card("LOAD")
        seg = tk.Frame(load_body, bg=CARD_BG)
        seg.pack(fill=tk.X)
        self._lbtn(seg, "📁  Suite2p Folder", self._load_gain_folder,
                   side=tk.TOP, padx=0, fill=tk.X)
        self._lbtn(seg, "🎬  Load .mat Movie", self._load_gain_mat_movie,
                   side=tk.TOP, padx=0, fill=tk.X)

        # ── Frame rate + fit parameters ──────────────────────────────
        fit_body = self._sidebar_card("FIT PARAMETERS")
        self._sidebar_row(fit_body, "Frame rate fs", self.fs_var, suffix="Hz",
                           help_text="Acquisition frame rate in Hz. Used to convert "
                                     "photons/frame into photons/cell/s for the flux "
                                     "panel, and read automatically from ops.npy/the "
                                     ".mat file when available.")
        self._sidebar_row(fit_body, "ENF", self.enf_var,
                           help_text="Excess noise factor for a GaAsP PMT (default "
                                     "1.2). gain_true = fitted slope / ENF². Only "
                                     "matters for photon-detector setups with excess "
                                     "multiplicative noise; leave at 1.0 for a plain "
                                     "shot-noise-limited camera.")
        fitrange_help = ("Which intensity-percentile bins go into the shot-noise "
                          "linear fit (0-50 by default, matching the Lees et al. "
                          "2025 reference protocol). Raise the high end toward 98 "
                          "to use almost the full intensity range instead -- a PMT "
                          "has no strong inherent need for a read-noise floor "
                          "exclusion the way a camera sensor does.")
        fitrange_row = tk.Frame(fit_body, bg=CARD_BG)
        fitrange_row.pack(fill=tk.X, pady=2)
        fitrange_lbl = tk.Label(fitrange_row, text="Fit range (% of mean)", bg=CARD_BG,
                                 fg=TEXT_MAIN, font=(FONT_FAMILY, 10))
        fitrange_lbl.pack(side=tk.LEFT)
        self._help_icon(fitrange_row, fitrange_help)
        fitrange_entries = tk.Frame(fit_body, bg=CARD_BG)
        fitrange_entries.pack(fill=tk.X, pady=(0, 2))
        fitrange_lo_canvas, fitrange_lo = _rounded_entry(fitrange_entries, self.fit_lo_var,
                                                           width=5, justify="center")
        fitrange_lo_canvas.pack(side=tk.LEFT, expand=True, fill=tk.X, padx=(0, 3))
        fitrange_dash = tk.Label(fitrange_entries, text="–", bg=CARD_BG, fg=TEXT_DIM)
        fitrange_dash.pack(side=tk.LEFT)
        fitrange_hi_canvas, fitrange_hi = _rounded_entry(fitrange_entries, self.fit_hi_var,
                                                           width=5, justify="center")
        fitrange_hi_canvas.pack(side=tk.LEFT, expand=True, fill=tk.X, padx=(3, 0))
        self._sidebar_row(fit_body, "Spatial bin", self.spatial_bin_var, suffix="px",
                           help_text="Superpixel binning applied before the PTC fit "
                                     "(pixels are summed, not averaged, so the "
                                     "recovered gain estimate is invariant to this "
                                     "setting). Raising it trades spatial resolution "
                                     "for fewer, less noisy bins. 1 = no binning.")
        self._sidebar_row(fit_body, "Edge margin", self.margin_var, suffix="px",
                           help_text="Crops this many pixels off every edge of each "
                                     "frame before computing anything, to exclude "
                                     "blanking/vignetting artifacts near the frame "
                                     "border that resonant-scan systems often have. "
                                     "A contaminated edge left uncropped can visibly "
                                     "bias the fitted slope. Default 4px matches the "
                                     "reference protocol; set to 0 to disable, or "
                                     "raise it if your system's blanking band is "
                                     "wider.")
        # Fit range / ENF / fs only feed the linear regression over bins
        # that a full run has already computed -- so once Run Analysis has
        # happened once, tweaking these and clicking here re-fits instantly
        # without redoing motion correction or CNMF. (Spatial bin / edge
        # margin above bake into the bins themselves, so those still need a
        # full Run Analysis to take effect.)
        self._lbtn(fit_body, "↻  Re-fit", self._refit_gain, bg=GREY_BTN,
                   font_size=10, bold=False, side=tk.TOP, padx=0, fill=tk.X)

        # ── Frame window ──────────────────────────────────────────────
        win_body = self._sidebar_card("FRAME WINDOW")
        self._sidebar_row(win_body, "Max frames", self.max_frames_var,
                           help_text="Size of the contiguous frame window used for "
                                     "the PTC estimate. The window must be "
                                     "contiguous (not evenly-spaced samples) because "
                                     "the frame-differencing noise estimate needs "
                                     "genuinely adjacent frames. Larger = more "
                                     "stable estimate, more memory/time.")
        self._sidebar_row(win_body, "Start frame", self.frame_start_var, suffix="blank=auto",
                           help_text="Explicit starting frame index for the analysis "
                                     "window. Leave blank to auto-center the window "
                                     "on the recording (the default). Set it to skip "
                                     "a noisy start-of-session period, or to target "
                                     "a specific known-bad stretch. Invalid/"
                                     "out-of-range values fall back to auto.")

        # ── CNMF ──────────────────────────────────────────────────────
        cnmf_body = self._sidebar_card("CNMF")
        self._sidebar_row(cnmf_body, "Cell radius", self.cnmf_gsig_var, suffix="px",
                           help_text="Expected cell radius (gSig) passed to CaImAn "
                                     "CNMF, used only when CNMF is offered to fill "
                                     "an empty photon-flux panel (no Suite2p F.npy "
                                     "available). The mean-projection viewer shown "
                                     "right before that prompt lets you measure a "
                                     "cell's diameter directly and auto-fills this.")
        self._sidebar_check(cnmf_body, "Exclude cell ROIs", self.exclude_roi_var,
                             help_text="Restrict the PTC fit to background/non-cell "
                                       "pixels only, using Suite2p's stat.npy masks. "
                                       "Useful if cell bodies show extra variance "
                                       "(e.g. residual motion) that biases the gain "
                                       "estimate away from pure background shot "
                                       "noise.")

        # ── Photon flux ──────────────────────────────────────────────
        flux_body = self._sidebar_card("PHOTON FLUX")
        self._sidebar_check(flux_body, "Use baseline (F0) for flux", self.subtract_baseline_var,
                             help_text="How each cell's raw trace converts to a "
                                       "photons/cell/s number. Unchecked: the "
                                       "per-frame MEAN of the whole trace converts "
                                       "directly, which gets pulled up by activity "
                                       "transients. Checked (default): each cell's own "
                                       "baseline F0 -- see 'Baseline pctile' below -- IS "
                                       "the value that gets converted, giving a stable "
                                       "resting-state photon-flux estimate per cell "
                                       "instead of an activity-inflated mean. F itself "
                                       "is never modified either way. Doesn't affect "
                                       "the gain fit -- only the flux panel.")
        self._sidebar_row(flux_body, "Baseline pctile", self.flux_baseline_pct_var, suffix="%",
                           help_text="Which percentile of each cell's own raw trace "
                                     "counts as its baseline (F0) and gets converted "
                                     "to photons/s when 'Use baseline (F0) for flux' "
                                     "is checked. Lower = closer to the trace's true "
                                     "minimum (more conservative, less activity "
                                     "contamination); higher = closer to the median. "
                                     "30 is a reasonable default for calcium traces "
                                     "that spend most of their time near baseline.")
        # Same story as ENF/fit range above: this only affects the flux
        # panel's conversion of already-cached F_for_flux, not the PTC fit
        # itself, so Re-fit picks it up instantly too.

        # ── Motion correction ────────────────────────────────────────
        mc_body = self._sidebar_card("MOTION CORRECTION")
        self._sidebar_check(mc_body, "Piecewise-rigid (NormCorre)", self.pw_rigid_var,
                             help_text="Use non-rigid (piecewise-rigid) motion "
                                       "correction instead of rigid. Only applies "
                                       "when NormCorre actually needs to run (no "
                                       "usable reg_tif export found). Slower, but "
                                       "corrects local/non-uniform drift that a "
                                       "single rigid shift can't.")
        self._sidebar_check(mc_body, "Skip motion correction\n(manual TIFF already registered)", self.skip_mc_var,
                             help_text="Manual-TIFF mode only (no Suite2p ops.npy "
                                       "found at all). Check this if the TIFF you "
                                       "point the tool at is already motion-"
                                       "corrected, to skip an unnecessary NormCorre "
                                       "pass.")
        self._sidebar_check(mc_body, "Save motion-corrected TIFF\n(reg_tif)", self.save_mc_var,
                             help_text="After NormCorre runs, save the result as "
                                       "reg_tif/ chunks next to the source data, "
                                       "matching Suite2p's own naming convention. "
                                       "Next time you load the same folder the tool "
                                       "finds this export and skips NormCorre "
                                       "entirely -- it only ever needs to run once "
                                       "per recording.")

        scratch_row = tk.Frame(mc_body, bg=CARD_BG)
        scratch_row.pack(fill=tk.X, pady=(6, 2), anchor="w")
        tk.Label(scratch_row, text="Scratch folder", bg=CARD_BG, fg=TEXT_MAIN,
                 font=(FONT_FAMILY, 10)).pack(side=tk.LEFT)
        self._help_icon(scratch_row,
                         "Where CaImAn writes its temporary motion-correction "
                         "memmap files -- these can be as large as (or larger "
                         "than) the raw movie itself. Left blank, CaImAn uses "
                         "its own default location (usually ~/caiman_data/"
                         "temp), which is exactly what runs out of room and "
                         "produces \"OSError: No space left on device\" "
                         "during NormCorre. Point this at a folder on a drive "
                         "with plenty of free space instead -- it's created "
                         "automatically if it doesn't exist yet.")
        # Plain text= updates (not textvariable=) so a blank scratch_dir_var
        # can show an explicit "(default location)" placeholder instead of
        # an empty-looking label.
        self._scratch_dir_label = tk.Label(
            mc_body, text="(default location)", bg=CARD_BG, fg=TEXT_DIM,
            font=(FONT_FAMILY, 8), wraplength=210, justify="left", anchor="w")
        self.scratch_dir_var.trace_add(
            "write", lambda *a: self._scratch_dir_label.config(
                text=self.scratch_dir_var.get() or "(default location)"))
        self._scratch_dir_label.pack(fill=tk.X, anchor="w", pady=(0, 4))
        scratch_btns = tk.Frame(mc_body, bg=CARD_BG)
        scratch_btns.pack(fill=tk.X, pady=(0, 2))
        self._lbtn(scratch_btns, "📁 Choose…", self._choose_scratch_dir,
                   bg=GREY_BTN, font_size=9, bold=False, side=tk.LEFT, padx=(0, 4))
        self._lbtn(scratch_btns, "Reset", self._clear_scratch_dir,
                   bg=GREY_BTN, font_size=9, bold=False, side=tk.LEFT, padx=0)

        # ── Export ────────────────────────────────────────────────────
        export_body = self._sidebar_card("EXPORT")
        self._lbtn(export_body, "💾  Export Results…", self._export_gain_results,
                   bg=GREY_BTN, font_size=10, bold=False, side=tk.TOP, padx=0, fill=tk.X)
        tk.Label(export_body, text="Saves this run's gain/flux numbers to a "
                 "CSV table that accumulates across runs, so different "
                 "conditions can be compared and plotted outside the app.\n"
                 "Needs Run Analysis to have finished at least once.",
                 bg=CARD_BG, fg=TEXT_DIM, font=(FONT_FAMILY, 8),
                 wraplength=210, justify="left").pack(anchor="w", pady=(6, 0))

        # PTC method reference -- the app's gain/flux math is checked
        # against this protocol (see README's "PTC method notes"); Filip
        # wanted the citation itself linked directly under Export, not
        # just documented separately.
        tk.Label(export_body, text=PTC_REFERENCE_CITATION,
                 bg=CARD_BG, fg=TEXT_DIM, font=(FONT_FAMILY, 8),
                 wraplength=210, justify="left").pack(anchor="w", pady=(8, 0))
        link = tk.Label(export_body, text=PTC_REFERENCE_URL,
                         bg=CARD_BG, fg=TEXT_MAIN, cursor="hand2",
                         font=(FONT_FAMILY, 8, "underline"),
                         wraplength=210, justify="left")
        link.pack(anchor="w", pady=(2, 0))
        link.bind("<Button-1>", lambda e: webbrowser.open(PTC_REFERENCE_URL))

        # ── Run Analysis (primary action, bottom of the sidebar) ────────
        # Was silently getting clipped off the bottom of the window before
        # the sidebar became scrollable -- there was no way to reach it.
        run_frame = tk.Frame(self._gain_sidebar_inner, bg=BG_MID)
        run_frame.pack(fill=tk.X, padx=12, pady=(4, 14))
        self._lbtn(run_frame, "▶  Run Analysis", self.run_gain_analysis,
                   bg=GREY_BTN_ACTIVE, fg=GREY_BTN_TEXT_ACTIVE, font_size=12,
                   side=tk.TOP, padx=0, fill=tk.X)

    def _choose_scratch_dir(self):
        """MOTION CORRECTION card's "Scratch folder" -- lets NormCorre's
        memmap scratch files go to a different drive than CaImAn's own
        default, to fix "No space left on device" errors during
        NormCorre. See run_normcorre's docstring for the mechanism."""
        d = filedialog.askdirectory(title="Select a scratch/temp folder for NormCorre")
        if d:
            self.scratch_dir_var.set(d)

    def _clear_scratch_dir(self):
        self.scratch_dir_var.set("")

    def _build_neuropil_sidebar(self):
        """Third tab: sweeps the neuropil-subtraction coefficient alpha in
        Fcorr = rawF - alpha*Fneu and plots the mean pairwise cell-cell
        correlation at each alpha (see neuropil_alpha_sweep). Suite2p
        only -- there's no registered-movie fallback here since F.npy/
        Fneu.npy/stat.npy/iscell.npy are all this needs."""
        ip = self._neuropil_sidebar_inner

        self.np_alpha_lo_var = tk.DoubleVar(value=0.0)
        self.np_alpha_hi_var = tk.DoubleVar(value=2.0)
        self.np_alpha_step_var = tk.DoubleVar(value=0.05)
        # 4px: closely-adjacent/overlapping ROIs can share optical
        # bleed-through independent of alpha, which would bias the sweep
        # at every alpha the same way -- see build_exclusion_mask.
        self.np_exclude_px_var = tk.IntVar(value=4)
        self.np_kurt_filter_var = tk.BooleanVar(value=False)
        self.np_kurt_thresh_var = tk.DoubleVar(value=5.0)

        # ── Load ──────────────────────────────────────────────────────
        load_body = self._sidebar_card("LOAD", parent=ip)
        self._lbtn(load_body, "📁  Suite2p Folder", self._load_neuropil_folder,
                   side=tk.TOP, padx=0, fill=tk.X)
        tk.Label(load_body, text="Suite2p only — needs F.npy, Fneu.npy, "
                 "stat.npy, and iscell.npy in the same folder.",
                 bg=CARD_BG, fg=TEXT_DIM, font=(FONT_FAMILY, 8),
                 wraplength=210, justify="left").pack(anchor="w", pady=(6, 0))

        # ── Alpha sweep ──────────────────────────────────────────────
        sweep_body = self._sidebar_card("ALPHA SWEEP", parent=ip)
        alpha_help = ("Sweeps the neuropil-subtraction coefficient alpha "
                      "in Fcorr = rawF - alpha*Fneu across this range, in "
                      "steps of 'Step' below, and plots the mean pairwise "
                      "cell-cell correlation at each alpha.")
        alpha_row = tk.Frame(sweep_body, bg=CARD_BG)
        alpha_row.pack(fill=tk.X, pady=2)
        alpha_lbl = tk.Label(alpha_row, text="Alpha range", bg=CARD_BG,
                              fg=TEXT_MAIN, font=(FONT_FAMILY, 10))
        alpha_lbl.pack(side=tk.LEFT)
        self._help_icon(alpha_row, alpha_help)
        alpha_entries = tk.Frame(sweep_body, bg=CARD_BG)
        alpha_entries.pack(fill=tk.X, pady=(0, 2))
        alpha_lo_canvas, alpha_lo = _rounded_entry(alpha_entries, self.np_alpha_lo_var,
                                                     width=5, justify="center")
        alpha_lo_canvas.pack(side=tk.LEFT, expand=True, fill=tk.X, padx=(0, 3))
        tk.Label(alpha_entries, text="–", bg=CARD_BG, fg=TEXT_DIM).pack(side=tk.LEFT)
        alpha_hi_canvas, alpha_hi = _rounded_entry(alpha_entries, self.np_alpha_hi_var,
                                                     width=5, justify="center")
        alpha_hi_canvas.pack(side=tk.LEFT, expand=True, fill=tk.X, padx=(3, 0))
        self._sidebar_row(sweep_body, "Step", self.np_alpha_step_var,
                           help_text="Alpha increment for the sweep -- "
                                     "smaller = finer resolution, slower "
                                     "to compute (one full pairwise-"
                                     "correlation matrix per step).")
        self._sidebar_row(sweep_body, "Exclusion", self.np_exclude_px_var, suffix="px",
                           help_text="Cell pairs whose ROI masks come "
                                     "within this many pixels of each "
                                     "other (nearest-pixel, edge-to-edge, "
                                     "from Suite2p's own stat.npy masks) "
                                     "are dropped from the pairwise-"
                                     "correlation average. Closely "
                                     "adjacent/overlapping ROIs can share "
                                     "optical bleed-through independent "
                                     "of alpha, which would bias the "
                                     "sweep the same way at every step.")

        # ── Cell filter ──────────────────────────────────────────────
        filt_body = self._sidebar_card("CELL FILTER", parent=ip)
        self._sidebar_check(filt_body, "Filter by kurtosis", self.np_kurt_filter_var,
                             help_text="Restrict the sweep to cells with "
                                       "Pearson kurtosis (fisher=False, "
                                       "normal≈3) above the threshold "
                                       "below, computed on the raw trace "
                                       "-- same convention as the "
                                       "Kurtosis tab. Keeps the sweep "
                                       "focused on clearly active/spiky "
                                       "cells rather than flat or noise-"
                                       "dominated ROIs.")
        self._sidebar_row(filt_body, "Kurtosis >", self.np_kurt_thresh_var,
                           help_text="Threshold applied only when "
                                     "'Filter by kurtosis' above is "
                                     "checked.")

        # ── Run Analysis (primary action, bottom of the sidebar) ────────
        run_frame = tk.Frame(ip, bg=BG_MID)
        run_frame.pack(fill=tk.X, padx=12, pady=(4, 14))
        self._lbtn(run_frame, "▶  Run Analysis", self.run_neuropil_analysis,
                   bg=GREY_BTN_ACTIVE, fg=GREY_BTN_TEXT_ACTIVE, font_size=12,
                   side=tk.TOP, padx=0, fill=tk.X)

    def _toggle_settings(self):
        """Kurtosis-tab only now -- the Gain tab's settings are always
        visible in the left sidebar, no toggle needed there."""
        if self._settings_open:
            self._settings_shared.pack_forget()
            self._settings_kurtosis.pack_forget()
            self._settings_btn.config(text="⚙  Settings")
            self._settings_open = False
        else:
            self._settings_shared.pack(fill=tk.X, after=self._bar)
            self._settings_kurtosis.pack(fill=tk.X, after=self._settings_shared)
            self._settings_btn.config(text="⚙  Settings ▲")
            self._settings_open = True

    # ── tab switching ────────────────────────────────────────────────────

    def _show_neuropil_idle(self):
        """Show the Neuropil Sweep tab's idle view -- only ever called
        while np_results is None. Whimsy on: the donut-eating-neuron
        animation (DonutNeuronBar), continuously looping, crumbs
        accumulating -- per Filip: "lets have a donut eating neuron
        animation running at the default." Whimsy off: the old plain
        text-only splash (_draw_neuropil_splash with no image, since it's
        whimsy-aware itself)."""
        if self.whimsy_var.get():
            self.canvas.get_tk_widget().pack_forget()
            self.donut_bar.pack(fill=tk.BOTH, expand=True)
            self.donut_bar.start_idle()
            self._donut_idle_active = True
        else:
            self._hide_donut_bar()
            self.canvas.get_tk_widget().pack(fill=tk.BOTH, expand=True)
            self._draw_neuropil_splash()

    def _hide_donut_bar(self):
        """Tear down the donut-eating-neuron idle view and reveal the plot
        canvas in its place -- a no-op unless _show_neuropil_idle actually
        put it up (tracked via _donut_idle_active rather than querying Tk
        directly, since PhotonNeuronBar/PlainProgressBar's own pack state
        is managed independently by _progress_start/_progress_stop and
        shouldn't be disturbed by this)."""
        if getattr(self, "_donut_idle_active", False):
            self.donut_bar.stop()
            self.donut_bar.pack_forget()
            self._donut_idle_active = False
            self.canvas.get_tk_widget().pack(fill=tk.BOTH, expand=True)

    def _switch_tab(self, new_tab):
        if new_tab == self.tab_var.get():
            return
        self.tab_var.set(new_tab)

        self._tab_kurtosis_btn.config(
            bg=GREY_BTN_ACTIVE if new_tab == "kurtosis" else GREY_BTN,
            fg=GREY_BTN_TEXT_ACTIVE if new_tab == "kurtosis" else TEXT_BRIGHT)
        self._tab_gain_btn.config(
            bg=GREY_BTN_ACTIVE if new_tab == "gain" else GREY_BTN,
            fg=GREY_BTN_TEXT_ACTIVE if new_tab == "gain" else TEXT_BRIGHT)
        self._tab_neuropil_btn.config(
            bg=GREY_BTN_ACTIVE if new_tab == "neuropil" else GREY_BTN,
            fg=GREY_BTN_TEXT_ACTIVE if new_tab == "neuropil" else TEXT_BRIGHT)

        if new_tab == "kurtosis":
            self._action_btn.config(text="▶  Plot")
            # Pack order (all side=LEFT, inside the same `left` frame)
            # fixes visual order: Load Data, Settings, Plot, then Sort by.
            self._load_data_btn.pack(side=tk.LEFT, padx=(4, 6), pady=5)
            self._settings_btn.pack(side=tk.LEFT, padx=6, pady=5)
            self._action_btn.pack(side=tk.LEFT, padx=(6, 10), pady=5)
            self._sort_frame.pack(side=tk.LEFT, padx=(16, 0))
            self._gain_sidebar.pack_forget()
            self._neuropil_sidebar.pack_forget()
        else:
            self._sort_frame.pack_forget()
            # Gain / Neuropil Sweep tabs have no top-bar Load/Settings/
            # Plot -- all of that lives in each tab's own always-visible
            # sidebar instead.
            self._action_btn.pack_forget()
            self._load_data_btn.pack_forget()
            self._settings_btn.pack_forget()
            if self._settings_open:
                self._toggle_settings()  # close the kurtosis panel if it was open
            if new_tab == "gain":
                self._neuropil_sidebar.pack_forget()
                self._gain_sidebar.pack(side=tk.LEFT, fill=tk.Y, before=self._main_area)
            else:  # "neuropil"
                self._gain_sidebar.pack_forget()
                self._neuropil_sidebar.pack(side=tk.LEFT, fill=tk.Y, before=self._main_area)

        if new_tab == "kurtosis":
            self._hide_donut_bar()
            if self.F is not None:
                self.plot()
            else:
                self._draw_splash()
            self.status_var.set(
                self.status_var.get() if self.F is not None else "No data loaded — Kurtosis mode")
        elif new_tab == "gain":
            self._hide_donut_bar()
            if self.g_results is not None:
                self._render_gain_results()
            else:
                self._draw_gain_splash()
            if self.g_plane_dir is None and not self.g_raw_tiffs and self.g_mat_movie is None:
                self.status_var.set("No data loaded — Gain Estimation mode "
                                     "(registered movie is only loaded when you click Run Analysis)")
        else:  # "neuropil"
            if self.np_results is not None:
                self._hide_donut_bar()
                self._render_neuropil_results()
            else:
                self._show_neuropil_idle()
            if self.np_plane_dir is None:
                self.status_var.set("No data loaded — Neuropil Sweep mode (Suite2p only)")

    def _load_dispatch(self):
        if self.tab_var.get() == "kurtosis":
            self._load_folder()
        else:
            self._load_gain_folder()

    def _on_action_click(self):
        if self.tab_var.get() == "kurtosis":
            self.plot()
        else:
            self.run_gain_analysis()

    def _replot_if_loaded(self):
        if self.F is not None:
            self.plot()

    # ── kurtosis-mode loader (unchanged logic) ──────────────────────────

    def _load_folder(self):
        """Scan folder; prefer .npy (fastest), fall back to .mat."""
        folder = filedialog.askdirectory(
            title="Navigate to the folder containing your .mat or .npy file")
        if not folder:
            return

        # Search order: root, then plane0/1/2/combined sub-dirs
        search = [folder] + [os.path.join(folder, d)
                              for d in ("plane0", "plane1", "plane2", "combined")]

        # Priority 1: Suite2p F.npy (fastest — raw numpy)
        for d in search:
            f_path = os.path.join(d, "F.npy")
            if os.path.exists(f_path):
                fneu_p = os.path.join(d, "Fneu.npy")
                ops_p  = os.path.join(d, "ops.npy")
                try:
                    F_raw    = np.load(f_path).astype(float)
                    Fneu_raw = np.load(fneu_p).astype(float) if os.path.exists(fneu_p) else None
                    if os.path.exists(ops_p):
                        ops = np.load(ops_p, allow_pickle=True).item()
                        fs  = self._try_fs(ops)
                        if fs: self.fs_var.set(round(fs, 4))
                    # Filter by iscell if available
                    iscell_p = os.path.join(d, "iscell.npy")
                    cell_mask = None
                    if os.path.exists(iscell_p):
                        iscell = np.load(iscell_p)
                        cell_mask = iscell[:, 0].astype(bool)
                        F_raw = F_raw[cell_mask]
                        if Fneu_raw is not None:
                            Fneu_raw = Fneu_raw[cell_mask]
                    self.F    = F_raw
                    self.Fneu = Fneu_raw
                except Exception as e:
                    messagebox.showerror("Error", str(e)); return
                self.data_type = "suite2p"
                n, t = self.F.shape
                note = " + Fneu" if self.Fneu is not None else ""
                cell_note = f"  [iscell: {n}]" if cell_mask is not None else ""
                self.status_var.set(
                    f"Suite2p: {n} cells × {t} frames{note}{cell_note}  ·  fs={self.fs_var.get()} Hz"
                    f"  [{os.path.relpath(f_path, folder)}]")
                self.plot(); return

        # Priority 2: any .npy at root level
        npy_files = [f for f in os.listdir(folder) if f.endswith(".npy")]
        if npy_files:
            path = os.path.join(folder, npy_files[0])
            try:
                arr = np.load(path, allow_pickle=False).astype(float)
            except Exception as e:
                messagebox.showerror("Error", str(e)); return
            arr = self._orient(arr, npy_files[0])
            if arr is None: return
            self.F = arr; self.Fneu = None; self.data_type = "npy"
            self.status_var.set(
                f"NumPy: {arr.shape[0]} cells × {arr.shape[1]} frames  ·  {npy_files[0]}")
            self.plot(); return

        # Priority 3: Fall.mat or first .mat
        mat_pref = ["Fall.mat"] + [f for f in os.listdir(folder) if f.endswith(".mat")]
        for fname in mat_pref:
            path = os.path.join(folder, fname)
            if not os.path.exists(path): continue
            result = self._read_mat(path)
            if result is None: return
            F, Fneu, fs = result
            arr = self._orient(F, fname)
            if arr is None: return
            self.F = arr; self.Fneu = Fneu; self.data_type = "mat"
            if fs is not None: self.fs_var.set(round(float(fs), 4))
            n, t = self.F.shape
            note = " + Fneu" if self.Fneu is not None else ""
            self.status_var.set(
                f"MATLAB: {n} cells × {t} frames{note}  ·  fs={self.fs_var.get()} Hz  ·  {fname}")
            self.plot(); return

        messagebox.showerror("Nothing found",
                             "No F.npy, .npy, or .mat files found in that folder.")

    def _load_file(self):
        """Pick a single file; dispatch by extension."""
        path = filedialog.askopenfilename(
            title="Select data file",
            filetypes=[("NumPy / MATLAB", "*.npy *.mat"),
                       ("NumPy", "*.npy"),
                       ("MATLAB", "*.mat"),
                       ("All", "*.*")])
        if not path: return
        if path.lower().endswith(".npy"):
            self.load_npy(path)
        else:
            self.load_mat(path)

    def _build_canvas(self):
        # _content_row holds the (Gain-tab-only) left sidebar next to the
        # always-present main output area, so the plot/animation and the
        # sidebar can sit side by side per Filip's "options on the left
        # column" request.
        self._content_row = tk.Frame(self.root, bg=BG_DARK)
        self._content_row.pack(fill=tk.BOTH, expand=True)

        # Each tab's sidebar card stack can be taller than the window at
        # the default 990px height, which silently clipped "Run Analysis"
        # off the bottom with no way to reach it -- so every sidebar is a
        # scrollable Canvas+Frame rather than a plain Frame (factored into
        # _build_scrollable_sidebar so the Gain and Neuropil Sweep tabs
        # share the exact same scroll/mousewheel/black-scrollbar behavior
        # instead of two hand-copied versions). The returned outer frame
        # is still what _switch_tab packs/unpacks; card-building
        # (_sidebar_card) targets the returned inner frame that actually
        # scrolls.
        self._gain_sidebar, self._gain_sidebar_inner = self._build_scrollable_sidebar()
        self._neuropil_sidebar, self._neuropil_sidebar_inner = self._build_scrollable_sidebar()

        self._main_area = tk.Frame(self._content_row, bg=BG_DARK)
        self._main_area.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        self.fig = Figure(facecolor=BG_DARK)
        self.canvas = FigureCanvasTkAgg(self.fig, master=self._main_area)
        self.canvas.get_tk_widget().pack(fill=tk.BOTH, expand=True)
        # No toolbar — removed intentionally

        # Busy animation lives in the same main output area, swapped in for
        # the canvas by _progress_start/_progress_stop while an analysis is
        # running -- not packed until then. Shared by the Gain and
        # Neuropil Sweep tabs alike (both are "click Run Analysis, wait,
        # see a plot" workflows).
        self.gain_progress_bar = PhotonNeuronBar(self._main_area)
        # Plain stand-in shown instead whenever whimsy_var is False (see
        # _toggle_whimsy / _active_bar) -- never packed until then.
        self.plain_progress_bar = PlainProgressBar(self._main_area)
        # Neuropil Sweep's idle *and* busy view rolled into one widget --
        # unlike gain_progress_bar/plain_progress_bar (only ever shown
        # while _progress_start/_progress_stop has one running), this one
        # is also the tab's idle "splash" (donut-eating-neuron loop,
        # crumbs accumulating) whenever the tab has no results yet and
        # whimsy is on -- see _show_neuropil_idle. _progress_start just
        # flips it into its "busy" (crumb-sweeping) mode rather than
        # swapping in a different widget. Never packed until then.
        self.donut_bar = DonutNeuronBar(self._main_area)
        self._active_bar = None
        self._progress_started_at = None
        self._progress_mode = "bar"   # "bar" or "donut" -- captured at
                                       # _progress_start time, reused by
                                       # _progress_stop so a mid-run tab
                                       # switch can't flip which one gets
                                       # torn down

        self._build_gain_sidebar()
        self._build_neuropil_sidebar()
        self._draw_splash()

    def _build_scrollable_sidebar(self, width=260):
        """Build one left sidebar: a non-propagating outer Frame (what
        _switch_tab packs/unpacks) wrapping a Canvas+Scrollbar whose inner
        Frame is where a tab's _sidebar_card content actually goes.
        Returns (outer, inner). Factored out of what was originally a
        Gain-tab-only block so the Neuropil Sweep sidebar gets the same
        scrolling/mousewheel/black-scrollbar behavior for free."""
        outer = tk.Frame(self._content_row, bg=BG_MID, width=width)
        outer.pack_propagate(False)
        # not packed here -- _switch_tab packs/unpacks it depending on tab

        canvas = tk.Canvas(outer, bg=BG_MID, highlightthickness=0, bd=0)
        # Black scrollbar (not the platform-default grey/silver one), to
        # match the sidebar's own greyscale palette. troughcolor blends
        # with the sidebar background; bg/activebackground are the
        # draggable thumb itself.
        scrollbar = tk.Scrollbar(
            outer, orient="vertical", command=canvas.yview,
            bg="black", activebackground="black", troughcolor=BG_MID,
            highlightthickness=0, bd=0, elementborderwidth=0)
        canvas.configure(yscrollcommand=scrollbar.set)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
        canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        inner = tk.Frame(canvas, bg=BG_MID)
        inner_win = canvas.create_window((0, 0), window=inner, anchor="nw")

        def _on_inner_configure(event=None):
            canvas.configure(scrollregion=canvas.bbox("all"))
        inner.bind("<Configure>", _on_inner_configure)

        def _on_canvas_configure(event):
            canvas.itemconfig(inner_win, width=event.width)
        canvas.bind("<Configure>", _on_canvas_configure)

        # Mouse-wheel scroll, only while the pointer is actually over this
        # sidebar (bound/unbound on Enter/Leave) so it doesn't hijack
        # scrolling anywhere else in the app. Covers Windows/macOS
        # (<MouseWheel>, event.delta) and Linux (<Button-4>/<Button-5>).
        def _on_mousewheel(event):
            if getattr(event, "num", None) == 5 or getattr(event, "delta", 0) < 0:
                canvas.yview_scroll(1, "units")
            elif getattr(event, "num", None) == 4 or getattr(event, "delta", 0) > 0:
                canvas.yview_scroll(-1, "units")

        def _bind_wheel(event=None):
            canvas.bind_all("<MouseWheel>", _on_mousewheel)
            canvas.bind_all("<Button-4>", _on_mousewheel)
            canvas.bind_all("<Button-5>", _on_mousewheel)

        def _unbind_wheel(event=None):
            canvas.unbind_all("<MouseWheel>")
            canvas.unbind_all("<Button-4>")
            canvas.unbind_all("<Button-5>")

        canvas.bind("<Enter>", _bind_wheel)
        canvas.bind("<Leave>", _unbind_wheel)

        return outer, inner

    def _draw_splash(self):
        """Kurtosis-tab splash, shown before any file has been loaded.
        Whimsy on: the "kurtosis_splash" art (four neurons each examining a
        trace of different peakiness), per Filip's "plug this for the
        whimsy kurtosis main graphic instead of the k which is to be
        non-whimsy". Whimsy off: the original K-trace logo -- drawn as
        matplotlib lines, no image, no hard edges -- which used to be the
        splash unconditionally and is now the de-whimsified fallback."""
        if self.whimsy_var.get():
            self._draw_kurtosis_splash_art()
        else:
            self._draw_k_trace_logo()
        self._splash_active = True

    def _draw_kurtosis_splash_art(self):
        self.fig.clear()
        ax = self.fig.add_axes([0.05, 0.05, 0.9, 0.9])
        ax.set_facecolor(BG_DARK)
        ax.axis("off")
        for spine in ax.spines.values():
            spine.set_visible(False)
        im = _load_kurtosis_splash_outlined()
        aspect = im.height / im.width
        # Preserve the art's own aspect ratio rather than stretching it to
        # fill the axes -- center it, sized to whichever dimension (width
        # or height) of the 0..1 axes box is the binding constraint.
        if aspect <= 1.0:
            w, h = 1.0, aspect
        else:
            w, h = 1.0 / aspect, 1.0
        x0, y0 = (1 - w) / 2, (1 - h) / 2
        ax.imshow(np.asarray(im), extent=(x0, x0 + w, y0, y0 + h), zorder=2)
        ax.set_xlim(0, 1); ax.set_ylim(0, 1)  # imshow's extent re-autoscales -- lock back
        self.canvas.draw_idle()

    def _draw_k_trace_logo(self):
        """Draw the K-trace logo as matplotlib lines — no image, no hard edges."""
        self.fig.clear()
        ax = self.fig.add_axes([0.20, 0.15, 0.60, 0.60])
        ax.set_facecolor(BG_DARK)
        ax.set_aspect("equal")
        ax.axis("off")
        for spine in ax.spines.values():
            spine.set_visible(False)

        # Original 27-row dense logo
        K_X_STEM, K_X_ARM = 200, 352
        K_Y_TOP, K_Y_BOTTOM = 96, 420
        K_Y_VERTEX = 288
        K_Y_ARM_TOP, K_Y_ARM_BOTTOM = 214, 420
        ROW_COUNT = 27
        BAND_X0, BAND_X1 = 62, 452
        BAND_Y0, BAND_Y1 = 78, 444
        SAMPLES = 160
        MAX_AMP, RISE_PX, DECAY_PX = 10, 6, 20

        def k_crossings(y):
            xs = []
            if K_Y_TOP <= y <= K_Y_BOTTOM:
                xs.append(K_X_STEM)
            if K_Y_ARM_TOP <= y <= K_Y_VERTEX:
                t = (K_Y_VERTEX - y) / (K_Y_VERTEX - K_Y_ARM_TOP)
                xs.append(K_X_STEM + t * (K_X_ARM - K_X_STEM))
            if K_Y_VERTEX <= y <= K_Y_ARM_BOTTOM:
                t = (y - K_Y_VERTEX) / (K_Y_ARM_BOTTOM - K_Y_VERTEX)
                xs.append(K_X_STEM + t * (K_X_ARM - K_X_STEM))
            return xs

        step = (BAND_Y1 - BAND_Y0) / (ROW_COUNT - 1)
        row_amp = min(MAX_AMP, step * 0.9)

        for r in range(ROW_COUNT):
            row_y = BAND_Y0 + r * step
            events = k_crossings(row_y)
            xs, ys = [], []
            for s in range(SAMPLES):
                t = s / (SAMPLES - 1)
                x = BAND_X0 + t * (BAND_X1 - BAND_X0)
                deflect = 0.0
                for ex in events:
                    d = x - ex
                    k = max(0.0, 1 + d / RISE_PX) if d < 0 else math.exp(-d / DECAY_PX)
                    deflect += k
                deflect = min(deflect, 1.2) * row_amp
                wobble = math.sin(x * 0.045 + r * 1.9) * 0.9 + math.sin(x * 0.12 + r * 0.5) * 0.45
                xs.append(x)
                ys.append(-(row_y - deflect - wobble))

            depth = r / (ROW_COUNT - 1)
            alpha = 0.5 + 0.42 * (1 - abs(depth - 0.5) * 1.1)
            ax.plot(xs, ys, color="white", lw=0.9, alpha=alpha, solid_capstyle="round")

        span = max(BAND_X1 - BAND_X0, BAND_Y1 - BAND_Y0)
        cx = (BAND_X0 + BAND_X1) / 2
        cy = -(BAND_Y0 + BAND_Y1) / 2
        ax.set_xlim(cx - span / 2, cx + span / 2)
        ax.set_ylim(cy - span / 2, cy + span / 2)
        self.canvas.draw_idle()

    def _draw_gain_splash(self):
        """Gain-tab splash, shown before any analysis has run. Used to
        sketch a placeholder hockey-stick curve; replaced with a centered
        quote per Filip's ask -- the real PTC hockey-stick plot still
        appears normally once Run Analysis actually produces results (see
        _render_gain_results). The quote is the "whimsical" part of this
        splash -- de-whimsify removes it (Filip: "dewhimsify will also
        change the no power source no gain to nothing"), leaving just the
        functional guidance text underneath."""
        self.fig.clear()
        ax = self.fig.add_axes([0.05, 0.05, 0.9, 0.9])
        ax.set_facecolor(BG_DARK)
        for s in ax.spines.values():
            s.set_visible(False)
        ax.set_xticks([]); ax.set_yticks([])
        if self.whimsy_var.get():
            ax.text(0.5, 0.55, "“no power supply no gain”",
                     color="white", fontsize=15, fontweight="bold",
                     fontfamily="sans-serif", ha="center", va="center",
                     transform=ax.transAxes)
        ax.text(0.5, 0.15, "Load a Suite2p folder, then click Run Analysis",
                 color=TEXT_DIM, fontsize=11, ha="center", transform=ax.transAxes)
        self.canvas.draw_idle()

    # ── loaders (kurtosis-mode extras, unchanged) ───────────────────────

    def _try_fs(self, ops_obj):
        if ops_obj is None:
            return None
        try:
            if isinstance(ops_obj, dict):
                return float(ops_obj.get("fs", 30.0))
            if hasattr(ops_obj, "item"):
                d = ops_obj.item()
                if isinstance(d, dict):
                    return float(d.get("fs", 30.0))
            return float(np.asarray(ops_obj["fs"]).flat[0])
        except Exception:
            return None

    def load_suite2p(self):
        folder = filedialog.askdirectory(title="Select Suite2p output folder")
        if not folder:
            return
        search = [folder] + [os.path.join(folder, d)
                              for d in ("plane0", "plane1", "plane2", "combined")]
        f_path = fneu_path = ops_path = None
        for d in search:
            cand = os.path.join(d, "F.npy")
            if os.path.exists(cand):
                f_path = cand
                fp = os.path.join(d, "Fneu.npy"); op = os.path.join(d, "ops.npy")
                if os.path.exists(fp): fneu_path = fp
                if os.path.exists(op): ops_path  = op
                break
        if f_path is None:
            messagebox.showerror("Not found", "F.npy not found."); return
        try:
            self.F    = np.load(f_path).astype(float)
            self.Fneu = np.load(fneu_path).astype(float) if fneu_path else None
            if ops_path:
                ops = np.load(ops_path, allow_pickle=True).item()
                fs  = self._try_fs(ops)
                if fs: self.fs_var.set(round(fs, 4))
        except Exception as e:
            messagebox.showerror("Error", str(e)); return
        self.data_type = "suite2p"
        n, t = self.F.shape
        note = " + Fneu" if self.Fneu is not None else ""
        self.status_var.set(
            f"Suite2p: {n} cells × {t} frames{note}  ·  fs = {self.fs_var.get()} Hz")

    def load_npy(self, path=None):
        if path is None:
            path = filedialog.askopenfilename(title="NumPy file",
                                              filetypes=[("NumPy", "*.npy"), ("All", "*.*")])
        if not path: return
        try:
            arr = np.load(path, allow_pickle=False).astype(float)
        except Exception as e:
            messagebox.showerror("Error", str(e)); return
        arr = self._orient(arr, os.path.basename(path))
        if arr is None: return
        self.F = arr; self.Fneu = None; self.data_type = "npy"
        self.status_var.set(f"NumPy: {arr.shape[0]} cells × {arr.shape[1]} frames")

    def load_mat(self, path=None):
        if path is None:
            path = filedialog.askopenfilename(title="MATLAB file",
                                              filetypes=[("MATLAB", "*.mat"), ("All", "*.*")])
        if not path: return
        result = self._read_mat(path)
        if result is None: return
        F, Fneu, fs = result
        arr = self._orient(F, os.path.basename(path))
        if arr is None: return
        self.F = arr; self.Fneu = Fneu; self.data_type = "mat"
        if fs is not None: self.fs_var.set(round(float(fs), 4))
        n, t = self.F.shape
        note = " + Fneu" if self.Fneu is not None else ""
        self.status_var.set(
            f"MATLAB: {n} cells × {t} frames{note}  ·  fs = {self.fs_var.get()} Hz")

    def _read_mat(self, path):
        def parse(mat, hdf5=False):
            def to2d(k):
                if k not in mat: return None
                try:
                    v = np.array(mat[k]).astype(float)
                    if hdf5: v = v.T
                    return v if v.ndim == 2 else None
                except Exception:
                    return None

            F = None
            for k in ("F", "f", "traces", "data"):
                F = to2d(k)
                if F is not None: break
            if F is None:
                keys = [k for k in mat
                        if not k.startswith("_") and not k.startswith("#")]
                two_d = [k for k in keys if to2d(k) is not None]
                if len(two_d) == 1:
                    F = to2d(two_d[0])
                elif two_d:
                    ch = self._pick_variable(two_d)
                    if ch is None: return None
                    F = to2d(ch)
                else:
                    messagebox.showerror("Error", "No 2-D variable found."); return None

            Fneu = None
            for k in ("Fneu", "fneu", "Fneuropil"):
                v = to2d(k)
                if v is not None: Fneu = v; break

            fs = None
            if "ops" in mat:
                try:
                    ops = mat["ops"]
                    if hdf5:
                        fs = float(np.array(ops["fs"]).flat[0])
                    else:
                        if hasattr(ops, "dtype") and ops.dtype.names:
                            fs = float(ops["fs"].flat[0])
                        elif hasattr(ops, "item"):
                            d = ops.item()
                            if isinstance(d, dict): fs = float(d.get("fs", 30.0))
                        else:
                            fs = float(np.asarray(ops[0, 0]["fs"]).flat[0])
                except Exception:
                    pass

            return F, Fneu, fs

        try:
            mat = scipy.io.loadmat(path)
            return parse(mat, hdf5=False)
        except NotImplementedError:
            pass
        except Exception as e:
            messagebox.showerror("Error", str(e)); return None

        try:
            import h5py
        except ImportError:
            messagebox.showerror("Missing package",
                                 "MATLAB v7.3 needs h5py:\n  pip install h5py")
            return None
        try:
            with h5py.File(path, "r") as f:
                return parse(f, hdf5=True)
        except Exception as e:
            messagebox.showerror("HDF5 error", str(e)); return None

    def _orient(self, arr, name):
        if arr.ndim != 2:
            messagebox.showerror("Shape error",
                                 f"{name}: expected 2-D, got {arr.shape}."); return None
        r, c = arr.shape
        if r == c:
            if not messagebox.askyesno("Square",
                                       f"{name} is {r}×{c}.\nYes → rows = cells"):
                arr = arr.T
        elif r > c:
            if messagebox.askyesno("Orientation",
                                   f"{name}: {r}×{c}, more rows than columns.\n"
                                   "Transpose (rows = frames)?"):
                arr = arr.T
        return arr

    def _pick_variable(self, keys):
        win = tk.Toplevel(self.root)
        win.title("Select variable"); win.configure(bg=BG_DARK); win.grab_set()
        tk.Label(win, text="Choose variable:", bg=BG_DARK, fg=TEXT_BRIGHT,
                 padx=16, pady=10).pack()
        choice = tk.StringVar(value=keys[0])
        for k in keys:
            tk.Radiobutton(win, text=k, variable=choice, value=k,
                           bg=BG_DARK, fg=TEXT_MAIN, selectcolor=BG_PANEL,
                           activebackground=BG_DARK).pack(anchor=tk.W, padx=24)
        result = [None]
        def ok(): result[0] = choice.get(); win.destroy()
        _rounded_button(win, "OK", ok, bg=BG_PANEL, fg="white",
                        font_size=10, pady=12, side=tk.TOP)
        self.root.wait_window(win)
        return result[0]

    # ── kurtosis plotting (unchanged) ────────────────────────────────────

    def plot(self):
        if self.F is None:
            messagebox.showwarning("No data", "Load data first."); return

        self._splash_active = False

        # Pre-process
        F = self.F.copy().astype(float)
        if (self.data_type in ("suite2p", "mat")
                and self.do_neuropil.get() and self.Fneu is not None):
            F -= self.neuropil_coeff.get() * self.Fneu
        if self.do_dff.get():
            pct = float(np.clip(self.dff_pct.get(), 1, 99))
            f0  = np.percentile(F, pct, axis=1, keepdims=True)
            f0  = np.where(np.abs(f0) < 1e-6, 1e-6, f0)
            F   = (F - f0) / np.abs(f0)
        fs  = max(0.1, float(self.fs_var.get()))
        sec = max(0.0, float(self.boxcar_sec.get()))
        bc  = max(1, round(sec * fs))
        # Metrics computed on unfiltered traces
        n_cells, n_frames = F.shape
        kurt = stats.kurtosis(F, axis=1, fisher=False)   # Pearson; normal ≈ 3
        snr  = (F.max(axis=1) - F.mean(axis=1)) / (F.std(axis=1) + 1e-12)

        # Boxcar filter applied only for display
        if bc > 1:
            F = uniform_filter1d(F, size=bc, axis=1)

        # Pick a shared pool of cells so both panels show the same population.
        # Subsample evenly from all cell indices (metric-agnostic), then sort
        # that same pool by each metric independently.
        if n_cells <= MAX_SHOW:
            pool = np.arange(n_cells)
        else:
            pool = np.round(np.linspace(0, n_cells - 1, MAX_SHOW)).astype(int)

        kurt_disp = pool[np.argsort(kurt[pool])[::-1]]
        snr_disp  = pool[np.argsort(snr[pool])[::-1]]

        mode = self.mode.get()
        prim  = kurt_disp if mode == "kurtosis" else snr_disp
        n_p   = len(prim)
        mid_s = n_p // 2 - N_ZOOM // 2
        groups = {
            "top": prim[:N_ZOOM],
            "mid": prim[mid_s: mid_s + N_ZOOM],
            "bot": prim[-N_ZOOM:],
        }
        cell_color = {}
        for g, cells in groups.items():
            for c in cells: cell_color[c] = G_COLORS[g]

        # ── figure ────────────────────────────────────────────────────────────
        self.fig.clear()
        gs = GridSpec(3, 3, figure=self.fig,
                      left=0.055, right=0.975, top=0.96, bottom=0.05,
                      wspace=0.22, hspace=0.32,
                      width_ratios=[1.4, 1.4, 1.4])

        ax_l  = self.fig.add_subplot(gs[:, 0])
        ax_r  = self.fig.add_subplot(gs[:, 2])
        ax_zt = self.fig.add_subplot(gs[0, 1])
        ax_zm = self.fig.add_subplot(gs[1, 1])
        ax_zb = self.fig.add_subplot(gs[2, 1])

        t = np.arange(n_frames)

        # ── style helper ──────────────────────────────────────────────────────
        def style(ax, right_spine=False):
            ax.set_facecolor(BG_DARK)
            for s in ax.spines.values(): s.set_color("#555")
            ax.spines["top"].set_visible(False)
            ax.spines["left"].set_color("#555")
            ax.spines["bottom"].set_color("#555")
            ax.spines["right"].set_visible(right_spine)
            if right_spine: ax.spines["right"].set_color("#555")
            ax.tick_params(colors=TEXT_MAIN, labelsize=6.5)

        def normed(trace, height=1.0):
            lo, hi = trace.min(), trace.max()
            rng = hi - lo
            return (trace - lo) / rng * height if rng > 0 else np.zeros_like(trace)

        # ── large stacked panels ──────────────────────────────────────────────

        def draw_large(ax, displayed, metric_vals, metric_label, is_source):
            style(ax)
            n = len(displayed)

            # Highlight bands (source panel only)
            if is_source:
                rank_map = {c: i for i, c in enumerate(displayed)}
                for g, cells in groups.items():
                    rows = sorted(rank_map[c] for c in cells if c in rank_map)
                    if not rows: continue
                    col  = G_COLORS[g]
                    y_lo = (n - 1 - max(rows)) * SP_L - 0.04
                    y_hi = (n - 1 - min(rows)) * SP_L + SP_L * 0.85 + 0.04
                    ax.axhspan(y_lo, y_hi, color=col, alpha=0.10, zorder=0)
                    ax.axhspan(y_lo, y_hi, xmin=0.990, xmax=1.0,
                               color=col, alpha=1.0, clip_on=False, zorder=6)

            # Traces — normalized to 85% of spacing to avoid harsh overlap
            h = SP_L * 0.85
            ytick_step = max(1, n // 20)
            ytick_pos, ytick_lbl = [], []
            for row_i, cidx in enumerate(displayed):
                tn     = normed(F[cidx], height=h)
                offset = (n - 1 - row_i) * SP_L
                col    = cell_color.get(cidx, C_UNSEL)
                sel    = cidx in cell_color
                ax.plot(t, tn + offset,
                        lw=0.75 if sel else 0.30,
                        color=col,
                        alpha=A_SEL if sel else A_UNSEL,
                        zorder=3 if sel else 1)
                if row_i % ytick_step == 0:
                    ytick_pos.append(offset + h * 0.5)
                    ytick_lbl.append(f"{metric_vals[cidx]:.1f}")

            ax.set_yticks(ytick_pos)
            ax.set_yticklabels(ytick_lbl, fontsize=6.5, color=TEXT_MAIN)
            ax.set_ylabel(metric_label, color=TEXT_MAIN, fontsize=9, labelpad=2)
            ax.set_xlim(0, n_frames - 1)
            ax.set_ylim(-SP_L * 0.5, n * SP_L)
            ax.set_xlabel("Frame", color=TEXT_DIM, fontsize=8)

            tag = "◀ groups defined here" if is_source else "◀ colors projected here"
            ax.set_title(
                f"Sorted by {metric_label}  ({n} / {n_cells})  {tag}",
                color=TEXT_BRIGHT, fontsize=9, pad=5, fontweight="bold")

        l_is_src = (mode == "kurtosis")
        draw_large(ax_l, kurt_disp, kurt, "κ",   is_source=l_is_src)
        draw_large(ax_r, snr_disp,  snr,  "SNR", is_source=not l_is_src)

        # ── zoom panels (dual y-axes) ─────────────────────────────────────────

        src_lbl = "κ" if mode == "kurtosis" else "SNR"
        zoom_meta = {
            "top": (ax_zt, f"Top {N_ZOOM}  {src_lbl} ↑",    C_TOP),
            "mid": (ax_zm, f"Middle {N_ZOOM}",                C_MID),
            "bot": (ax_zb, f"Bottom {N_ZOOM}  {src_lbl} ↓",  C_BOT),
        }

        for g, (ax, title, col) in zoom_meta.items():
            style(ax, right_spine=True)
            gcells   = groups[g]           # best → worst
            ordered  = gcells[::-1]        # worst → best (bottom → top in plot)
            h_z      = SP_Z * 0.85

            ytick_pos   = []
            kurt_labels = []
            snr_labels  = []

            for row_i, cidx in enumerate(ordered):
                tn     = normed(F[cidx], height=h_z)
                offset = row_i * SP_Z
                ax.plot(t, tn + offset, lw=0.85, color=col, alpha=0.92)
                ytick_pos.append(offset + h_z * 0.5)
                kurt_labels.append(f"{kurt[cidx]:.1f}")
                snr_labels.append(f"{snr[cidx]:.1f}")

            y_lo = -SP_Z * 0.3
            y_hi = N_ZOOM * SP_Z

            # Left y-axis = κ
            ax.set_yticks(ytick_pos)
            ax.set_yticklabels(kurt_labels, fontsize=6.5, color=TEXT_MAIN)
            ax.set_ylabel("κ", color=TEXT_MAIN, fontsize=8, labelpad=2)
            ax.set_ylim(y_lo, y_hi)

            # Right y-axis = SNR (twin)
            ax2 = ax.twinx()
            ax2.set_facecolor("none")
            ax2.spines["right"].set_color("#555")
            ax2.spines["top"].set_visible(False)
            ax2.spines["left"].set_visible(False)
            ax2.spines["bottom"].set_visible(False)
            ax2.tick_params(colors=TEXT_DIM, labelsize=6.5)
            ax2.set_yticks(ytick_pos)
            ax2.set_yticklabels(snr_labels, fontsize=6.5, color=TEXT_DIM)
            ax2.set_ylabel("SNR", color=TEXT_DIM, fontsize=8, labelpad=2)
            ax2.set_ylim(y_lo, y_hi)

            ax.set_xlim(0, n_frames - 1)
            ax.set_title(title, color=col, fontsize=9, pad=3, fontweight="bold")
            ax.tick_params(axis="x",
                           colors=TEXT_DIM if g != "bot" else TEXT_MAIN,
                           labelsize=6 if g != "bot" else 6.5)
            if g == "bot":
                ax.set_xlabel("Frame", color=TEXT_DIM, fontsize=8)
            else:
                ax.set_xticklabels([])

        self.canvas.draw()

    # ── gain-mode: loading (never touches the registered movie) ─────────

    def _load_gain_folder(self):
        folder = filedialog.askdirectory(title="Select Suite2p output folder")
        if not folder:
            return
        plane_dir = find_suite2p_plane(folder)
        if plane_dir is None:
            self._load_gain_manual_tiff(folder)
            return
        try:
            ops = np.load(os.path.join(plane_dir, "ops.npy"), allow_pickle=True).item()
            F = np.load(os.path.join(plane_dir, "F.npy")).astype(float)
            fneu_p = os.path.join(plane_dir, "Fneu.npy")
            Fneu = np.load(fneu_p).astype(float) if os.path.exists(fneu_p) else None
            stat_p = os.path.join(plane_dir, "stat.npy")
            stat = np.load(stat_p, allow_pickle=True) if os.path.exists(stat_p) else None
            iscell_p = os.path.join(plane_dir, "iscell.npy")
            if os.path.exists(iscell_p):
                iscell = np.load(iscell_p)
                mask = iscell[:, 0].astype(bool)
                F = F[mask]
                if Fneu is not None:
                    Fneu = Fneu[mask]
                if stat is not None:
                    stat = stat[mask]
            # Suite2p normalizes its per-pixel ROI weights (lam) to sum to
            # 1 before extraction (see masks.py / create_cell_mask), so
            # F.npy is a weighted MEAN pixel value, not a sum -- its
            # magnitude is roughly independent of ROI size. Multiply back
            # by each ROI's pixel count (stat.npy's "npix") to recover a
            # per-cell total ADU, matching footprints_to_raw_traces' true
            # pixel-sum convention (CNMF path) so photon-flux numbers are
            # comparable and represent whole-cell totals, not per-pixel
            # averages.
            if stat is not None:
                npix = np.array([max(1, int(s.get("npix", 1))) for s in stat], dtype=float)
                F = F * npix[:, None]
                if Fneu is not None:
                    Fneu = Fneu * npix[:, None]
        except Exception as e:
            messagebox.showerror("Error", str(e)); return

        self.g_plane_dir, self.g_ops, self.g_F, self.g_Fneu, self.g_stat = \
            plane_dir, ops, F, Fneu, stat
        self.g_raw_tiffs = None   # clear any previous manual-TIFF selection
        self.g_raw_shape = None
        self.g_mat_movie = None  # clear any previous .mat-movie selection
        self.g_results = None
        fs = ops.get("fs")
        if fs:
            self.fs_var.set(round(float(fs), 4))
        n_cells = F.shape[0]
        reg_dir = os.path.join(plane_dir, "reg_tif")
        # Use the exact same file-matching logic Run Analysis will use, so this
        # hint can never say "found" while Run Analysis then falls back anyway.
        n_reg_files = len(_find_reg_tif_files(reg_dir)) if os.path.isdir(reg_dir) else 0
        src_hint = (f"reg_tif found ({n_reg_files} file(s))" if n_reg_files else
                    "no usable reg_tif — will need NormCorre on raw TIFFs")
        self.status_var.set(f"Loaded: {plane_dir}  ·  {n_cells} cells  ·  "
                              f"fs={self.fs_var.get()} Hz  ·  {src_hint}  ·  click Run Analysis")
        self._draw_gain_splash()

    def _load_neuropil_folder(self):
        """Neuropil Sweep tab's loader -- Suite2p only, no registered-
        movie fallback (unlike the Gain tab). Needs F.npy, Fneu.npy,
        stat.npy (for the ROI exclusion distance), and iscell.npy."""
        folder = filedialog.askdirectory(title="Select Suite2p output folder")
        if not folder:
            return
        plane_dir = find_suite2p_plane(folder)
        if plane_dir is None:
            messagebox.showerror(
                "Not found",
                "No Suite2p plane folder found (needs F.npy, Fneu.npy, "
                "stat.npy, and iscell.npy) -- Neuropil Sweep only works "
                "with Suite2p output, unlike the other two tabs.")
            return
        try:
            F = np.load(os.path.join(plane_dir, "F.npy")).astype(float)
            fneu_p = os.path.join(plane_dir, "Fneu.npy")
            if not os.path.exists(fneu_p):
                messagebox.showerror("Not found", "Fneu.npy not found -- "
                                      "needed for the neuropil sweep.")
                return
            Fneu = np.load(fneu_p).astype(float)
            stat_p = os.path.join(plane_dir, "stat.npy")
            if not os.path.exists(stat_p):
                messagebox.showerror("Not found", "stat.npy not found -- "
                                      "needed for the ROI exclusion "
                                      "distance.")
                return
            stat = np.load(stat_p, allow_pickle=True)
            iscell_p = os.path.join(plane_dir, "iscell.npy")
            if os.path.exists(iscell_p):
                iscell = np.load(iscell_p)
                mask = iscell[:, 0].astype(bool)
                F = F[mask]
                Fneu = Fneu[mask]
                stat = stat[mask]
            else:
                messagebox.showwarning(
                    "No iscell.npy",
                    "iscell.npy not found -- using all ROIs, not just "
                    "user-curated cells.")
        except Exception as e:
            messagebox.showerror("Error", str(e)); return

        self.np_plane_dir = plane_dir
        self.np_F, self.np_Fneu, self.np_stat = F, Fneu, list(stat)
        self.np_results = None
        n_cells, n_frames = F.shape
        self.status_var.set(f"Loaded: {plane_dir}  ·  {n_cells} cells × "
                             f"{n_frames} frames  ·  click Run Analysis")
        self._draw_neuropil_splash()

    def _load_gain_manual_tiff(self, folder):
        """No Suite2p ops.npy found — offer to run the PTC gain estimate directly
        on user-selected TIFF(s) instead. No F.npy means no per-cell photon-flux
        panel, but the hockey-stick gain fit itself doesn't need Suite2p at all."""
        proceed = messagebox.askyesno(
            "No Suite2p output found",
            f"No ops.npy found in that folder (checked root, plane0/1/2/3, combined).\n\n"
            f"Select TIFF file(s) to run the PTC gain estimate on directly?\n"
            f"(Without Suite2p's F.npy, only the gain estimate is available — "
            f"per-cell photon flux needs cell traces.)")
        if not proceed:
            return
        paths = filedialog.askopenfilenames(
            title="Select TIFF(s) to analyze", initialdir=folder,
            filetypes=[("TIFF", "*.tif *.tiff"), ("All", "*.*")])
        if not paths:
            return
        try:
            Ly, Lx, total_frames = probe_tiff_shape(paths)
        except ImportError:
            messagebox.showerror("Missing package", "tifffile is required:\n  pip install tifffile")
            return
        except Exception as e:
            messagebox.showerror("Error", str(e)); return

        self.g_plane_dir, self.g_ops, self.g_F, self.g_Fneu, self.g_stat = None, None, None, None, None
        self.g_raw_tiffs = list(paths)
        self.g_raw_shape = (Ly, Lx, total_frames)
        self.g_mat_movie = None  # clear any previous .mat-movie selection
        self.g_results = None
        self.status_var.set(
            f"Loaded {len(paths)} TIFF(s)  ·  {Ly}x{Lx} px  ·  {total_frames} frames  ·  "
            f"no Suite2p F.npy — gain estimate only  ·  verify fs in Settings  ·  click Run Analysis")
        self._draw_gain_splash()

    def _load_gain_mat_movie(self):
        """Load an already motion-corrected movie straight from a .mat file,
        bypassing NormCorre entirely. For when motion correction was already
        done elsewhere (e.g. MATLAB), or when NormCorre's own memmap write
        keeps failing (e.g. 'OSError: No space left on device' -- that error
        comes from np.memmap() writing a multi-GB scratch file to disk during
        motion_correction_piecewise, so it means the disk NormCorre's scratch
        dir lives on is full, not that anything is wrong with the movie).

        Expects a 3D numeric array shaped (x, y, time); axis-order handling
        for scipy (classic .mat) vs h5py (v7.3/HDF5 .mat) is in
        _load_mat_movie_array."""
        path = filedialog.askopenfilename(
            title="Select a motion-corrected movie (.mat, matrix x/y/time)",
            filetypes=[("MATLAB", "*.mat"), ("All", "*.*")])
        if not path:
            return
        try:
            arr, varname = _load_mat_movie_array(path)
        except ImportError:
            messagebox.showerror(
                "Missing package",
                "This .mat file needs h5py to read (MATLAB v7.3 / HDF5 format):\n"
                "  pip install h5py")
            return
        except Exception as e:
            messagebox.showerror("Error", str(e)); return

        T, Ly, Lx = arr.shape
        proceed = messagebox.askyesno(
            "Confirm movie shape",
            f"Loaded variable '{varname}' from {os.path.basename(path)}.\n\n"
            f"Interpreted as {T} frames of {Lx}x{Ly} px (x, y, time order).\n\n"
            f"If that looks wrong (e.g. frame count and pixel dimensions "
            f"look swapped), cancel and double check the axis order the "
            f"movie was saved with.\n\nProceed?")
        if not proceed:
            return

        self.g_plane_dir, self.g_ops, self.g_F, self.g_Fneu, self.g_stat = None, None, None, None, None
        self.g_raw_tiffs = None
        self.g_raw_shape = None
        self.g_mat_movie = arr
        self.g_mat_movie_note = f"{os.path.basename(path)} (var '{varname}')"
        self.g_results = None
        self.status_var.set(
            f"Loaded motion-corrected movie from .mat  ·  {T} frames  ·  {Lx}x{Ly} px  ·  "
            f"{os.path.basename(path)}  ·  NormCorre will be skipped  ·  "
            f"no Suite2p F.npy — gain estimate only  ·  verify fs in Settings  ·  click Run Analysis")
        self._draw_gain_splash()

    def _ask_raw_dir(self):
        return filedialog.askdirectory(
            title="Locate the raw acquisition TIFF folder (ops paths didn't resolve)")

    # ── gain-mode: analysis (threaded; this is the only place the movie loads) ──

    def run_gain_analysis(self):
        if self.g_plane_dir is None and not self.g_raw_tiffs and self.g_mat_movie is None:
            messagebox.showwarning("No data", "Load a Suite2p folder, select TIFFs, or load a .mat movie first.")
            return

        max_frames = max(50, int(self.max_frames_var.get()))
        if self.g_plane_dir is not None:
            Ly, Lx = self.g_ops.get("Ly"), self.g_ops.get("Lx")
        elif self.g_raw_tiffs:
            Ly, Lx, _ = self.g_raw_shape
        else:
            _, Ly, Lx = self.g_mat_movie.shape
        frame_bytes = Ly * Lx * 4  # worst case: float32
        est_gb = (frame_bytes * max_frames) / 1e9
        if est_gb > 1.5:
            proceed = messagebox.askyesno(
                "Memory check",
                f"Loading up to {max_frames} frames at {Lx}x{Ly} "
                f"px may use roughly {est_gb:.1f} GB of RAM (more if NormCorre motion "
                f"correction is needed). The movie is only loaded now, not before.\n\n"
                f"Continue? (Lower 'Max frames' or raise 'Spatial bin' in Settings to reduce this.)")
            if not proceed:
                return

        self.status_var.set("Locating registered movie...")
        self._progress_start()
        self.root.update_idletasks()
        t = threading.Thread(target=self._run_gain_worker, daemon=True)
        t.start()

    def _gain_progress(self, msg):
        self.root.after(0, lambda: self.status_var.set(msg))
        self.root.after(0, lambda: self._motion_overlay_tick(msg))

    def _toggle_whimsy(self):
        """De-whimsify / whimsify the GUI (Filip's own terms). Affects the
        creative busy-animations (gain_progress_bar and, once built, the
        Neuropil Sweep one) -- that swap happens the next time
        _progress_start fires, doesn't touch anything mid-run. Also
        immediately redraws whichever idle splash is currently showing
        (the Kurtosis tab's four-neuron art vs. the K-trace logo / the
        Gain tab's quote / the Neuropil tab's donut-bite picture), since
        those should react right away rather than waiting for a tab
        switch or a Run Analysis to reveal the change."""
        self.whimsy_var.set(not self.whimsy_var.get())
        self._whimsy_btn.config(
            text="De-whimsify the GUI" if self.whimsy_var.get() else "Whimsify the GUI")
        tab = self.tab_var.get()
        if tab == "kurtosis" and self.F is None:
            self._draw_splash()
        elif tab == "gain" and self.g_results is None:
            self._draw_gain_splash()
        elif tab == "neuropil" and self.np_results is None:
            self._show_neuropil_idle()

    # Neuropil Sweep's alpha-sweep computation can finish in well under a
    # second for typical cell counts -- fast enough that the busy
    # animation could get started and immediately torn down again before
    # a single frame of it ever actually painted, which reads as "the
    # animation did not work" even though nothing was actually broken.
    # Gain Estimation's PTC/CNMF pipeline is slow enough this never
    # mattered there. _progress_stop enforces this minimum so the bar is
    # always visible long enough to actually see, regardless of how fast
    # the underlying work finishes.
    PROGRESS_MIN_VISIBLE_S = 0.6

    def _progress_start(self):
        """Start whichever busy indicator fits the current tab, and
        remember which one (_progress_mode) so _progress_stop tears down
        the same one even if the active tab changes in between. Neuropil
        Sweep + whimsy on is special: the donut-eating-neuron idle view
        (DonutNeuronBar) is already up and packed (it's also this tab's
        idle "splash" -- see _show_neuropil_idle), so there's nothing to
        swap in/out here, just flip it into its crumb-sweeping busy mode
        in place. Every other case swaps the plot canvas out for
        PhotonNeuronBar (whimsy on) or a plain indeterminate bar (whimsy
        off), same as before. Safe to call from any thread (marshals onto
        the main loop)."""
        def _go():
            if (self.tab_var.get() == "neuropil" and self.whimsy_var.get()
                    and getattr(self, "_donut_idle_active", False)):
                self._progress_mode = "donut"
                self.donut_bar.set_busy(True)
            else:
                self._progress_mode = "bar"
                self.canvas.get_tk_widget().pack_forget()
                self._active_bar = self.gain_progress_bar if self.whimsy_var.get() else self.plain_progress_bar
                self._active_bar.pack(fill=tk.X, expand=True)
                self._active_bar.start()
            self._progress_started_at = time.monotonic()
        self.root.after(0, _go)

    def _progress_stop(self):
        """Stop whichever busy indicator _progress_start actually started
        (per _progress_mode) -- but not before it's been visible for at
        least PROGRESS_MIN_VISIBLE_S (see above), so a fast worker (e.g. a
        small Neuropil Sweep) can't make it flash by too quickly to ever
        be seen. In "donut" mode, the crumb pile has been swept clean by
        now (DonutNeuronBar.set_busy(False) just returns it to idle) --
        if the run produced real results, hand off to the plot canvas;
        otherwise it stays up as the (now crumb-free) idle view, exactly
        the state Filip described: "when the loading is happening sweep
        the crumbs away." Safe to call from any thread (marshals onto the
        main loop)."""
        def _finish():
            if self._progress_mode == "donut":
                self.donut_bar.set_busy(False)
                if self.np_results is not None:
                    self.donut_bar.stop()
                    self.donut_bar.pack_forget()
                    self._donut_idle_active = False
                    self.canvas.get_tk_widget().pack(fill=tk.BOTH, expand=True)
            else:
                bar = self._active_bar or self.gain_progress_bar
                bar.stop()
                bar.pack_forget()
                self._active_bar = None
                self.canvas.get_tk_widget().pack(fill=tk.BOTH, expand=True)

        def _go():
            started = getattr(self, "_progress_started_at", None)
            elapsed = (time.monotonic() - started) if started is not None else self.PROGRESS_MIN_VISIBLE_S
            remaining = self.PROGRESS_MIN_VISIBLE_S - elapsed
            if remaining > 0:
                self.root.after(int(remaining * 1000), _finish)
            else:
                _finish()
        self.root.after(0, _go)

    def _motion_overlay_start(self):
        """Open the big centered motion-correction overlay. Called via
        on_normcorre_start, from the worker thread -- marshals onto the
        main loop. Safe to call even if one is already open (no-op)."""
        def _do():
            if self._motion_overlay is None:
                self._motion_overlay = MotionCorrectionOverlay(
                    self.root, plain=not self.whimsy_var.get())
        self.root.after(0, _do)

    def _motion_overlay_tick(self, msg=None):
        """No-op unless the motion-correction overlay is currently open."""
        if self._motion_overlay is not None:
            try:
                self._motion_overlay.tick(msg)
            except Exception:
                pass

    def _motion_overlay_stop(self):
        """Close the motion-correction overlay if one is open. Called via
        on_normcorre_done, from the worker thread -- marshals onto the
        main loop. Always fires (even on NormCorre failure) so the overlay
        never gets stuck open."""
        def _do():
            if self._motion_overlay is not None:
                ov = self._motion_overlay
                self._motion_overlay = None
                try:
                    ov.close()
                except Exception:
                    pass
        self.root.after(0, _do)

    def _ask_yesno_blocking(self, title, message):
        """Show a yes/no dialog from this background worker thread and block
        until answered. tkinter dialogs must run on the main thread, so this
        marshals the call via root.after and waits on an Event for the result."""
        result = {}
        event = threading.Event()
        def _ask():
            result["answer"] = messagebox.askyesno(title, message)
            event.set()
        self.root.after(0, _ask)
        event.wait()
        return result.get("answer", False)

    def _show_mean_projection_blocking(self, movie_array):
        """Shows the zoomable mean-projection viewer and blocks this
        (worker) thread until the user closes it, so it's seen and
        dismissed before the CNMF prompt fires. Same main-thread-marshal
        pattern as _ask_yesno_blocking, since Tk windows must be created
        on the main thread.

        The viewer asks the user directly for the cell diameter (px) they
        measured; if they gave one, it's converted to a radius (diameter/2,
        rounded, floor of 2) and written into cnmf_gsig_var right here, so
        the CNMF call that follows uses it automatically instead of relying
        on whatever was left in the Settings panel."""
        event = threading.Event()
        result = {}
        mean_img = np.asarray(movie_array).astype(np.float32).mean(axis=0)
        try:
            default_diameter = max(2, int(self.cnmf_gsig_var.get())) * 2
        except Exception:
            default_diameter = 12

        def _show():
            def _on_continue(diameter):
                result["diameter"] = diameter
                event.set()
            MeanProjectionViewer(self.root, mean_img, default_diameter,
                                  on_continue=_on_continue)

        self.root.after(0, _show)
        event.wait()

        diameter = result.get("diameter")
        if diameter is not None:
            new_radius = max(2, round(diameter / 2))
            self.cnmf_gsig_var.set(new_radius)
            self._gain_progress(
                f"Cell diameter set to {diameter:.0f}px -> CNMF radius {new_radius}px")

    def _parse_frame_start(self):
        """Parse the "Start frame" setting: blank -> None (auto-centered,
        the original default behavior), otherwise an explicit non-negative
        frame index. Invalid/negative text is treated as blank rather than
        raising, so a stray typo just falls back to auto-centering."""
        raw = self.frame_start_var.get().strip()
        if not raw:
            return None
        try:
            v = int(raw)
        except ValueError:
            return None
        return v if v >= 0 else None

    def _scratch_dir_or_none(self):
        """Blank scratch_dir_var -> None (CaImAn's own default location),
        otherwise the chosen folder -- see run_normcorre's docstring for
        what this actually controls."""
        raw = self.scratch_dir_var.get().strip()
        return raw or None

    def _run_gain_worker(self):
        try:
            max_frames = max(50, int(self.max_frames_var.get()))
            pw_rigid = bool(self.pw_rigid_var.get())
            save_mc = bool(self.save_mc_var.get())
            frame_start = self._parse_frame_start()

            mat_movie = getattr(self, "g_mat_movie", None)
            if mat_movie is not None:
                # Already motion-corrected -- NormCorre is skipped entirely,
                # so this never touches disk the way run_normcorre's memmap
                # write does.
                total = mat_movie.shape[0]
                start, end = contiguous_window(total, max_frames, start=frame_start)
                mat_note = getattr(self, "g_mat_movie_note", "")
                self._gain_progress(
                    f"Using pre-loaded .mat movie ({mat_note}), "
                    f"frames [{start}:{end}) of {total} -- NormCorre skipped")
                movie = RegisteredMovie(
                    mat_movie[start:end], "mat_file",
                    f"{mat_note}, frames [{start}:{end}) of {total}, "
                    f"already motion-corrected (NormCorre skipped)")
            elif self.g_plane_dir is not None:
                movie = load_registered_movie(
                    self.g_plane_dir, self.g_ops, max_frames, pw_rigid,
                    progress_cb=self._gain_progress, ask_raw_dir=self._ask_raw_dir,
                    save_mc=save_mc,
                    on_normcorre_start=self._motion_overlay_start,
                    on_normcorre_done=self._motion_overlay_stop,
                    frame_start=frame_start, scratch_dir=self._scratch_dir_or_none())
            else:
                movie = load_registered_movie_manual(
                    self.g_raw_tiffs, max_frames, pw_rigid,
                    skip_mc=bool(self.skip_mc_var.get()), save_mc=save_mc,
                    progress_cb=self._gain_progress,
                    on_normcorre_start=self._motion_overlay_start,
                    on_normcorre_done=self._motion_overlay_stop,
                    frame_start=frame_start, scratch_dir=self._scratch_dir_or_none())

            self._gain_progress(f"Computing PTC from {movie.source} ({movie.shape[0]} frames)...")

            exclude_mask = None
            if self.exclude_roi_var.get() and self.g_stat is not None:
                Ly, Lx = movie.shape[1], movie.shape[2]
                exclude_mask = roi_exclusion_mask(self.g_stat, Ly, Lx)

            spatial_bin = max(1, int(self.spatial_bin_var.get()))
            margin = max(0, int(self.margin_var.get()))
            mu_flat, var_flat, mu_bin, var_bin, n_bin = compute_ptc(
                movie.array, spatial_bin=spatial_bin, exclude_mask=exclude_mask,
                margin=margin)

            fit = fit_gain(mu_bin, var_bin, n_bin,
                            self.fit_lo_var.get(), self.fit_hi_var.get(), self.enf_var.get())

            # Cell traces: existing Suite2p F.npy, or -- any time there's no
            # usable mask at all (no F.npy), regardless of whether the movie
            # came from reg_tif or a fresh NormCorre run -- offer CaImAn
            # CNMF so the flux panel doesn't just stay empty.
            F_for_flux = self.g_F
            cnmf_used = False
            if F_for_flux is None:
                self._gain_progress("Movie loaded — showing mean projection "
                                     "for a cell-size check...")
                self._show_mean_projection_blocking(movie.array)
                movie_desc = ("the registered movie" if movie.source == "reg_tif"
                               else "the motion-corrected movie")
                want_cnmf = self._ask_yesno_blocking(
                    "Run cell segmentation?",
                    f"There's no Suite2p F.npy for this dataset, so the photon-flux "
                    f"panel would otherwise stay empty.\n\n"
                    f"Run CaImAn CNMF on {movie_desc} to detect cells and "
                    f"extract traces? (First-pass integration — sanity-check the "
                    f"resulting footprints/traces against your data before trusting "
                    f"the photon flux numbers.)")
                if want_cnmf:
                    gsig = max(2, int(self.cnmf_gsig_var.get()))
                    fs_for_cnmf = max(0.1, float(self.fs_var.get()))
                    F_cnmf, npix_cnmf, mask_info = run_cnmf_segmentation(
                        movie.array, fs_for_cnmf, gsig, progress_cb=self._gain_progress)
                    mean_img_for_mask = movie.array.mean(axis=0)
                    self.root.after(0, lambda: CNMFMaskViewer(
                        self.root, mean_img_for_mask, mask_info))
                    if F_cnmf.shape[0] > 0:
                        F_for_flux = F_cnmf
                        cnmf_used = True
                    else:
                        self._gain_progress("CNMF found no usable components — "
                                             "continuing without a flux panel.")

            # capture lightweight metadata, then drop the (possibly huge) movie array
            movie_source, movie_note, movie_shape = movie.source, movie.note, movie.shape
            del movie
            gc.collect()

            has_cells = F_for_flux is not None and len(F_for_flux) > 0
            if has_cells:
                fs = max(0.1, float(self.fs_var.get()))
                # Inlined rather than calling self._flux_baseline_pct(): a
                # few tests bind just this method onto a lightweight fake
                # app object via types.MethodType, which doesn't have
                # _flux_baseline_pct available as a *callable* attribute
                # (only whatever was explicitly bound) -- getattr on the
                # *variable* here degrades gracefully instead.
                subtract_var = getattr(self, "subtract_baseline_var", None)
                baseline_pct = (float(self.flux_baseline_pct_var.get())
                                 if subtract_var is not None and subtract_var.get()
                                 else None)
                flux = photon_flux_per_cell(F_for_flux, fit["gain_true"], fs,
                                             baseline_pct=baseline_pct)
                med, sem = bootstrap_median_sem(flux)
            else:
                flux, med, sem = None, np.nan, np.nan

            self.g_results = dict(movie_source=movie_source, movie_note=movie_note,
                                   movie_shape=movie_shape, has_cells=has_cells,
                                   cnmf_used=cnmf_used, n_cells=(len(F_for_flux) if has_cells else 0),
                                   mu_flat=mu_flat, var_flat=var_flat,
                                   mu_bin=mu_bin, var_bin=var_bin, n_bin=n_bin,
                                   fit=fit, flux=flux, flux_med=med, flux_sem=sem,
                                   # cached only so "Re-fit" (below) can redo the cheap
                                   # part -- fit_gain() + photon_flux_per_cell() -- from
                                   # a changed Fit range / ENF without re-running
                                   # motion correction or CNMF. F_for_flux is small
                                   # (n_cells x n_frames), nowhere near the size of the
                                   # movie array this function already dropped above.
                                   F_for_flux=(F_for_flux if has_cells else None))

            self._progress_stop()
            self.root.after(0, self._render_gain_results)
        except Exception as e:
            traceback.print_exc()
            msg = str(e)
            self._progress_stop()
            self._motion_overlay_stop()  # safety net -- should already be closed via the finally in _normcorre_then_maybe_save
            self.root.after(0, lambda: messagebox.showerror("Analysis failed", msg))
            self.root.after(0, lambda: self.status_var.set("Analysis failed — see error dialog"))

    def _flux_baseline_pct(self):
        """The percentile that defines each cell's baseline F0, used AS the
        photon-flux conversion input (not subtracted from F -- see
        photon_flux_per_cell's docstring), or None if 'Use baseline (F0)
        for flux' is unchecked (falls back to converting the trace's
        plain mean instead).

        Uses getattr rather than a direct attribute access because several
        tests build a lightweight fake app (types.SimpleNamespace, not a
        real KurtosisChecker) and bind just _run_gain_worker/_refit_gain
        onto it without setting every sidebar var -- falling back to None
        (the original raw-F behavior) keeps those tests focused on what
        they're actually exercising instead of forcing every one of them
        to also stub out this unrelated setting."""
        var = getattr(self, "subtract_baseline_var", None)
        if var is not None and var.get():
            return float(self.flux_baseline_pct_var.get())
        return None

    def _refit_gain(self):
        """Re-run just the cheap part of the analysis -- the linear PTC fit
        and (if there are cell traces) the photon-flux conversion -- using
        whatever Fit range / ENF / frame rate / baseline settings are
        currently in the sidebar, against the mean/variance bins +
        F_for_flux already cached in g_results from the last full Run
        Analysis.

        Deliberately does NOT touch the movie, motion correction, or CNMF --
        those bins are a function of the raw pixel data (spatial bin, edge
        margin, exclude-ROI mask, frame window all bake into them at
        compute_ptc() time), so changing *those* settings still requires a
        full Run Analysis. Fit range, ENF, and the baseline-subtraction
        settings, by contrast, only rework numbers that already exist (the
        cached bins, and the cached raw F_for_flux respectively) -- this is
        instant and needs no thread."""
        r = self.g_results
        if r is None:
            self.status_var.set("Nothing to re-fit yet — click Run Analysis first")
            return

        fit = fit_gain(r["mu_bin"], r["var_bin"], r["n_bin"],
                        self.fit_lo_var.get(), self.fit_hi_var.get(), self.enf_var.get())
        r["fit"] = fit

        if r["has_cells"] and r.get("F_for_flux") is not None:
            fs = max(0.1, float(self.fs_var.get()))
            flux = photon_flux_per_cell(r["F_for_flux"], fit["gain_true"], fs,
                                         baseline_pct=self._flux_baseline_pct())
            med, sem = bootstrap_median_sem(flux)
            r["flux"], r["flux_med"], r["flux_sem"] = flux, med, sem

        self._render_gain_results()
        self.status_var.set(
            f"Re-fit with ENF={self.enf_var.get():.2f}, fit range "
            f"{self.fit_lo_var.get():.0f}–{self.fit_hi_var.get():.0f}% -- "
            f"gain_true={fit['gain_true']:.2f} ADU/photon")

    def _prompt_text(self, title, prompt, default=""):
        """Small blocking text-entry dialog -- same Toplevel + wait_window
        pattern as _pick_variable/_ask_yesno_blocking elsewhere in this
        file. Returns the entered string, or None if cancelled/closed."""
        win = tk.Toplevel(self.root)
        win.title(title); win.configure(bg=BG_DARK); win.grab_set()
        tk.Label(win, text=prompt, bg=BG_DARK, fg=TEXT_BRIGHT, padx=16,
                 pady=10, wraplength=280, justify="left").pack()
        var = tk.StringVar(value=default)
        entry_canvas, entry = _rounded_entry(win, var, width=30, justify="left")
        entry_canvas.pack(padx=16, pady=(0, 10))
        entry.focus_set()
        entry.select_range(0, tk.END)
        result = [None]
        def ok(event=None):
            result[0] = var.get()
            win.destroy()
        def cancel(event=None):
            result[0] = None
            win.destroy()
        entry.bind("<Return>", ok)
        win.protocol("WM_DELETE_WINDOW", cancel)
        btn_row = tk.Frame(win, bg=BG_DARK)
        btn_row.pack(pady=(0, 12))
        _rounded_button(btn_row, "OK", ok, bg=BG_PANEL, fg="white", font_size=10, padx=6)
        _rounded_button(btn_row, "Cancel", cancel, bg=BG_PANEL, fg="white", font_size=10, padx=6)
        self.root.wait_window(win)
        return result[0]

    def _export_gain_results(self):
        """GUI wrapper around write_gain_export -- gathers a condition
        label and a destination folder, then hands off to the pure
        (GUI-free, directly testable) export function. Filip's ask: an
        option to output results so different conditions/runs can be
        plotted against each other outside the app."""
        r = self.g_results
        if r is None:
            self.status_var.set("Nothing to export yet — click Run Analysis first")
            return

        label = self._prompt_text(
            "Export Results",
            "Short label for this condition/run (used in filenames and "
            "the summary row -- e.g. the animal/session/condition name):",
            default="condition")
        if label is None:
            return  # cancelled

        folder = filedialog.askdirectory(title="Select folder to save exported results")
        if not folder:
            return

        subtract_var = getattr(self, "subtract_baseline_var", None)
        baseline_pct_var = getattr(self, "flux_baseline_pct_var", None)
        settings = dict(
            fs=self.fs_var.get(), enf=self.enf_var.get(),
            fit_lo=self.fit_lo_var.get(), fit_hi=self.fit_hi_var.get(),
            spatial_bin=self.spatial_bin_var.get(), edge_margin=self.margin_var.get(),
            use_baseline=(subtract_var.get() if subtract_var is not None else ""),
            baseline_pctile=(baseline_pct_var.get() if baseline_pct_var is not None else ""),
        )
        try:
            summary_path, bins_path, flux_path = write_gain_export(r, settings, folder, label)
        except OSError as e:
            messagebox.showerror("Export failed", str(e))
            return

        extra = f" + {os.path.basename(flux_path)}" if flux_path else ""
        self.status_var.set(
            f"Exported '{label}' -> {os.path.basename(summary_path)} "
            f"(+ {os.path.basename(bins_path)}{extra})")

    # ── gain-mode: plotting ──────────────────────────────────────────────

    def _render_gain_results(self):
        r = self.g_results
        fit = r["fit"]

        self.fig.clear()
        gs = GridSpec(1, 2, figure=self.fig, left=0.07, right=0.97, top=0.90, bottom=0.12,
                      wspace=0.28, width_ratios=[1.3, 1])
        ax_ptc = self.fig.add_subplot(gs[0, 0])
        ax_hist = self.fig.add_subplot(gs[0, 1])

        def style(ax):
            ax.set_facecolor(BG_DARK)
            for s in ax.spines.values(): s.set_color("#555")
            ax.spines["top"].set_visible(False)
            ax.spines["right"].set_visible(False)
            ax.tick_params(colors=TEXT_MAIN, labelsize=8)

        # ── PTC / hockey-stick panel ────────────────────────────────────
        style(ax_ptc)
        sub = np.random.default_rng(0).choice(len(r["mu_flat"]), size=min(20000, len(r["mu_flat"])), replace=False)
        ax_ptc.scatter(r["mu_flat"][sub], r["var_flat"][sub], s=2, color="#3a3a3a", alpha=0.35, zorder=1)

        mask = fit["mask"]
        ax_ptc.scatter(r["mu_bin"][~mask], r["var_bin"][~mask], s=28, color=C_EXCL, zorder=2, label="excluded")
        ax_ptc.scatter(r["mu_bin"][mask], r["var_bin"][mask], s=28, color=C_INCL, zorder=3, label="fit bins")

        if np.isfinite(fit["slope"]):
            xline = np.array([r["mu_bin"][mask].min(), r["mu_bin"][mask].max()])
            yline = fit["slope"] * xline + fit["intercept"]
            ax_ptc.plot(xline, yline, color=C_FIT, lw=2, zorder=4,
                        label=f"shot-noise fit (slope={fit['slope']:.2f})")
            # Only draw a "read-noise floor" line when bins were actually excluded
            # at the LOW end (fit_pct_lo > 0) -- otherwise there's nothing to draw
            # a floor from, and conflating it with high-end saturation-excluded
            # bins would mislabel them.
            low_mask = fit.get("low_mask")
            if low_mask is not None and low_mask.sum():
                floor = np.median(r["var_bin"][low_mask])
                ax_ptc.axhline(floor, color=C_FLOOR, lw=1.2, ls="--", alpha=0.8,
                                zorder=2, label="read-noise floor (excluded low bins)")

        ax_ptc.set_xlabel("Mean (ADU)", color=TEXT_DIM, fontsize=9)
        ax_ptc.set_ylabel("Variance (ADU²)", color=TEXT_DIM, fontsize=9)
        ax_ptc.legend(fontsize=7, facecolor=BG_MID, edgecolor="#555", labelcolor=TEXT_MAIN, loc="upper left")

        gain_true = fit["gain_true"]
        title = (f"Hockey stick PTC  ·  {r['movie_source']}  ·  gain_apparent={fit['slope']:.2f} ADU/ph"
                  if np.isfinite(fit["slope"]) else f"Hockey stick PTC  ·  {r['movie_source']}  ·  fit failed")
        ax_ptc.set_title(title, color=TEXT_BRIGHT, fontsize=10, pad=8)
        if np.isfinite(gain_true):
            ax_ptc.text(0.98, 0.04,
                        f"ENF={self.enf_var.get():.2f}\ngain_true={gain_true:.2f} ADU/photon\nR²={fit['r2']:.3f}",
                        transform=ax_ptc.transAxes, ha="right", va="bottom",
                        color=TEXT_BRIGHT, fontsize=8,
                        bbox=dict(facecolor=BG_MID, edgecolor="#555", boxstyle="round,pad=0.4"))

        # ── photon-flux histogram panel (needs Suite2p F.npy) ─────────────
        style(ax_hist)
        if not r.get("has_cells", True):
            ax_hist.axis("off")
            ax_hist.text(0.5, 0.5, "No Suite2p F.npy loaded\n(manual TIFF mode)\n\n"
                                    "PTC gain estimate only —\nper-cell photon flux unavailable",
                        transform=ax_hist.transAxes, ha="center", va="center",
                        color=TEXT_DIM, fontsize=9)
        else:
            flux = r["flux"][np.isfinite(r["flux"])]
            cell_src = "CaImAn CNMF (unverified — sanity-check!)" if r.get("cnmf_used") else "Suite2p F.npy"
            if len(flux):
                ax_hist.hist(flux, bins=30, color=C_HIST, alpha=0.75)
                ax_hist.axvline(r["flux_med"], color="white", lw=1.5, ls="--")
                ax_hist.text(0.98, 0.95,
                            f"median = {r['flux_med']:.1f}\n± {r['flux_sem']:.1f} SEM\nn={len(flux)} cells",
                            transform=ax_hist.transAxes, ha="right", va="top",
                            color=TEXT_BRIGHT, fontsize=8,
                            bbox=dict(facecolor=BG_MID, edgecolor="#555", boxstyle="round,pad=0.4"))
            ax_hist.set_xlabel("Photons / cell / s", color=TEXT_DIM, fontsize=9)
            ax_hist.set_ylabel("Cells", color=TEXT_DIM, fontsize=9)
            ax_hist.set_title(f"Per-cell photon flux  ·  cells via {cell_src}",
                               color=(C_HIST if r.get("cnmf_used") else TEXT_BRIGHT), fontsize=10, pad=8)

        self.canvas.draw()

        if r.get("has_cells", True):
            cell_src = "CNMF" if r.get("cnmf_used") else "Suite2p"
            self.status_var.set(
                f"Done  ·  source={r['movie_source']}  ({r['movie_note']})  ·  "
                f"gain_true={gain_true:.2f} ADU/ph  ·  cells via {cell_src}  ·  "
                f"median flux={r['flux_med']:.1f}±{r['flux_sem']:.1f} ph/cell/s")
        else:
            self.status_var.set(
                f"Done  ·  source={r['movie_source']}  ({r['movie_note']})  ·  "
                f"gain_true={gain_true:.2f} ADU/ph  ·  no F.npy — flux not computed")

    # ── neuropil-sweep mode: running + rendering ────────────────────────

    def run_neuropil_analysis(self):
        if self.np_F is None:
            messagebox.showwarning("No data", "Load a Suite2p folder first.")
            return
        lo = float(self.np_alpha_lo_var.get())
        hi = float(self.np_alpha_hi_var.get())
        step = float(self.np_alpha_step_var.get())
        if step <= 0 or hi <= lo:
            messagebox.showerror("Invalid range",
                "Alpha range needs a high end greater than the low end, "
                "and a positive step.")
            return

        self.status_var.set("Running neuropil sweep...")
        self._progress_start()
        self.root.update_idletasks()
        t = threading.Thread(target=self._run_neuropil_worker, daemon=True)
        t.start()

    def _run_neuropil_worker(self):
        try:
            lo = float(self.np_alpha_lo_var.get())
            hi = float(self.np_alpha_hi_var.get())
            step = float(self.np_alpha_step_var.get())
            n_steps = int(round((hi - lo) / step)) + 1
            alphas = lo + np.arange(n_steps) * step
            alphas = alphas[alphas <= hi + 1e-9]
            exclude_px = float(self.np_exclude_px_var.get())
            kurt_thresh = (float(self.np_kurt_thresh_var.get())
                           if self.np_kurt_filter_var.get() else None)

            result = neuropil_alpha_sweep(
                self.np_F, self.np_Fneu, self.np_stat, alphas, exclude_px,
                kurtosis_thresh=kurt_thresh, progress_cb=self._gain_progress)
            result["plane_dir"] = self.np_plane_dir
            self.np_results = result
            self.root.after(0, self._render_neuropil_results)
        except Exception as e:
            traceback.print_exc()
            msg = str(e)
            self.root.after(0, lambda: messagebox.showerror("Neuropil sweep failed", msg))
            self.root.after(0, lambda: self.status_var.set("Neuropil sweep failed"))
        finally:
            self._progress_stop()

    def _render_neuropil_results(self):
        r = self.np_results

        self.fig.clear()
        ax = self.fig.add_axes([0.10, 0.12, 0.85, 0.78])
        ax.set_facecolor(BG_DARK)
        for s in ax.spines.values(): s.set_color("#555")
        ax.spines["top"].set_visible(False)
        ax.spines["right"].set_visible(False)
        ax.tick_params(colors=TEXT_MAIN, labelsize=8)

        alphas = r["alphas"]
        mean_c = r["mean_corr"]
        sem_c = r["sem_corr"]
        finite = np.isfinite(mean_c)
        ax.fill_between(alphas, mean_c - sem_c, mean_c + sem_c,
                         color=C_INCL, alpha=0.25, zorder=1)
        ax.plot(alphas, mean_c, color=C_INCL, lw=2, zorder=2, marker="o", ms=3)
        ax.axhline(0, color="#555", lw=1, ls=":", zorder=0)

        if finite.any():
            best_i = np.nanargmin(np.abs(mean_c))
            ax.axvline(alphas[best_i], color=C_FLOOR, lw=1.2, ls="--", alpha=0.8, zorder=1)
            ax.text(0.98, 0.95,
                    f"alpha ≈ {alphas[best_i]:.2f}\n(closest to zero mean corr.)",
                    transform=ax.transAxes, ha="right", va="top",
                    color=TEXT_BRIGHT, fontsize=8,
                    bbox=dict(facecolor=BG_MID, edgecolor="#555", boxstyle="round,pad=0.4"))

        ax.set_xlabel("alpha   (Fcorr = rawF − alpha·Fneu)", color=TEXT_DIM, fontsize=9)
        ax.set_ylabel("Mean pairwise correlation\n(off-diagonal, ± SEM)", color=TEXT_DIM, fontsize=9)
        filt_note = (f"kurtosis > {r['kurtosis_thresh']:.1f}"
                     if r.get("kurtosis_thresh") is not None else "no kurtosis filter")
        ax.set_title(f"Neuropil sweep  ·  {r['n_cells']} cells, {r['n_pairs']} pairs  ·  "
                     f"exclusion={r['exclude_px']:.0f}px  ·  {filt_note}",
                     color=TEXT_BRIGHT, fontsize=10, pad=8)

        self.canvas.draw()

        alpha_span = f"{alphas[0]:.2f}–{alphas[-1]:.2f}" if len(alphas) else "n/a"
        self.status_var.set(
            f"Done  ·  {r['n_cells']} cells  ·  {r['n_pairs']} pairs  ·  "
            f"alpha {alpha_span}  ·  {r.get('plane_dir', '')}")

    def _draw_neuropil_splash(self):
        """Neuropil-sweep-tab splash, shown before any sweep has run yet.
        Per Filip: "for the default screen I want a the neuron biting
        into the donut stationry to be there" -- a static (non-animated)
        picture of the neuron mid-bite, one of the poses from his Sweep
        SVG sheet (the same sheet the future donut-sweep busy bar will
        use, but this one specific frame drawn still rather than
        animated). That image is this splash's "whimsical" part --
        de-whimsify removes it ("dewhimsify will change it to nothing"),
        leaving just the functional guidance text underneath."""
        self.fig.clear()
        ax = self.fig.add_axes([0.05, 0.05, 0.9, 0.9])
        ax.set_facecolor(BG_DARK)
        for s in ax.spines.values():
            s.set_visible(False)
        ax.set_xticks([]); ax.set_yticks([])
        ax.set_xlim(0, 1); ax.set_ylim(0, 1)
        if self.whimsy_var.get():
            im = _load_art_image_outlined("neuron_donut_bite")
            ax.imshow(np.asarray(im), extent=(0.38, 0.62, 0.30, 0.82), zorder=2)
            ax.set_xlim(0, 1); ax.set_ylim(0, 1)  # imshow's extent re-autoscales -- lock back
        ax.text(0.5, 0.15, "Load a Suite2p folder, then click Run Analysis",
                 color=TEXT_DIM, fontsize=11, ha="center", transform=ax.transAxes)
        self.canvas.draw_idle()


# ── entry ─────────────────────────────────────────────────────────────────────
if __name__ == "__main__":
    root = tk.Tk()
    KurtosisChecker(root)
    root.mainloop()
